#!/usr/bin/env node
/*
 Auto-translate autogen keys using a LibreTranslate endpoint (fallbacks).
 Usage: run from repo root: `node waynest-FE/scripts/auto-translate.cjs`
 Optional env vars:
 - LIBRETRANSLATE_URL: custom translate endpoint (POST /translate)
 - SKIP_NETWORK: if set, skips network calls and copies English text into other langs

 Writes:
 - waynest-FE/i18n-autogen-translated-report.json
 - waynest-FE/i18n-autogen-translated-report.csv
 - updates waynest-FE/public/locales/<lang>/translation.json (creates if missing)
*/

const fs = require('fs');
const path = require('path');
const fetch = require('node-fetch');

const cwd = process.cwd();
const wfRoot = path.join(cwd, 'waynest-FE');
const candidates = [
  path.join(wfRoot, 'i18n-autogen-map.json'),
  path.join(cwd, 'i18n-autogen-map.json'),
];

function findAutogenMap() {
  for (const p of candidates) {
    if (fs.existsSync(p)) return p;
  }
  return null;
}

function readJSON(p) {
  return JSON.parse(fs.readFileSync(p, 'utf8'));
}

function writeJSON(p, obj) {
  fs.writeFileSync(p, JSON.stringify(obj, null, 2), 'utf8');
}

function ensureDir(p) {
  if (!fs.existsSync(p)) fs.mkdirSync(p, { recursive: true });
}

async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function translateTextLibre(text, target) {
  const endpoint = process.env.LIBRETRANSLATE_URL || 'https://libretranslate.de/translate';
  try {
    const res = await fetch(endpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ q: text, source: 'en', target, format: 'text' })
    });
    if (!res.ok) throw new Error('HTTP ' + res.status);
    const j = await res.json();
    // LibreTranslate-style: { translatedText: '...' }
    if (j.translatedText) return j.translatedText;
    // fallback: common shape { data: { translations: [ { translatedText } ] } }
    if (j.data && j.data.translations && j.data.translations[0] && j.data.translations[0].translatedText) {
      return j.data.translations[0].translatedText;
    }
    return null;
  } catch (err) {
    console.error('Translate error (Libre) ->', err.message);
    return null;
  }
}

const langNameMap = {
  en: 'English',
  ar: 'Arabic',
  fr: 'French',
  ru: 'Russian',
  tr: 'Turkish'
};

async function translateOpenAI(text, targetLanguageName) {
  const apiKey = process.env.OPENAI_API_KEY;
  if (!apiKey) return null;
  try {
    const endpoint = process.env.OPENAI_API_BASE || 'https://api.openai.com/v1/chat/completions';
    const system = `You are a concise translator. Translate the user's text to ${targetLanguageName}. Output only the translated text with no commentary. Preserve punctuation, emojis, and line breaks.`;
    const body = {
      model: process.env.OPENAI_MODEL || 'gpt-3.5-turbo',
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: text }
      ],
      temperature: 0,
      max_tokens: 800
    };
    const res = await fetch(endpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + apiKey },
      body: JSON.stringify(body)
    });
    if (!res.ok) {
      const t = await res.text();
      throw new Error('HTTP ' + res.status + ' ' + t.slice(0,200));
    }
    const j = await res.json();
    if (j.choices && j.choices[0] && j.choices[0].message && j.choices[0].message.content) {
      return j.choices[0].message.content.trim();
    }
    return null;
  } catch (err) {
    console.error('Translate error (OpenAI) ->', err.message);
    return null;
  }
}

async function translateGemini(text, targetLanguageName) {
  const apiKey = process.env.GEMINI_API_KEY;
  if (!apiKey) return null;
  const endpoint = process.env.GEMINI_API_URL;
  if (!endpoint) {
    console.error('GEMINI_API_URL not set — set to your Gemini endpoint (e.g. https://...): skipping Gemini.');
    return null;
  }
  try {
    const system = `You are a concise translator. Translate the user's text to ${targetLanguageName}. Output only the translated text with no commentary. Preserve punctuation, emojis, and line breaks.`;
    let url = endpoint;
    let headers = { 'Content-Type': 'application/json' };

    // Google Generative Language (generativelanguage.googleapis.com) expects x-goog-api-key header
    const isGoogleGL = url.includes('generativelanguage.googleapis.com');
    if (isGoogleGL) {
      headers['x-goog-api-key'] = apiKey;
    } else if (process.env.GEMINI_USE_KEY_PARAM === '1') {
      url += (url.includes('?') ? '&' : '?') + 'key=' + encodeURIComponent(apiKey);
    } else {
      headers.Authorization = 'Bearer ' + apiKey;
    }

    // For Google GL, use the `contents` body shape; otherwise send a generic prompt payload
    let body;
    if (isGoogleGL) {
      body = { contents: [{ parts: [{ text: system + '\n\n' + text }] }] };
    } else {
      body = { prompt: system + '\n\n' + text };
    }

    const res = await fetch(url, { method: 'POST', headers, body: JSON.stringify(body) });
    if (!res.ok) {
      const t = await res.text();
      throw new Error('HTTP ' + res.status + ' ' + t.slice(0,200));
    }
    const j = await res.json();
    if (!j) return null;
    // Google GL response: { candidates: [ { content: { parts: [ { text } ] } } ] }
    if (j.candidates && j.candidates[0]) {
      const cand = j.candidates[0];
      if (cand.content && Array.isArray(cand.content.parts) && cand.content.parts[0] && cand.content.parts[0].text) {
        return cand.content.parts[0].text.trim();
      }
      // older shapes
      if (cand.text) return cand.text.trim();
    }
    // fallback shapes (OpenAI-like)
    if (typeof j === 'string' && j.trim()) return j.trim();
    if (j.outputText) return j.outputText;
    if (j.choices && j.choices[0] && j.choices[0].message && j.choices[0].message.content) return j.choices[0].message.content.trim();
    if (j.responses && j.responses[0] && j.responses[0].content) {
      const c = j.responses[0].content;
      if (Array.isArray(c)) return c.map(x => x.text || x.output_text || '').join('').trim() || null;
      if (typeof c === 'string') return c.trim();
    }
    return null;
  } catch (err) {
    console.error('Translate error (Gemini) ->', err.message);
    return null;
  }
}

async function translate(text, target) {
  if (!text || text.trim() === '') return text;
  if (process.env.SKIP_NETWORK) return text;
  // Prefer Gemini if API key provided
  if (process.env.GEMINI_API_KEY) {
    const langName = langNameMap[target] || target;
    const trGem = await translateGemini(text, langName);
    if (trGem) return trGem;
  }
  // Prefer OpenAI if API key provided
  if (process.env.OPENAI_API_KEY) {
    const langName = langNameMap[target] || target;
    const trOpen = await translateOpenAI(text, langName);
    if (trOpen) return trOpen;
  }
  // fallback to libretranslate
  let tr = await translateTextLibre(text, target);
  if (tr) return tr;
  // small delay then return original as fallback
  await sleep(100);
  return text;
}

function setNested(obj, parts, value) {
  let cur = obj;
  for (let i = 0; i < parts.length - 1; i++) {
    const p = parts[i];
    if (!(p in cur) || typeof cur[p] !== 'object') cur[p] = {};
    cur = cur[p];
  }
  cur[parts[parts.length - 1]] = value;
}

function getNested(obj, parts) {
  let cur = obj;
  for (let i = 0; i < parts.length; i++) {
    const p = parts[i];
    if (cur == null || typeof cur !== 'object' || !(p in cur)) return undefined;
    cur = cur[p];
  }
  return cur;
}

async function main() {
  const mapPath = findAutogenMap();
  if (!mapPath) {
    console.error('i18n-autogen-map.json not found. Run generate-autogen-keys first.');
    process.exitCode = 2;
    return;
  }
  console.log('Using autogen map:', mapPath);

  const map = readJSON(mapPath); // array of { key, text, locations }

  const localesDir = path.join(wfRoot, 'public', 'locales');
  if (!fs.existsSync(localesDir)) {
    console.error('Locales folder not found at', localesDir);
    process.exitCode = 3;
    return;
  }

  const langs = fs.readdirSync(localesDir).filter(f => fs.statSync(path.join(localesDir, f)).isDirectory());
  console.log('Found languages:', langs.join(', '));

  // Prepare per-language JSON objects
  const translationsByLang = {};
  for (const lang of langs) {
    const file = path.join(localesDir, lang, 'translation.json');
    if (fs.existsSync(file)) {
      try { translationsByLang[lang] = readJSON(file); } catch (e) { translationsByLang[lang] = {}; }
    } else {
      translationsByLang[lang] = {};
    }
  }

  const report = [];
  // translate sequentially (throttle)
  for (let i = 0; i < map.length; i++) {
    const item = map[i];
    const key = item.key; // e.g. autogen.back_to_explore
    const parts = key.split('.');
    const enText = item.text;
    const row = { key, text: enText, locations: item.locations || [], translations: {} };

    for (const lang of langs) {
      if (lang === 'en') {
        setNested(translationsByLang[lang], parts, enText);
        row.translations[lang] = enText;
        continue;
      }
      const existing = getNested(translationsByLang[lang], parts);
      if (existing && typeof existing === 'string' && existing.trim() !== '' && existing !== enText) {
        // keep existing human translation
        row.translations[lang] = existing;
        continue;
      }
      // translate
      const tr = await translate(enText, lang);
      setNested(translationsByLang[lang], parts, tr);
      row.translations[lang] = tr;
      // small throttle to be gentle on public endpoints
      await sleep(180);
    }
    report.push(row);
    if ((i + 1) % 20 === 0) console.log(`Processed ${i + 1}/${map.length} keys...`);
  }

  // write back translation.json files
  for (const lang of langs) {
    const outFile = path.join(localesDir, lang, 'translation.json');
    ensureDir(path.dirname(outFile));
    writeJSON(outFile, translationsByLang[lang]);
    console.log('Wrote', outFile);
  }

  // write report JSON + CSV
  const reportJsonPath = path.join(wfRoot, 'i18n-autogen-translated-report.json');
  writeJSON(reportJsonPath, report);
  console.log('Wrote report JSON:', reportJsonPath);

  // CSV
  const csvPath = path.join(wfRoot, 'i18n-autogen-translated-report.csv');
  const headers = ['key','text','locations', ...langs];
  const rows = [headers.join(',')];
  for (const r of report) {
    const cols = [
      `"${r.key.replace(/"/g, '""')}"`,
      `"${(r.text||'').replace(/"/g,'""')}"`,
      `"${(r.locations||[]).join(' | ').replace(/"/g,'""')}"`
    ];
    for (const lang of langs) cols.push(`"${(r.translations[lang]||'').replace(/"/g,'""')}"`);
    rows.push(cols.join(','));
  }
  fs.writeFileSync(csvPath, rows.join('\n'), 'utf8');
  console.log('Wrote CSV report:', csvPath);

  console.log('Done. Translated', map.length, 'keys for', langs.length, 'languages.');
}

main().catch(err => { console.error(err); process.exitCode = 1; });

import axios from "axios";

const API_BASE = process.env.API_BASE || "http://localhost:3001";

(async function () {
  try {
    const res = await axios.get(`${API_BASE}/api/docs`, { timeout: 3000 });
    console.log("status", res.status);
    console.log("headers", JSON.stringify(res.headers));
  } catch (err) {
    console.error("ERR", err.message);
    if (err.response) {
      console.error("RESP", err.response.status, err.response.data);
    } else if (err.request) {
      console.error("NO RESPONSE, request made");
    } else {
      console.error("SETUP ERROR", err.stack);
    }
    process.exit(1);
  }
})();

const fs = require("fs");
const path = require("path");

const SRC = path.join(__dirname, "..", "src");

function isLikelyUIString(s) {
  if (!s) return false;
  const trimmed = s.trim();
  if (!trimmed) return false;
  if (trimmed.length < 2) return false; // too short
  if (/^\d+$/.test(trimmed)) return false; // just numbers
  if (trimmed.includes("\n")) return false;
  if (trimmed.includes("{") || trimmed.includes("}")) return false;
  if (/^\s*$/.test(trimmed)) return false;
  // skip common icons or single words like OK (maybe still translate?) keep words longer than 1 char
  return true;
}

async function walk(dir) {
  const entries = await fs.promises.readdir(dir, { withFileTypes: true });
  const files = [];
  for (const e of entries) {
    const full = path.join(dir, e.name);
    if (e.isDirectory()) {
      files.push(...(await walk(full)));
    } else if (/\.(jsx|js|tsx|ts|mjs|cjs)$/.test(e.name)) {
      files.push(full);
    }
  }
  return files;
}

async function extract() {
  const files = await walk(SRC);
  const found = new Map();

  const attrPattern =
    /(aria-label|placeholder|alt|title|subTitle|label)=\s*["'`]([^"'`<>]+?)["'`]/gi;
  const textPattern = />\s*([^<{][^<\n]+?)\s*</g;

  for (const file of files) {
    let content;
    try {
      content = await fs.promises.readFile(file, "utf8");
    } catch (e) {
      continue;
    }

    let m;
    while ((m = attrPattern.exec(content)) !== null) {
      const val = m[2].trim();
      if (!isLikelyUIString(val)) continue;
      const key = val;
      if (!found.has(key)) found.set(key, new Set());
      found
        .get(key)
        .add(
          `${path.relative(process.cwd(), file)}:${getLineForIndex(content, m.index)}`,
        );
    }

    while ((m = textPattern.exec(content)) !== null) {
      const val = m[1].trim();
      // skip if contains JSX expression markers
      if (!isLikelyUIString(val)) continue;
      // skip if line contains t(" or useTranslation or {t(
      const before = content.slice(Math.max(0, m.index - 200), m.index + 200);
      if (/t\(/.test(before) || /{\s*t\(/.test(before)) continue;
      const key = val;
      if (!found.has(key)) found.set(key, new Set());
      found
        .get(key)
        .add(
          `${path.relative(process.cwd(), file)}:${getLineForIndex(content, m.index)}`,
        );
    }
  }

  const out = [];
  for (const [text, locations] of found.entries()) {
    out.push({ text, locations: Array.from(locations) });
  }

  out.sort((a, b) => a.text.localeCompare(b.text));

  const reportPath = path.join(
    __dirname,
    "..",
    "i18n-untranslated-report.json",
  );
  await fs.promises.writeFile(reportPath, JSON.stringify(out, null, 2));
  console.log(
    `Found ${out.length} candidate untranslated strings. Report: ${reportPath}`,
  );
}

function getLineForIndex(content, index) {
  return content.slice(0, index).split("\n").length;
}

extract().catch((err) => {
  console.error(err);
  process.exit(1);
});

const fs = require("fs");
const path = require("path");

const projectRoot = path.join(__dirname, "..");
const reportPath = path.join(projectRoot, "i18n-untranslated-report.json");
const localesDir = path.join(projectRoot, "public", "locales");

function slugify(text) {
  return text
    .toLowerCase()
    .replace(/[^\p{L}0-9]+/gu, "_")
    .replace(/^_+|_+$/g, "")
    .slice(0, 60);
}

function isCodeLike(s) {
  if (!s) return true;
  // heuristics: contains code operators or unbalanced punctuation
  if (/\&\&|\|\||=>|\?\?|\(|\)\s*:\s*\(|^\d+\s*&&|<[^>]+>|\{\s*\}/.test(s))
    return true;
  // if it contains many punctuation and no letters
  const letters = (s.match(/\p{L}/gu) || []).length;
  const others = s.length - letters;
  if (letters === 0 && others > 0) return true;
  // skip very short tokens
  if (s.trim().length <= 1) return true;
  return false;
}

async function main() {
  const raw = fs.readFileSync(reportPath, "utf8");
  const items = JSON.parse(raw);

  const candidates = items.filter((it) => !isCodeLike(it.text));

  const map = [];
  const usedKeys = new Set();

  for (const it of candidates) {
    let base = slugify(it.text);
    if (!base) {
      base = "text";
    }
    let key = base;
    let idx = 1;
    while (usedKeys.has(key)) {
      key = `${base}_${idx++}`;
    }
    usedKeys.add(key);
    map.push({ key: `autogen.${key}`, text: it.text, locations: it.locations });
  }

  // save map
  const mapPath = path.join(projectRoot, "i18n-autogen-map.json");
  fs.writeFileSync(mapPath, JSON.stringify(map, null, 2), "utf8");
  console.log(`Wrote autogen map: ${mapPath} (${map.length} entries)\n`);

  // update each locale translation.json by adding autogen keys if missing (copy english text)
  const langs = await fs.promises.readdir(localesDir, { withFileTypes: true });
  for (const dirent of langs) {
    if (!dirent.isDirectory()) continue;
    const lang = dirent.name;
    const filePath = path.join(localesDir, lang, "translation.json");
    let data = {};
    try {
      data = JSON.parse(await fs.promises.readFile(filePath, "utf8"));
    } catch (e) {
      console.warn(`Failed to read ${filePath}, creating new object.`);
      data = {};
    }

    if (!data.autogen) data.autogen = {};
    let added = 0;
    for (const entry of map) {
      const keyPath = entry.key.split(".").slice(1); // remove autogen prefix
      let node = data.autogen;
      for (let i = 0; i < keyPath.length - 1; i++) {
        const part = keyPath[i];
        if (!node[part] || typeof node[part] !== "object") node[part] = {};
        node = node[part];
      }
      const last = keyPath[keyPath.length - 1];
      if (node[last] === undefined) {
        // if English, keep original; for others, copy English as placeholder
        node[last] = entry.text;
        added++;
      }
    }

    await fs.promises.writeFile(
      filePath,
      JSON.stringify(data, null, 2) + "\n",
      "utf8",
    );
    console.log(`Updated ${filePath} — added ${added} autogen keys.`);
  }

  console.log("Done.");
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

const fs = require("fs");
const path = require("path");

const localesDir = path.join(__dirname, "..", "public", "locales");

function isObject(val) {
  return val && typeof val === "object" && !Array.isArray(val);
}

function deepMergePreferBase(base, src) {
  for (const key of Object.keys(src)) {
    if (isObject(src[key])) {
      if (!isObject(base[key])) {
        base[key] = {};
      }
      deepMergePreferBase(base[key], src[key]);
    } else {
      if (base[key] === undefined) {
        base[key] = src[key];
      }
    }
  }
}

async function mergeLocales() {
  try {
    const langs = await fs.promises.readdir(localesDir, {
      withFileTypes: true,
    });
    for (const dirent of langs) {
      if (!dirent.isDirectory()) continue;
      const lang = dirent.name;
      const langPath = path.join(localesDir, lang);
      const files = await fs.promises.readdir(langPath);

      let base = {};
      const translationFile = path.join(langPath, "translation.json");
      if (files.includes("translation.json")) {
        try {
          const text = await fs.promises.readFile(translationFile, "utf8");
          base = JSON.parse(text);
        } catch (err) {
          console.error(`Failed to read ${translationFile}:`, err.message);
          base = {};
        }
      }

      for (const file of files) {
        if (!file.endsWith(".json")) continue;
        if (file === "translation.json") continue;
        const filePath = path.join(langPath, file);
        try {
          const txt = await fs.promises.readFile(filePath, "utf8");
          const obj = JSON.parse(txt);
          deepMergePreferBase(base, obj);
        } catch (err) {
          console.error(`Failed to process ${filePath}:`, err.message);
        }
      }

      try {
        const out = JSON.stringify(base, null, 2);
        await fs.promises.writeFile(translationFile, out + "\n", "utf8");
        console.log(`Merged locale for '${lang}' -> ${translationFile}`);
      } catch (err) {
        console.error(`Failed to write ${translationFile}:`, err.message);
      }
    }
  } catch (err) {
    console.error("Failed to read locales directory:", err.message);
    process.exit(1);
  }
}

mergeLocales();

const fs = require("fs");
const path = require("path");

const localesDir = path.join(__dirname, "..", "public", "locales");

function isObject(val) {
  return val && typeof val === "object" && !Array.isArray(val);
}

function deepMergePreferBase(base, src) {
  // merge src into base but do not overwrite existing non-object values in base
  for (const key of Object.keys(src)) {
    if (isObject(src[key])) {
      if (!isObject(base[key])) {
        base[key] = {};
      }
      deepMergePreferBase(base[key], src[key]);
    } else {
      if (base[key] === undefined) {
        base[key] = src[key];
      }
    }
  }
}

async function mergeLocales() {
  try {
    const langs = await fs.promises.readdir(localesDir, {
      withFileTypes: true,
    });
    for (const dirent of langs) {
      if (!dirent.isDirectory()) continue;
      const lang = dirent.name;
      const langPath = path.join(localesDir, lang);
      const files = await fs.promises.readdir(langPath);

      // start with existing translation.json if present
      let base = {};
      const translationFile = path.join(langPath, "translation.json");
      if (files.includes("translation.json")) {
        try {
          const text = await fs.promises.readFile(translationFile, "utf8");
          base = JSON.parse(text);
        } catch (err) {
          console.error(`Failed to read ${translationFile}:`, err.message);
          base = {};
        }
      }

      for (const file of files) {
        if (!file.endsWith(".json")) continue;
        if (file === "translation.json") continue; // already loaded
        const filePath = path.join(langPath, file);
        try {
          const txt = await fs.promises.readFile(filePath, "utf8");
          const obj = JSON.parse(txt);
          deepMergePreferBase(base, obj);
        } catch (err) {
          console.error(`Failed to process ${filePath}:`, err.message);
        }
      }

      // write back merged translation.json
      try {
        const out = JSON.stringify(base, null, 2);
        await fs.promises.writeFile(translationFile, out + "\n", "utf8");
        console.log(`Merged locale for '${lang}' -> ${translationFile}`);
      } catch (err) {
        console.error(`Failed to write ${translationFile}:`, err.message);
      }
    }
  } catch (err) {
    console.error("Failed to read locales directory:", err.message);
    process.exit(1);
  }
}

mergeLocales();

import axios from "axios";
import { io } from "socket.io-client";

const API_BASE = process.env.API_BASE || "http://localhost:3001";
const CHAT_NS = "/chat";

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

async function ensureUp() {
  for (let i = 0; i < 10; i++) {
    try {
      await axios
        .get(`${API_BASE}/api/docs`, { timeout: 1000 })
        .catch(() => {});
      return;
    } catch (e) {
      await sleep(500);
    }
  }
}

async function registerIfNeeded(user) {
  try {
    const regBody = {
      firstName: user.firstName,
      lastName: user.lastName,
      email: user.email,
