import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { FiMessageCircle, FiX } from "react-icons/fi";
import { toast } from "react-toastify";
import { useAuth } from "@/context/AuthContext";
import { fetchInbox } from "@/api/social";
import { getApiErrorMessage } from "@/utils/errors";
import "./NavbarMessagesMenu.css";

const PREVIEW_MAX = 72;
const LIST_LIMIT = 6;

const sortByRecent = (rows) =>
  [...rows].sort(
    (a, b) =>
      new Date(b.lastMessageAt).getTime() - new Date(a.lastMessageAt).getTime(),
  );

const truncateOneLine = (text, max = PREVIEW_MAX) => {
  if (!text || typeof text !== "string") {
    return "";
  }
  const t = text.trim();
  return t.length <= max ? t : `${t.slice(0, max - 1)}…`;
};

const conversationTitle = (conversation, currentUserId, fallback) => {
  if (conversation.isGroup) {
    return conversation.title?.trim() || fallback;
  }
  const peer = conversation.members?.find((m) => m.userId !== currentUserId);
  return (
    `${peer?.firstName ?? ""} ${peer?.lastName ?? ""}`.trim() ||
    peer?.username ||
    fallback
  );
};

export function NavbarMessagesMenu({ open, onToggle, onNavigate }) {
  const { t } = useTranslation();
  const { user } = useAuth();
  const currentUserId = user?.id ?? user?.userId ?? "";
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!open) {
      return;
    }

    let active = true;
    void (async () => {
      try {
        setLoading(true);
        const payload = await fetchInbox();

        if (!active) {
          return;
        }
        setRows(sortByRecent(Array.isArray(payload) ? payload : []));
      } catch (error) {
        if (active) {
          toast.error(
            getApiErrorMessage(
              error,
              t("social.inbox.loadFailed", {
                defaultValue: "Failed to load inbox",
              }),
            ),
          );
          setRows([]);
        }
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    })();

    return () => {
      active = false;
    };
  }, [open, t]);

  // Refresh inbox when a chat message arrives elsewhere in the app
  useEffect(() => {
    let active = true;
    const onChatMessage = async () => {
      try {
        const payload = await fetchInbox();

        if (!active) return;
        setRows(sortByRecent(Array.isArray(payload) ? payload : []));
      } catch (err) {
        // ignore - don't override existing state on failure
      }
    };

    window.addEventListener("chat:message", onChatMessage);
    return () => {
      active = false;
      window.removeEventListener("chat:message", onChatMessage);
    };
  }, []);

  const items = rows.slice(0, LIST_LIMIT);
  const totalUnread = rows.reduce(
    (sum, row) => sum + (Number(row.unreadCount) || 0),
    0,
  );

  return (
    <div className="public-navbar-messages">
      <button
        type="button"
        className="public-navbar-messages-trigger"
        onClick={onToggle}
        aria-expanded={open}
        aria-haspopup="menu"
        aria-label={t("navbar.messagesMenu", { defaultValue: "Messages" })}>
        <FiMessageCircle className="public-navbar-messages-icon" aria-hidden />
        {totalUnread > 0 ? (
          <span className="public-navbar-messages-badge">
            {totalUnread > 99 ? "99+" : totalUnread}
          </span>
        ) : null}
      </button>

      {open ? (
        <div className="public-navbar-messages-dropdown" role="menu">
          <div className="public-navbar-messages-head">
            <span>
              {t("navbar.messagesTitle", { defaultValue: "Messages" })}
            </span>
            <button
              type="button"
              className="public-navbar-messages-close"
              aria-label={t("common.close", { defaultValue: "Close" })}
              onClick={() => onToggle?.()}>
              <FiX aria-hidden />
            </button>
          </div>

          {loading && items.length === 0 ? (
            <p className="public-navbar-messages-empty">
              {t("common.loading", { defaultValue: "Loading…" })}
            </p>
          ) : null}

          {!loading && items.length === 0 ? (
            <p className="public-navbar-messages-empty">
              {t("navbar.messagesEmpty", {
                defaultValue:
                  "No conversations yet. Start one from the messenger.",
              })}
            </p>
          ) : null}

          <ul className="public-navbar-messages-list">
            {items.map((conversation) => {
              const isYou = conversation.initiatorId
                ? currentUserId === conversation.initiatorId
                : Array.isArray(conversation.members) &&
                  conversation.members.length === 1 &&
                  conversation.members[0]?.userId === currentUserId;
              const fallback = isYou
                ? t("sidebar.youLabel", { defaultValue: "You" })
                : t("sidebar.unknownLabel", { defaultValue: "Unknown" });
              const title = conversationTitle(
                conversation,
                currentUserId,
                fallback,
              );
              const preview = truncateOneLine(conversation.lastMessage);
              const unread = Number(conversation.unreadCount) || 0;

              return (
                <li key={conversation.id}>
                  <Link
                    role="menuitem"
                    className="public-navbar-messages-row"
                    to={`/social?conversation=${encodeURIComponent(conversation.id)}`}
                    onClick={() => onNavigate?.()}>
                    <span className="public-navbar-messages-row-title">
                      <span className="public-navbar-messages-row-name">
                        {title}
                      </span>
                      {unread > 0 ? (
                        <span className="public-navbar-messages-row-unread">
                          {unread}
                        </span>
                      ) : null}
                    </span>
                    {preview ? (
                      <span
                        className="public-navbar-messages-row-preview"
                        title={preview}>
                        {preview}
                      </span>
                    ) : (
                      <span className="public-navbar-messages-row-preview public-navbar-messages-row-preview--muted">
                        {t("navbar.noMessagesYet", {
                          defaultValue: "No messages yet",
                        })}
                      </span>
                    )}
                  </Link>
                </li>
              );
            })}
          </ul>

          <Link
            className="public-navbar-messages-footer"
            to="/social"
            role="menuitem"
            onClick={() => onNavigate?.()}>
            {t("navbar.openAllMessages", { defaultValue: "Open messenger" })}
          </Link>
        </div>
      ) : null}
    </div>
  );
}

import { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { FiBell, FiX } from "react-icons/fi";
import { toast } from "react-toastify";
import {
  fetchNotifications,
  getNotificationHref,
  markAllNotificationsRead,
  markNotificationRead,
} from "@/api/social";
import { useNotifications } from "@/context/NotificationsContext";
import { getResolvedAvatarUrl, handleAvatarImageError } from "@/utils/avatar";
import { getApiErrorMessage } from "@/utils/errors";
import "./NavbarNotificationsMenu.css";

const PREVIEW_LIMIT = 10;

function formatNotifTime(iso, locale) {
  try {
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return "";
    const now = new Date();
    const diffMs = now.getTime() - d.getTime();
    const mins = Math.floor(diffMs / 60_000);
    if (mins < 1) return "now";
    if (mins < 60) return `${mins}m`;
    const hours = Math.floor(mins / 60);
    if (hours < 24) return `${hours}h`;
    const days = Math.floor(hours / 24);
    if (days < 7) return `${days}d`;
    return d.toLocaleDateString(locale, { month: "short", day: "numeric" });
  } catch {
    return "";
  }
}

function actorInitials(item) {
  const a = item.actor;
  if (!a || typeof a !== "object") {
    const m = typeof item.message === "string" ? item.message.trim() : "";
    return m.charAt(0).toUpperCase() || "•";
  }
  const f = typeof a.firstName === "string" ? a.firstName.trim() : "";
  const l = typeof a.lastName === "string" ? a.lastName.trim() : "";
  if (f || l) {
    return (
      `${f.charAt(0)}${l.charAt(0)}`.toUpperCase() ||
      (a.username || "?").charAt(0).toUpperCase()
    );
  }
  const u = typeof a.username === "string" ? a.username : "";
  return u.charAt(0).toUpperCase() || "?";
}

export function NavbarNotificationsMenu({
  open,
  onToggle,
  onNavigate,
  unreadCount,
}) {
  const { t, i18n } = useTranslation();
  const navigate = useNavigate();
  const { refreshUnreadCount } = useNotifications();
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!open) {
      return;
    }

    let active = true;
    void (async () => {
      try {
        setLoading(true);
        const payload = await fetchNotifications(PREVIEW_LIMIT);
        if (!active) {
          return;
        }
        setRows(Array.isArray(payload) ? payload : []);
      } catch (error) {
        if (active) {
          toast.error(
            getApiErrorMessage(
              error,
              t("social.notifications.loadFailed", {
                defaultValue: "Failed to load notifications",
              }),
            ),
          );
          setRows([]);
        }
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    })();

    return () => {
      active = false;
    };
  }, [open, t]);

  const handleRowActivate = async (item) => {
    const href = getNotificationHref(item);
    try {
      await markNotificationRead(item.id);
      await refreshUnreadCount();
      onNavigate?.();
      if (href) {
        navigate(href);
      }
    } catch (error) {
      toast.error(
        getApiErrorMessage(
          error,
          t("social.notifications.markFailed", {
            defaultValue: "Failed to update notification",
          }),
        ),
      );
    }
  };

  const handleMarkAll = async () => {
    try {
      await markAllNotificationsRead();
      await refreshUnreadCount();
      const payload = await fetchNotifications(PREVIEW_LIMIT);
      setRows(Array.isArray(payload) ? payload : []);
    } catch (error) {
      toast.error(
        getApiErrorMessage(
          error,
          t("social.notifications.markFailed", {
            defaultValue: "Failed to mark notifications",
          }),
        ),
      );
    }
  };

  return (
    <div className="public-navbar-notifications">
      <button
        type="button"
        className="public-navbar-messages-trigger"
        onClick={onToggle}
        aria-expanded={open}
        aria-haspopup="menu"
        aria-label={t("navbar.notificationsMenu", {
          defaultValue: "Notifications",
        })}>
        <FiBell className="public-navbar-messages-icon" aria-hidden />
        {unreadCount > 0 ? (
          <span className="public-navbar-messages-badge">
            {unreadCount > 99 ? "99+" : unreadCount}
          </span>
        ) : null}
      </button>

      {open ? (
        <div className="public-navbar-notifications-dropdown" role="menu">
          <div className="public-navbar-notifications-head">
            <span className="public-navbar-notifications-head__title">
              {t("social.notifications.title", {
                defaultValue: "Notifications",
              })}
            </span>
            <div className="public-navbar-notifications-head-actions">
              {rows.some((r) => !r.isRead) ? (
                <button
                  type="button"
                  className="public-navbar-notifications-markall"
                  onClick={() => void handleMarkAll()}>
                  {t("social.notifications.markAllRead", {
                    defaultValue: "Mark all as read",
                  })}
                </button>
              ) : null}
              <button
                type="button"
                className="public-navbar-notifications-close"
                aria-label={t("common.close", { defaultValue: "Close" })}
                onClick={() => onToggle?.()}>
                <FiX aria-hidden />
              </button>
            </div>
          </div>

          {loading && rows.length === 0 ? (
            <p className="public-navbar-messages-empty">
              {t("common.loading", { defaultValue: "Loading…" })}
            </p>
          ) : null}

          {!loading && rows.length === 0 ? (
            <p className="public-navbar-messages-empty">
              {t("social.notifications.empty", {
                defaultValue: "No notifications yet.",
              })}
            </p>
          ) : null}

          <ul className="public-navbar-notifications-list">
            {rows.map((item) => {
              const href = getNotificationHref(item);
              const avatarUrl = getResolvedAvatarUrl(item.actor);
              const timeLabel = formatNotifTime(item.createdAt, i18n.language);

              return (
                <li key={item.id}>
                  {href ? (
                    <Link
                      role="menuitem"
                      to={href}
                      className={`public-navbar-notif-row${item.isRead ? "" : " public-navbar-notif-row--unread"}`}
                      onClick={(e) => {
                        e.preventDefault();
                        void handleRowActivate(item);
                      }}>
                      <span
                        className="public-navbar-notif-row__avatar"
                        aria-hidden>
                        {avatarUrl ? (
                          <img
                            src={avatarUrl}
                            alt=""
                            className="public-navbar-notif-row__avatarImg"
                            onError={handleAvatarImageError}
                          />
                        ) : (
                          <span className="public-navbar-notif-row__avatarLetter">
                            {actorInitials(item)}
                          </span>
                        )}
                      </span>
                      <div className="public-navbar-notif-row__body">
                        <p className="public-navbar-notif-row__msg">
                          {item.message}
                        </p>
                        <span className="public-navbar-notif-row__time">
                          {timeLabel}
                        </span>
                      </div>
                      {!item.isRead ? (
                        <span
                          className="public-navbar-notif-row__dot"
                          aria-hidden
                        />
                      ) : null}
                    </Link>
                  ) : (
                    <button
                      type="button"
                      role="menuitem"
                      className={`public-navbar-notif-row public-navbar-notif-row--button${item.isRead ? "" : " public-navbar-notif-row--unread"}`}
                      onClick={() => void handleRowActivate(item)}>
                      <span
                        className="public-navbar-notif-row__avatar"
                        aria-hidden>
                        {avatarUrl ? (
                          <img
                            src={avatarUrl}
                            alt=""
                            className="public-navbar-notif-row__avatarImg"
                            onError={handleAvatarImageError}
                          />
                        ) : (
                          <span className="public-navbar-notif-row__avatarLetter">
                            {actorInitials(item)}
                          </span>
                        )}
                      </span>
                      <div className="public-navbar-notif-row__body">
                        <p className="public-navbar-notif-row__msg">
                          {item.message}
                        </p>
                        <span className="public-navbar-notif-row__time">
                          {timeLabel}
                        </span>
                      </div>
                      {!item.isRead ? (
                        <span
                          className="public-navbar-notif-row__dot"
                          aria-hidden
                        />
                      ) : null}
                    </button>
                  )}
                </li>
              );
            })}
          </ul>

          <Link
            className="public-navbar-messages-footer"
            to="/notifications"
            role="menuitem"
            onClick={() => onNavigate?.()}>
            {t("navbar.notificationsSeeAll", {
              defaultValue: "See all notifications",
            })}
          </Link>
        </div>
      ) : null}
    </div>
  );
}

