          disabled: quickMessageSending || !quickMessageText.trim()
        }}
        confirmLoading={quickMessageSending}
        destroyOnHidden>
        <div className="social-composer">
          <h3>
            {tt("social.quickMessage.to", "To")}: {quickMessageTargetLabel}
          </h3>
          <textarea
            placeholder={tt("social.quickMessage.placeholder", "Write a message...")}
            value={quickMessageText}
            onChange={(event) => setQuickMessageText(event.target.value)} />
          
        </div>
      </Modal>
    </div>);

};

import { Navigate, Outlet, useLocation } from "react-router-dom";
import { useAuth } from "@/context/AuthContext";
import { RouteLoadingState } from "@/components/shared/RouteLoadingState";
import { hasProviderModeChosen } from "@/utils/providerModeStorage";
import {
  getActiveWorkspace,
  isPathAllowedInProviderWorkspace,
  isPathProviderPanelPath,
} from "@/utils/activeWorkspaceStorage";

const CHOOSE_ACCOUNT_PATH = "/choose-account";
const PROVIDER_HOME = "/account/provider";
const PERSONAL_HOME = "/";

/**
 * Provider-role users must complete account-mode selection before using the app.
 * Workspace "provider": only business-related paths until switching to personal.
 * Workspace "personal" (or unset): cannot open /account/* except via navbar (sets workspace first).
 */
export function ProviderModeGate() {
  const { user, loading } = useAuth();
  const location = useLocation();

  if (loading) {
    return <RouteLoadingState />;
  }

  if (user?.role === "PROVIDER" && !hasProviderModeChosen(user.id)) {
    if (location.pathname !== CHOOSE_ACCOUNT_PATH) {
      return (
        <Navigate
          to={CHOOSE_ACCOUNT_PATH}
          replace
          state={{
            redirectTo: `${location.pathname}${location.search ?? ""}`,
          }}
        />
      );
    }
  }

  if (user?.role === "PROVIDER" && user.id && hasProviderModeChosen(user.id)) {
    const workspace = getActiveWorkspace(user.id);
    const path = location.pathname;

    if (workspace === "provider") {
      if (!isPathAllowedInProviderWorkspace(path)) {
        return <Navigate to={PROVIDER_HOME} replace />;
      }
    }

    if (workspace === "personal" || workspace === null) {
      if (isPathProviderPanelPath(path)) {
        return <Navigate to={PERSONAL_HOME} replace />;
      }
    }
  }

  return <Outlet />;
}

import { useCallback, useEffect, useRef, useState } from "react";
import { useTranslation } from "react-i18next";
import { FiMapPin, FiNavigation } from "react-icons/fi";
import { toast } from "react-toastify";
import { fetchNearestPlaces, searchPlaces } from "@/api/public";
import { getApiErrorMessage } from "@/utils/errors";

const PLACES_INITIAL_LIMIT = 40;
const PLACES_SEARCH_LIMIT = 24;

function formatPlaceLabel(hit) {
  const city = hit.subtitle?.trim();
  return city ? `${hit.title}, ${city}` : hit.title;
}

function formatPlaceFromEntity(p) {
  const city = p.city?.name?.trim();
  return city ? `${p.name}, ${city}` : p.name;
}

/**
 * @param {{ placeId: string; label: string; lat: number; lng: number; slug: string }} place
 */
export function ComposerPlaceField({
  value,
  onChange,
  selectedPlace,
  onSelectPlace,
  locating,
  onLocatingChange,
}) {
  const { t } = useTranslation();
  const rootRef = useRef(null);
  const debounceRef = useRef(0);
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [loadingAll, setLoadingAll] = useState(true);
  const [hits, setHits] = useState([]);
  const [basePlaces, setBasePlaces] = useState([]);

  useEffect(() => {
    const onDoc = (e) => {
      if (!rootRef.current?.contains(e.target)) {
        setOpen(false);
      }
    };
    document.addEventListener("mousedown", onDoc);
    return () => document.removeEventListener("mousedown", onDoc);
  }, []);

  useEffect(() => {
    let cancelled = false;
    void (async () => {
      setLoadingAll(true);
      try {
        const res = await searchPlaces("", PLACES_INITIAL_LIMIT);
        const items = Array.isArray(res?.items) ? res.items : [];
        const places = items.filter((h) => h.type === "place" && h.placeId);
        if (!cancelled) {
          setBasePlaces(places);
          setHits(places);
        }
      } catch (error) {
        if (!cancelled) {
          toast.error(
            getApiErrorMessage(
              error,
              t("social.feed.composer.placeSearchFailed", { defaultValue: "Could not load places" }),
            ),
          );
          setBasePlaces([]);
          setHits([]);
        }
      } finally {
        if (!cancelled) {
          setLoadingAll(false);
        }
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [t]);

  useEffect(() => {
    const q = value.trim();
    window.clearTimeout(debounceRef.current);

    if (q.length >= 2) {
      debounceRef.current = window.setTimeout(() => {
        void (async () => {
          setLoading(true);
          try {
            const res = await searchPlaces(q, PLACES_SEARCH_LIMIT);
            const items = Array.isArray(res?.items) ? res.items : [];
            const places = items.filter((h) => h.type === "place" && h.placeId);
            setHits(places);
            setOpen(true);
          } catch (error) {
            toast.error(
              getApiErrorMessage(
                error,
                t("social.feed.composer.placeSearchFailed", { defaultValue: "Could not load places" }),
              ),
            );
            setHits([]);
          } finally {
            setLoading(false);
          }
        })();
      }, 320);
      return () => window.clearTimeout(debounceRef.current);
    }

    setLoading(false);
    const low = q.toLowerCase();
    if (q.length === 0) {
      setHits(basePlaces);
    } else {
      setHits(
        basePlaces.filter(
          (h) =>
            (h.title && h.title.toLowerCase().includes(low)) ||
            (h.subtitle && h.subtitle.toLowerCase().includes(low)),
        ),
      );
    }
    return undefined;
  }, [value, basePlaces, t]);

  const pickHit = useCallback(
    (hit) => {
      onSelectPlace({
        placeId: hit.placeId,
        label: formatPlaceLabel(hit),
        lat: hit.latitude,
        lng: hit.longitude,
        slug: hit.slug,
      });
      onChange(formatPlaceLabel(hit));
      setOpen(false);
    },
    [onChange, onSelectPlace],
  );

  const useMyLocation = useCallback(() => {
    if (!navigator.geolocation) {
      toast.error(
        t("social.feed.composer.geoUnsupported", {
          defaultValue: "Location is not supported in this browser",
        }),
      );
      return;
    }
    onLocatingChange(true);
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        try {
          const list = await fetchNearestPlaces(
            pos.coords.latitude,
            pos.coords.longitude,
            6,
          );
          const rows = Array.isArray(list) ? list : [];
          if (rows.length === 0) {
            toast.error(
              t("social.feed.composer.noNearbyPlaces", {
                defaultValue: "No Waynest places found near you yet",
              }),
            );
            onLocatingChange(false);
            return;
          }
          const p = rows[0];
          const label = formatPlaceFromEntity(p);
          onSelectPlace({
            placeId: p.id,
            label,
            lat: Number(p.latitude),
            lng: Number(p.longitude),
            slug: p.slug,
          });
          onChange(label);
          setOpen(false);
          toast.success(
            t("social.feed.composer.nearestPlaceSet", {
              defaultValue: "Nearest place selected",
            }),
          );
        } catch (error) {
          toast.error(
            getApiErrorMessage(
              error,
              t("social.feed.composer.nearestFailed", { defaultValue: "Could not load nearby places" }),
            ),
          );
        } finally {
          onLocatingChange(false);
        }
      },
      () => {
        toast.error(
          t("social.feed.composer.geoDenied", {
            defaultValue: "Could not read your location — try typing a place or pick from the list",
          }),
        );
        onLocatingChange(false);
      },
      { enableHighAccuracy: false, timeout: 14_000, maximumAge: 60_000 },
    );
  }, [onChange, onLocatingChange, onSelectPlace, t]);

  const showList = open && hits.length > 0;
  const showLoading = loading || loadingAll;

  return (
    <div className="social-composer-extra">
      <div className="social-composer-extra__head">
        <FiMapPin aria-hidden className="social-composer-extra__icon" />
        <span className="social-composer-extra__title">
          {t("social.feed.composer.placeSection", { defaultValue: "Place" })}
        </span>
      </div>
      <p className="social-composer-extra__hint">
        {t("social.feed.composer.placeHintDb", {
          defaultValue:
            "All Waynest places load below — type to search the full list, or use your location.",
        })}
      </p>
      <div className="social-composer-place-row" ref={rootRef}>
        <div className="social-composer-place-autocomplete">
          <input
            type="text"
            className={`social-composer-field__input social-composer-place-input${
              selectedPlace ? " social-composer-place-input--linked" : ""
            }`}
            placeholder={t("social.feed.composer.placePlaceholder", {
              defaultValue: "Search or pick from the list…",
            })}
            value={value}
            onChange={(e) => {
              onChange(e.target.value);
              if (selectedPlace) {
                onSelectPlace(null);
              }
            }}
            onFocus={() => {
              setOpen(true);
            }}
            autoComplete="off"
            aria-autocomplete="list"
            aria-expanded={open}
          />
          {selectedPlace ? (
            <span
              className="social-composer-place-badge"
              title={t("social.feed.composer.linkedPlace", { defaultValue: "Linked to Waynest place" })}
            >
              ✓
            </span>
          ) : null}
          {showList ? (
            <ul className="social-composer-place-suggestions" role="listbox">
              {hits.map((hit) => (
                <li key={hit.placeId} role="none">
                  <button
                    type="button"
                    role="option"
                    className="social-composer-place-suggestion"
                    onMouseDown={(e) => e.preventDefault()}
                    onClick={() => pickHit(hit)}
                  >
                    <span className="social-composer-place-suggestion__title">{hit.title}</span>
                    {hit.subtitle ? (
                      <span className="social-composer-place-suggestion__sub">{hit.subtitle}</span>
                    ) : null}
                  </button>
                </li>
              ))}
            </ul>
          ) : null}
          {showLoading ? (
            <span className="social-composer-place-loading" aria-live="polite">
              {t("common.loading", { defaultValue: "Loading…" })}
            </span>
          ) : null}
        </div>
        <button
          type="button"
          className="social-composer-locate-btn"
          onClick={() => void useMyLocation()}
          disabled={locating}
          title={t("social.feed.composer.useMyLocation", { defaultValue: "Use my location" })}
        >
          <FiNavigation aria-hidden />
          <span className="social-composer-locate-btn__label">
            {locating
              ? t("social.feed.composer.locating", { defaultValue: "Locating…" })
              : t("social.feed.composer.useMyLocationShort", { defaultValue: "My location" })}
          </span>
        </button>
      </div>
    </div>
  );
}

import { useCallback, useMemo, useRef, useState } from "react";
import { useAuth } from "@/context/AuthContext";
import { useTranslation } from "react-i18next";
import { FiImage } from "react-icons/fi";
import { resolveMediaUrl } from "@/utils/mediaUrl";
import { formatTripPlanDisplayName } from "@/utils/trips/formatTripPlanDisplayName";
import { ComposerPlaceField } from "./ComposerPlaceField";
import { SocialComposerSelect } from "./SocialComposerSelect";

const CreatePostCard = ({
  publishing,
  canPublish,
  savedPlans,
  savedPlansLoading,
  selectedTripPlanId,
  newPostTitle,
  newPostBody,
  newPostVisibility,
  postImages,
  uploadProgress,
  locationLabel,
  selectedPlace,
  onPublish,
  onPickPostImages,
  onRemovePostImage,
  setSelectedTripPlanId,
  setNewPostTitle,
  setNewPostBody,
  setNewPostVisibility,
  setLocationLabel,
  setSelectedPlace,
  setLocating,
  locating,
  showSavedPlanSelect = true,
}) => {
  const { t } = useTranslation();
  const fileInputRef = useRef(null);
  const [dragOver, setDragOver] = useState(false);

  const openFilePicker = () => {
    fileInputRef.current?.click();
  };

  const onDragOver = useCallback((e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragOver(true);
  }, []);

  const onDragLeave = useCallback((e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragOver(false);
  }, []);

  const onDrop = useCallback(
    (e) => {
      e.preventDefault();
      e.stopPropagation();
      setDragOver(false);
      const files = e.dataTransfer?.files;
      if (!files?.length) return;
      const synthetic = { target: { files, value: "" } };
      void onPickPostImages(synthetic);
    },
    [onPickPostImages],
  );

  const planOptions = useMemo(() => {
    const emptyLabel = savedPlansLoading
      ? t("social.feed.composer.loadingPlans", {
          defaultValue: "Loading plans…",
        })
      : savedPlans.length === 0
        ? t("social.feed.composer.noPlans", { defaultValue: "No saved plans" })
        : t("social.feed.composer.planOptional", {
            defaultValue: "No plan attached",
          });
    return [
      { value: "", label: emptyLabel },
      ...savedPlans.map((plan) => ({
        value: plan.id,
        label: formatTripPlanDisplayName(plan, t),
      })),
    ];
  }, [savedPlans, savedPlansLoading, t]);

  const { user } = useAuth();

  const visibilityOptions = useMemo(() => {
    const isProvider = user?.role === "PROVIDER";
    if (isProvider) {
      return [
        {
          value: "PUBLIC",
          label: t("social.feed.composer.visPublic", {
            defaultValue: "Public",
          }),
        },
        {
          value: "FOLLOWERS",
          label: t("social.feed.composer.visFollowers", {
            defaultValue: "Followers",
          }),
        },
      ];
    }
    return [
      {
        value: "PUBLIC",
        label: t("social.feed.composer.visPublic", { defaultValue: "Public" }),
      },
      {
        value: "FRIENDS",
        label: t("social.feed.composer.visFriends", {
          defaultValue: "Friends",
        }),
      },
      {
        value: "PRIVATE",
        label: t("social.feed.composer.visPrivate", {
          defaultValue: "Private",
        }),
      },
    ];
  }, [t, user]);

  const uploadBusy = uploadProgress > 0 && uploadProgress < 100;
  const publishDisabled = publishing || !canPublish || uploadBusy;

  return (
    <article className="social-composer">
      <div className="social-composer-header">
        <div>
          <p className="social-composer-eyebrow">
            {t("social.feed.composer.eyebrow", {
              defaultValue: "Publish to Waynest",
            })}
          </p>
          <h2>
            {t("social.feed.composer.title", {
              defaultValue: "Share your trip",
            })}
          </h2>
        </div>
        <p className="social-composer-helper">
          {t("social.feed.composer.helper", {
            defaultValue:
              "Write a note, add photos or a place, or attach a saved plan — publish what matters to you.",
          })}
        </p>
      </div>

      <div className="social-composer-stack">
        <label className="social-composer-field">
          <span className="social-composer-field__label">
            {t("social.feed.composer.postTitle", { defaultValue: "Title" })}
          </span>
          <input
            type="text"
            className="social-composer-field__input"
            placeholder={t("social.feed.composer.postTitlePlaceholder", {
              defaultValue: "Post title (optional)",
            })}
            value={newPostTitle}
            onChange={(event) => setNewPostTitle(event.target.value)}
          />
        </label>

        <label className="social-composer-field">
          <span className="social-composer-field__label">
            {t("social.feed.composer.bodyLabel", {
              defaultValue: "What’s on your mind?",
            })}
          </span>
          <textarea
            className="social-composer-field__textarea"
            placeholder={t("social.feed.composer.bodyPlaceholder", {
              defaultValue:
                "Write something about your trip, a tip, or a moment…",
            })}
            value={newPostBody}
            onChange={(event) => setNewPostBody(event.target.value)}
            rows={4}
          />
        </label>
      </div>

      <div className="social-composer-extras">
        <div className="social-composer-extra">
          <div className="social-composer-extra__head">
            <FiImage aria-hidden className="social-composer-extra__icon" />
            <span className="social-composer-extra__title">
              {t("social.feed.composer.imagesSection", {
                defaultValue: "Photos",
              })}
            </span>
          </div>
          <p className="social-composer-extra__hint">
            {t("social.feed.composer.imagesHint", {
              defaultValue: "PNG or JPG, up to 6 images · 5MB each",
            })}
          </p>
          <input
            ref={fileInputRef}
            type="file"
            accept="image/*"
            multiple
            className="social-composer-file-input"
            onChange={onPickPostImages}
          />
          <button
            type="button"
            className={`social-composer-dropzone${dragOver ? " social-composer-dropzone--active" : ""}`}
            onDragOver={onDragOver}
            onDragLeave={onDragLeave}
            onDrop={onDrop}
            onClick={openFilePicker}>
            <FiImage aria-hidden className="social-composer-dropzone__glyph" />
            <span className="social-composer-dropzone__text">
              {t("social.feed.composer.dropzone", {
                defaultValue: "Drop images here or click to browse",
              })}
            </span>
          </button>
          {uploadBusy ? (
            <p className="social-composer-upload-status" role="status">
              {t("social.feed.composer.uploading", {
                defaultValue: "Uploading…",
              })}{" "}
              {uploadProgress}%
            </p>
          ) : null}
          {postImages.length > 0 ? (
            <div className="social-post-images-grid">
              {postImages.map((url, idx) => (
                <div key={`${url}-${idx}`} className="social-post-image-item">
                  <img
                    src={resolveMediaUrl(url)}
                    alt=""
                    className="social-post-image"
                  />
                  <button
                    type="button"
                    className="social-post-image-remove"
                    onClick={() => onRemovePostImage(idx)}>
                    {t("social.feed.composer.removeImage", {
                      defaultValue: "Remove",
                    })}
                  </button>
                </div>
              ))}
            </div>
          ) : null}
        </div>

        <ComposerPlaceField
          value={locationLabel}
          onChange={setLocationLabel}
          selectedPlace={selectedPlace}
          onSelectPlace={setSelectedPlace}
          locating={locating}
          onLocatingChange={setLocating}
        />
      </div>

      <div className="social-composer-footer">
        {showSavedPlanSelect ? (
          <div className="social-composer-footer__field social-composer-footer__field--grow">
            <SocialComposerSelect
              id="composer-saved-plan"
              label={t("social.feed.composer.planLabel", {
                defaultValue: "Saved plan",
              })}
              value={selectedTripPlanId}
              onChange={setSelectedTripPlanId}
              options={planOptions}
              disabled={savedPlansLoading}
            />
          </div>
        ) : null}

        <div className="social-composer-footer__field social-composer-footer__field--narrow">
          <SocialComposerSelect
            id="composer-visibility"
            label={t("social.feed.composer.visibilityLabel", {
              defaultValue: "Who can see",
            })}
            value={newPostVisibility}
            onChange={setNewPostVisibility}
            options={visibilityOptions}
          />
        </div>

        <div className="social-composer-footer__submit-wrap">
          <button
            className="social-composer-submit"
            type="button"
            onClick={() => void onPublish()}
            disabled={publishDisabled}>
            {publishing
              ? t("social.feed.composer.publishing", {
                  defaultValue: "Publishing…",
                })
              : t("social.feed.composer.publish", { defaultValue: "Publish" })}
          </button>
        </div>
      </div>
    </article>
  );
};

export default CreatePostCard;

import {
  FiArrowRight,
  FiBookmark,
  FiCompass,
  FiHome,
  FiInfo,
