      icon: <FiCompass />,
    },
    {
      key: "planner",
      to: "/plan",
      label: t("navbar.planner", { defaultValue: "Planner" }),
      description: t("sidebar.memberPlannerHint", {
        defaultValue: "Generate and refine your next AI itinerary",
