      label: t("sidebar.messengerTitle", { defaultValue: "Messenger" }),
      description: t("sidebar.messengerHint", {
        defaultValue: "Open direct chats, group planning, and traveler threads",
      }),
      icon: <FiMessageCircle />,
    },
    {
      key: "friends",
      to: "/profile/friends",
      label: t("sidebar.friends", { defaultValue: "Friends" }),
      description: t("sidebar.friendsHint", {
        defaultValue: "See your friends and traveler connections",
      }),
      icon: <FiUsers />,
    },
    {
      key: "saved",
      to: "/saved-plans",
      label: t("sidebar.saved", { defaultValue: "Saved Plans" }),
      description: t("sidebar.savedHint", {
        defaultValue: "Return to the trips you kept for later",
      }),
      icon: <FiBookmark />,
    },
    {
      key: "profile",
      to: "/profile",
      label: t("sidebar.profile", { defaultValue: "Profile" }),
      description: t("sidebar.profileHint", {
