                <span className="fb3-leftNavMeta">{item.description}</span>
              </span>
              <FiArrowRight className="fb3-leftNavArrow" aria-hidden="true" />
            </NavLink>
          ))}
        </div>
      </nav>

      {isSignedIn && (
        <div className="fb3-sidebar-footer">
          <Link to="/settings" className="fb3-footer-action">
            <FiSettings size={15} />
            <span>{t("sidebar.settings", { defaultValue: "Settings" })}</span>
          </Link>
          <button
            type="button"
            className="fb3-footer-action fb3-footer-action--logout"
            onClick={async () => {
              await logout?.();
              navigate("/");
            }}>
            <FiLogOut size={15} />
            <span>{t("sidebar.logout", { defaultValue: "Log out" })}</span>
          </button>
        </div>
      )}

      {showJoinCard ? (
        <section className="fb3-card fb3-card--planner">
          <span className="fb3-miniTag">
            {t("sidebar.plannerTag", { defaultValue: "Member access" })}
          </span>
          <h3 className="fb3-cardTitle">
            {t("sidebar.joinCardTitle", {
              defaultValue: "Unlock the social layer",
            })}
          </h3>
          <p className="fb3-cardText">
            {t("sidebar.joinCardBody", {
              defaultValue:
                "Sign in when you want stories, chats, saved plans, profiles, and traveler connections.",
            })}
          </p>
          <Link
            to="/login"
            className="fb3-railLinkButton fb3-railLinkButton--accent">
            <FiLogIn aria-hidden="true" />
            <span>{t("navbar.login", { defaultValue: "Login" })}</span>
          </Link>
        </section>
      ) : null}
    </div>
  );
};

export default LeftSidebar;

