import { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { useLocation } from "react-router-dom";
import { FiMenu, FiX } from "react-icons/fi";

import { useMediaQuery } from "@/hooks/useMediaQuery";

import Feed from "./Feed";
import LeftSidebar from "./LeftSidebar";
import RightSidebar from "./RightSidebar";

import "../facebookLayout.css";

const MOBILE_BREAKPOINT = "(max-width: 860px)";

const MainLayout = ({ children, variant = "guest-discovery" }) => {
  const { t } = useTranslation();
  const location = useLocation();
  /** Traveler left/right rails — hide on profile, user pages, and public provider business pages */
  const hideSocialRails =
    variant === "signed-in-social" &&
    (location.pathname.startsWith("/profile") ||
      location.pathname.startsWith("/u/") ||
      location.pathname.startsWith("/p/") ||
      location.pathname.startsWith("/provider/"));
  const showLeftRail =
    variant !== "auth" &&
    variant !== "messenger" &&
    variant !== "guest-discovery" &&
    !hideSocialRails;
  const showRightRail = variant === "signed-in-social" && !hideSocialRails;
  const isMobileSidebar = useMediaQuery(MOBILE_BREAKPOINT);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  useEffect(() => {
    setMobileMenuOpen(false);
  }, [location.pathname]);

  useEffect(() => {
    if (!isMobileSidebar) {
      setMobileMenuOpen(false);
    }
  }, [isMobileSidebar]);

  useEffect(() => {
    if (!mobileMenuOpen || typeof document === "undefined") {
      return undefined;
    }
    const previous = document.body.style.overflow;
    document.body.style.overflow = "hidden";
    return () => {
      document.body.style.overflow = previous;
    };
  }, [mobileMenuOpen]);

  const desktopLeftAside =
    showLeftRail && !isMobileSidebar ? (
      <aside className="fb3-sidebar fb3-left">
        <LeftSidebar variant={variant} />
      </aside>
    ) : null;

  const mobileRailChrome =
    showLeftRail && isMobileSidebar ? (
      <>
        <div className="fb3-mobileRailBar">
          <button
            type="button"
            className="fb3-mobileRailBarBtn"
            onClick={() => setMobileMenuOpen(true)}
            aria-expanded={mobileMenuOpen}
            aria-controls="fb3-mobile-sidebar-drawer"
          >
            <FiMenu aria-hidden />
            <span>{t("sidebar.openMenu", { defaultValue: "Menu" })}</span>
          </button>
        </div>
        {mobileMenuOpen ? (
          <>
            <button
              type="button"
              className="fb3-mobileRailBackdrop"
              aria-label={t("sidebar.closeMenu", { defaultValue: "Close menu" })}
              onClick={() => setMobileMenuOpen(false)}
            />
            <aside
              id="fb3-mobile-sidebar-drawer"
              className="fb3-sidebar fb3-sidebar--mobileDrawer"
              aria-modal="true"
              role="dialog"
              aria-label={t("sidebar.navigation", { defaultValue: "Navigation" })}
            >
              <div className="fb3-sidebarDrawerHeader">
                <button
                  type="button"
                  className="fb3-sidebarDrawerClose"
                  onClick={() => setMobileMenuOpen(false)}
                  aria-label={t("sidebar.closeMenu", { defaultValue: "Close menu" })}
                >
                  <FiX aria-hidden />
                </button>
              </div>
              <LeftSidebar variant={variant} />
            </aside>
          </>
        ) : null}
      </>
    ) : null;

  return (
    <div
      className={`fb3-layout fb3-layout--${variant}${
        hideSocialRails ? " fb3-layout--full-center" : ""
      }`}
    >
      {desktopLeftAside}
      <section className={`fb3-center fb3-center--${variant}`}>
        {mobileRailChrome}
        <Feed>{children}</Feed>
      </section>
      {showRightRail ? (
        <aside className="fb3-sidebar fb3-right">
          <RightSidebar />
        </aside>
      ) : null}
    </div>
  );
};

export default MainLayout;

import { Link } from "react-router-dom";
import { toast } from "react-toastify";
import { useTranslation } from "react-i18next";
import { useEffect, useState } from "react";
import {
  FiBookmark,
  FiEdit2,
  FiExternalLink,
  FiHeart,
  FiMapPin,
  FiMessageCircle,
  FiShare2,
  FiTrash2,
} from "react-icons/fi";

import { copyTextToClipboard } from "@/utils/clipboard";
import { getResolvedAvatarUrl, handleAvatarImageError } from "@/utils/avatar";
import { getApiErrorMessage } from "@/utils/errors";
import { resolveMediaUrl } from "@/utils/mediaUrl";

import PostCommentsDialog from "./PostCommentsDialog";
import "./PostCard.css";

function formatPostDate(iso, locale) {
  try {
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return "";
    return d.toLocaleString(locale, {
      dateStyle: "medium",
      timeStyle: "short",
    });
  } catch {
    return "";
  }
}

function parsePostLocation(snapshot) {
  if (!snapshot || typeof snapshot !== "object") return null;
  const raw = snapshot.location;
  if (!raw || typeof raw !== "object") return null;
  const label = typeof raw.label === "string" ? raw.label.trim() : "";
  if (!label) return null;
  const lat = typeof raw.lat === "number" && Number.isFinite(raw.lat) ? raw.lat : null;
  const lng = typeof raw.lng === "number" && Number.isFinite(raw.lng) ? raw.lng : null;
  const slug = typeof raw.slug === "string" && raw.slug.trim() ? raw.slug.trim() : null;
  const mapsUrl =
    lat != null && lng != null
      ? `https://www.openstreetmap.org/?mlat=${lat}&mlon=${lng}&zoom=14`
      : `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(label)}`;
  const placePath = slug ? `/places/${encodeURIComponent(slug)}` : null;
  return { label, mapsUrl, placePath };
}

const PostCard = ({
  post,
  isAuthenticated,
  toggleSocialLike,
  saveSocialPost,
  unsaveSocialPost,
  actorId,
  onDeletePost,
  onUpdatePost,
}) => {
  const { t, i18n } = useTranslation();
  const [editing, setEditing] = useState(false);
  const [draftTitle, setDraftTitle] = useState(post.title ?? "");
  const [draftBody, setDraftBody] = useState(post.body ?? "");
  const [likeCount, setLikeCount] = useState(post.likeCount ?? post._count?.likes ?? 0);
  const [likedByMe, setLikedByMe] = useState(Boolean(post.likedByMe));
  const [savedByMe, setSavedByMe] = useState(Boolean(post.savedByMe));
  const [savingPost, setSavingPost] = useState(false);
  const [commentsOpen, setCommentsOpen] = useState(false);
  const [commentCount, setCommentCount] = useState(post.commentCount ?? post._count?.comments ?? 0);

  useEffect(() => {
    setLikeCount(post.likeCount ?? post._count?.likes ?? 0);
    setLikedByMe(Boolean(post.likedByMe));
    setSavedByMe(Boolean(post.savedByMe));
    setCommentCount(post.commentCount ?? post._count?.comments ?? 0);
  }, [post.id, post.likeCount, post.likedByMe, post.savedByMe, post.commentCount]);

  const authorHref = post.author?.username
    ? `/u/${encodeURIComponent(post.author.username)}`
    : `/social/users/${encodeURIComponent(post.authorId)}`;
  const authorName =
    post.author?.username ?? t("social.feed.traveler", { defaultValue: "Traveler" });
  const authorInitial = authorName.trim().charAt(0).toUpperCase() || "T";
  const avatarUrl = getResolvedAvatarUrl(post.author);

  const imageUrls = Array.isArray(post.imageUrls) ? post.imageUrls : [];
  const imageCount = Math.min(imageUrls.length, 6);
  const locationInfo = parsePostLocation(post.snapshot);

  const onLike = async () => {
    if (!isAuthenticated) {
      toast.info(t("social.feed.loginFirst", { defaultValue: "Please login first" }));
      return;
    }

    try {
      const result = await toggleSocialLike(post.id);
      setLikedByMe(result.liked);
      setLikeCount(typeof result.likeCount === "number" ? result.likeCount : likeCount);
    } catch (error) {
      toast.error(
        getApiErrorMessage(error, t("social.feed.likeFailed", { defaultValue: "Could not update like" })),
      );
    }
  };

  const onSave = async () => {
    if (!isAuthenticated) {
      toast.info(t("social.feed.loginFirst", { defaultValue: "Please login first" }));
      return;
    }

    if (savingPost) {
      return;
    }

    setSavingPost(true);
    try {
      if (savedByMe) {
        await unsaveSocialPost(post.id);
        setSavedByMe(false);
        toast.success(
          t("social.feed.removedFromSaved", { defaultValue: "Removed from saved" }),
        );
      } else {
        await saveSocialPost(post.id);
        setSavedByMe(true);
        toast.success(
          t("social.feed.savedToAccount", { defaultValue: "Saved to your account" }),
        );
      }
    } catch (error) {
      toast.error(
        getApiErrorMessage(
          error,
          t("social.feed.saveFailed", { defaultValue: "Could not update saved posts" }),
        ),
      );
    } finally {
      setSavingPost(false);
    }
  };

  const onShare = async () => {
    if (!post.shareSlug) {
      toast.info(
        t("social.feed.shareUnavailable", {
          defaultValue: "This post has no shareable trip yet",
        }),
      );
      return;
    }

    const url = `${window.location.origin}/trip/${post.shareSlug}`;
    await copyTextToClipboard(url);
    toast.success(t("social.feed.shareCopied", { defaultValue: "Trip link copied" }));
  };

  const isOwner = Boolean(actorId && post.authorId === actorId);

  return (
    <article className="social-post-card">
      <header className="social-post-card__header">
        <div className="social-post-card__author">
          <div className="social-post-card__avatar" aria-hidden="true">
            {avatarUrl ? (
              <img
                src={avatarUrl}
                alt=""
                className="social-post-card__avatarImg"
                onError={handleAvatarImageError}
              />
            ) : (
              authorInitial
            )}
          </div>
          <div className="social-post-card__meta">
            <p className="social-post-card__name">
              <Link to={authorHref}>{authorName}</Link>
            </p>
            <p className="social-post-card__time">{formatPostDate(post.createdAt, i18n.language)}</p>
          </div>
        </div>
        {post.shareSlug ? (
          <span className="social-post-card__chip">
            {t("social.feed.sharedPlan", { defaultValue: "Shared itinerary" })}
          </span>
        ) : null}
      </header>

      {post.title || post.body ? (
        <div className="social-post-card__text">
          {post.title ? <h3 className="social-post-card__title">{post.title}</h3> : null}
          {post.body ? <p className="social-post-card__body">{post.body}</p> : null}
        </div>
      ) : null}

      {imageUrls.length > 0 ? (
        <div
          className={`social-post-card__gallery social-post-card__gallery--${imageCount}`}
          role="group"
          aria-label={t("social.feed.postImages", { defaultValue: "Post images" })}
        >
          {imageUrls.slice(0, 6).map((imageUrl, idx) => (
            <img
              key={`${imageUrl}-${idx}`}
              src={resolveMediaUrl(imageUrl)}
              alt=""
              className="social-post-card__img"
            />
          ))}
        </div>
      ) : null}

      {locationInfo ? (
        <div className="social-post-card__location">
          <FiMapPin aria-hidden className="social-post-card__locationIcon" />
          {locationInfo.placePath ? (
            <Link to={locationInfo.placePath} className="social-post-card__locationLink">
              {locationInfo.label}
            </Link>
          ) : (
            <a
              href={locationInfo.mapsUrl}
              target="_blank"
              rel="noopener noreferrer"
              className="social-post-card__locationLink"
            >
              {locationInfo.label}
            </a>
          )}
        </div>
      ) : null}

      {editing ? (
        <div className="social-post-card__edit">
          <input
            value={draftTitle}
            onChange={(event) => setDraftTitle(event.target.value)}
            placeholder={t("social.feed.editTitle", { defaultValue: "Title" })}
          />
          <textarea
            value={draftBody}
            onChange={(event) => setDraftBody(event.target.value)}
            placeholder={t("social.feed.editBody", { defaultValue: "Body" })}
          />
          <button
            type="button"
            className="social-post-card__editSave"
            onClick={async () => {
              await onUpdatePost?.(post.id, {
                title: draftTitle.trim(),
                body: draftBody.trim(),
              });
              setEditing(false);
            }}
          >
            {t("social.feed.saveEdits", { defaultValue: "Save" })}
          </button>
        </div>
      ) : null}

      {post.shareSlug ? (
        <div className="social-post-card__trip">
          <Link to={`/trip/${encodeURIComponent(post.shareSlug)}`} className="social-post-card__tripLink">
            <FiExternalLink aria-hidden />
            {t("social.feed.openSharedTrip", { defaultValue: "Open shared trip" })}
          </Link>
        </div>
      ) : null}

      <footer className="social-post-card__footer">
        <button
          type="button"
          className={`social-post-card__action${likedByMe ? " social-post-card__action--liked" : ""}`}
          onClick={() => void onLike()}
          aria-pressed={likedByMe}
          aria-label={t("social.feed.actions.like", { defaultValue: "Like" })}
        >
          <FiHeart aria-hidden className="social-post-card__heartIcon" />
          <span>{likeCount}</span>
        </button>
        <button
          type="button"
          className={`social-post-card__action${savedByMe ? " social-post-card__action--saved" : ""}`}
          onClick={() => void onSave()}
          disabled={savingPost}
          aria-pressed={savedByMe}
          aria-label={
            savedByMe
              ? t("social.feed.actions.unsave", { defaultValue: "Remove from saved" })
              : t("social.feed.actions.save", { defaultValue: "Save" })
          }
        >
          <FiBookmark aria-hidden className="social-post-card__bookmarkIcon" />
          <span>
            {savedByMe
              ? t("social.feed.actions.saved", { defaultValue: "Saved" })
              : t("social.feed.actions.save", { defaultValue: "Save" })}
          </span>
        </button>
        <button
          type="button"
          className="social-post-card__action"
          onClick={(event) => {
            event.preventDefault();
            event.stopPropagation();
            setCommentsOpen(true);
          }}
          aria-label={t("social.feed.comments", { defaultValue: "Comments" })}
        >
          <FiMessageCircle aria-hidden />
          <span>{commentCount}</span>
        </button>
        <button
          type="button"
          className="social-post-card__action"
          onClick={() => void onShare()}
          aria-label={t("social.feed.actions.share", { defaultValue: "Share" })}
        >
          <FiShare2 aria-hidden />
          <span>{t("social.feed.actions.share", { defaultValue: "Share" })}</span>
        </button>
        {isOwner ? (
          <>
            <button
              type="button"
              className="social-post-card__action"
              onClick={() => setEditing((current) => !current)}
              aria-label={editing ? t("social.feed.cancelEdit", { defaultValue: "Cancel" }) : t("social.feed.edit", { defaultValue: "Edit" })}
            >
              <FiEdit2 aria-hidden />
              <span>{editing ? t("social.feed.cancelEdit", { defaultValue: "Cancel" }) : t("social.feed.edit", { defaultValue: "Edit" })}</span>
            </button>
            <button
              type="button"
              className="social-post-card__action social-post-card__action--danger"
              onClick={() => void onDeletePost?.(post.id)}
              aria-label={t("social.feed.delete", { defaultValue: "Delete" })}
            >
              <FiTrash2 aria-hidden />
              <span>{t("social.feed.delete", { defaultValue: "Delete" })}</span>
            </button>
          </>
        ) : null}
      </footer>

      {commentsOpen ? (
        <PostCommentsDialog
          isOpen={commentsOpen}
          onClose={() => setCommentsOpen(false)}
          postId={post.id}
          postTitle={post.title ?? ""}
          onCommentsLoaded={setCommentCount}
        />
      ) : null}
    </article>
  );
};

export default PostCard;

import { createPortal } from "react-dom";
import { useCallback, useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { FiX } from "react-icons/fi";
import { toast } from "react-toastify";

import { useAuth } from "@/context/AuthContext";
import { getApiErrorMessage } from "@/utils/errors";
import { createPostComment, fetchPostComments } from "@/services/social/social.service";

import "./PostCommentsDialog.css";

const PostCommentsDialog = ({
  isOpen,
  onClose,
  postId,
  postTitle,
  onCommentsLoaded,
}) => {
  const { t, i18n } = useTranslation();
  const { isAuthenticated, user } = useAuth();
  const [comments, setComments] = useState([]);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [text, setText] = useState("");

  const loadComments = useCallback(async () => {
    if (!postId) {
      return;
    }
    setLoading(true);
    try {
      const list = await fetchPostComments(postId);
      const rows = Array.isArray(list) ? list : [];
      setComments(rows);
      onCommentsLoaded?.(rows.length);
    } catch (error) {
      toast.error(
        getApiErrorMessage(
          error,
          t("social.comments.loadFailed", { defaultValue: "Could not load comments" }),
        ),
      );
    } finally {
      setLoading(false);
    }
  }, [postId, t, onCommentsLoaded]);

  useEffect(() => {
    if (isOpen && postId) {
      void loadComments();
      setText("");
    }
  }, [isOpen, postId, loadComments]);

  useEffect(() => {
    if (!isOpen) {
      return;
    }
    const onKey = (event) => {
      if (event.key === "Escape") {
        onClose();
      }
    };
    window.addEventListener("keydown", onKey);
    const previousOverflow = document.body.style.overflow;
    document.body.style.overflow = "hidden";
    return () => {
      window.removeEventListener("keydown", onKey);
      document.body.style.overflow = previousOverflow;
    };
  }, [isOpen, onClose]);

  if (!isOpen) {
    return null;
  }

  const authorLabel = (author) => {
    if (!author || typeof author !== "object") {
      return t("social.feed.traveler", { defaultValue: "Traveler" });
    }
    const u = author.username?.trim();
    if (u) {
      return u;
    }
    const name = `${author.firstName ?? ""} ${author.lastName ?? ""}`.trim();
    return name || t("social.feed.traveler", { defaultValue: "Traveler" });
  };

  const handleSubmit = async () => {
    const trimmed = text.trim();
    if (!trimmed || !isAuthenticated) {
      return;
    }
    setSubmitting(true);
    try {
      const saved = await createPostComment(postId, { content: trimmed });
      setText("");
      const author = user
        ? {
            id: user.id,
            username: user.username,
            firstName: user.firstName,
            lastName: user.lastName,
            avatarUrl: user.avatarUrl ?? null,
          }
        : null;
      setComments((current) => {
        const next = [
          ...current,
          author ? { ...saved, author } : saved,
        ];
        onCommentsLoaded?.(next.length);
        return next;
      });
    } catch (error) {
      toast.error(
        getApiErrorMessage(
          error,
          t("social.postDetail.addCommentFailed", { defaultValue: "Failed to add comment" }),
        ),
      );
    } finally {
      setSubmitting(false);
    }
  };

  const dialog = (
    <div className="post-comments-dialog__backdrop" onClick={onClose} role="presentation">
      <div
        className="post-comments-dialog"
        role="dialog"
        aria-modal="true"
        aria-labelledby="post-comments-dialog-title"
        onClick={(event) => event.stopPropagation()}
      >
        <header className="post-comments-dialog__header">
          <h2 id="post-comments-dialog-title" className="post-comments-dialog__title">
            {postTitle?.trim()
              ? postTitle.trim()
              : t("social.postDetail.commentsTitle", { defaultValue: "Comments" })}
          </h2>
          <button
            type="button"
            className="post-comments-dialog__close"
            onClick={onClose}
            aria-label={t("common.close", { defaultValue: "Close" })}
          >
            <FiX aria-hidden />
          </button>
        </header>

        <div className="post-comments-dialog__body">
          {loading ? (
            <p className="post-comments-dialog__muted">
              {t("social.comments.loading", { defaultValue: "Loading comments…" })}
            </p>
          ) : comments.length === 0 ? (
            <p className="post-comments-dialog__muted">
              {t("social.postDetail.commentsEmpty", { defaultValue: "No comments yet." })}
            </p>
          ) : (
            <ul className="post-comments-dialog__list">
              {comments.map((comment) => (
                <li key={comment.id} className="post-comments-dialog__item">
                  <div className="post-comments-dialog__itemMeta">
                    <span className="post-comments-dialog__author">
                      {authorLabel(comment.author)}
                    </span>
                    <time dateTime={comment.createdAt}>
                      {new Date(comment.createdAt).toLocaleString(i18n.language, {
                        dateStyle: "medium",
                        timeStyle: "short",
                      })}
                    </time>
                  </div>
                  <p className="post-comments-dialog__content">{comment.content}</p>
                </li>
              ))}
            </ul>
          )}
        </div>

        {isAuthenticated ? (
          <div className="post-comments-dialog__compose">
            <textarea
              className="post-comments-dialog__textarea"
              value={text}
              onChange={(event) => setText(event.target.value)}
              placeholder={t("social.postDetail.commentPlaceholder", {
                defaultValue: "Add a comment…",
              })}
              rows={3}
            />
            <button
              type="button"
              className="post-comments-dialog__submit"
              onClick={() => void handleSubmit()}
              disabled={submitting || !text.trim()}
            >
              {submitting
                ? t("social.comments.sending", { defaultValue: "Sending…" })
                : t("social.postDetail.addComment", { defaultValue: "Comment" })}
            </button>
          </div>
        ) : (
          <p className="post-comments-dialog__loginHint">
            {t("social.comments.loginToComment", {
              defaultValue: "Sign in to add a comment.",
            })}
          </p>
        )}
      </div>
    </div>
  );

  return createPortal(dialog, document.body);
};

export default PostCommentsDialog;

import { useEffect, useMemo, useState } from "react";
import { useTranslation } from "react-i18next";
import { toast } from "react-toastify";
import { getApiErrorMessage } from "@/utils/errors";
import { useAuth } from "@/context/AuthContext";
import { extractTripPlans } from "@/utils/trips/dataNormalizers";
import { createSocialPost, uploadImage } from "@/services/social/social.service";
import { fetchSavedTripPlans } from "@/api/trips";
import CreatePostCard from "./CreatePostCard";

/**
 * Publish trip posts — only mounted on the viewer's own social profile (`/u/:username`).
 */
const ProfilePostComposer = ({ onPublished }) => {
  const { t } = useTranslation();
  const { isAuthenticated } = useAuth();

  const [savedPlans, setSavedPlans] = useState([]);
  const [savedPlansLoading, setSavedPlansLoading] = useState(false);
  const [publishing, setPublishing] = useState(false);
  const [locating, setLocating] = useState(false);
  const [newPostBody, setNewPostBody] = useState("");
  const [newPostTitle, setNewPostTitle] = useState("");
  const [selectedTripPlanId, setSelectedTripPlanId] = useState("");
  const [newPostVisibility, setNewPostVisibility] = useState("PUBLIC");
  const [postImages, setPostImages] = useState([]);
  const [postUploadProgress, setPostUploadProgress] = useState(0);
  const [locationLabel, setLocationLabel] = useState("");
  const [selectedPlace, setSelectedPlace] = useState(
    /** @type {{ placeId: string; label: string; lat: number; lng: number; slug: string } | null} */ (
      null
    ),
  );

  useEffect(() => {
    if (!isAuthenticated) {
      setSavedPlans([]);
      setSelectedTripPlanId("");
      return;
    }

    const loadSavedPlans = async () => {
      try {
        setSavedPlansLoading(true);
        const payload = await fetchSavedTripPlans();
        const plans = extractTripPlans(payload).sort(
          (a, b) => new Date(b.createdAt) - new Date(a.createdAt),
        );
        setSavedPlans(plans);
      } catch (error) {
        setSavedPlans([]);
        toast.error(getApiErrorMessage(error, "Failed to load saved plans"));
      } finally {
        setSavedPlansLoading(false);
      }
    };

    void loadSavedPlans();
  }, [isAuthenticated]);

  const canPublish = useMemo(() => {
    const text = Boolean(newPostBody.trim() || newPostTitle.trim());
    const hasTrip = Boolean(selectedTripPlanId);
    const hasImgs = postImages.length > 0;
    const hasLoc = Boolean(selectedPlace || locationLabel.trim());
    return text || hasTrip || hasImgs || hasLoc;
  }, [newPostBody, newPostTitle, selectedTripPlanId, postImages, locationLabel, selectedPlace]);

  const publish = async () => {
    if (!isAuthenticated) {
      toast.info("Login first");
      return;
    }
    if (!canPublish) {
      toast.info(
        t("social.feed.composer.needContent", {
          defaultValue: "Add text, photos, a place, or attach a saved plan",
        }),
      );
      return;
    }
    try {
      setPublishing(true);
      const placeId = selectedPlace?.placeId;
      await createSocialPost({
        body: newPostBody.trim() || undefined,
        imageUrls: postImages.length ? postImages : undefined,
        title: newPostTitle.trim() || undefined,
        tripPlanId: selectedTripPlanId || undefined,
        visibility: newPostVisibility,
        placeId: placeId || undefined,
        locationLabel: !placeId && locationLabel.trim() ? locationLabel.trim() : undefined,
      });
      setNewPostBody("");
      setNewPostTitle("");
      setPostImages([]);
      setLocationLabel("");
      setSelectedPlace(null);
      setSelectedTripPlanId("");
      toast.success(t("social.feed.publishedToast", { defaultValue: "Published!" }));
      onPublished?.();
    } catch (error) {
      toast.error(getApiErrorMessage(error, "Publish failed"));
    } finally {
      setPublishing(false);
    }
  };

  const handlePickPostImages = async (event) => {
    const files = Array.from(event.target.files ?? []);
    if (files.length === 0) return;
    const nextUrls = [];
    try {
      for (const file of files) {
        if (!file.type.startsWith("image/")) {
          toast.error("Only image files are allowed");
          continue;
        }
        if (file.size > 5 * 1024 * 1024) {
          toast.error("Image size must be less than 5MB");
          continue;
        }
        const uploaded = await uploadImage(file, setPostUploadProgress);
        nextUrls.push(uploaded.path);
      }
      setPostImages((current) => [...current, ...nextUrls].slice(0, 6));
    } catch (error) {
      toast.error(getApiErrorMessage(error, "Image upload failed"));
    } finally {
      setPostUploadProgress(0);
      event.target.value = "";
    }
  };

  return (
    <CreatePostCard
      publishing={publishing}
      canPublish={canPublish}
      savedPlans={savedPlans}
      savedPlansLoading={savedPlansLoading}
      selectedTripPlanId={selectedTripPlanId}
      newPostTitle={newPostTitle}
      newPostBody={newPostBody}
      newPostVisibility={newPostVisibility}
      postImages={postImages}
      uploadProgress={postUploadProgress}
      locationLabel={locationLabel}
      selectedPlace={selectedPlace}
      onPublish={publish}
      onPickPostImages={handlePickPostImages}
      onRemovePostImage={(index) =>
        setPostImages((current) => current.filter((_, idx) => idx !== index))
      }
      setSelectedTripPlanId={setSelectedTripPlanId}
      setNewPostTitle={setNewPostTitle}
      setNewPostBody={setNewPostBody}
      setNewPostVisibility={setNewPostVisibility}
      setLocationLabel={setLocationLabel}
      setSelectedPlace={setSelectedPlace}
      setLocating={setLocating}
      locating={locating}
    />
  );
};

export default ProfilePostComposer;

import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { toast } from "react-toastify";
import { useAuth } from "@/context/AuthContext";
import { getApiErrorMessage } from "@/utils/errors";
import { extractTripPlans } from "@/utils/trips/dataNormalizers";
import { formatTripPlanDisplayName } from "@/utils/trips/formatTripPlanDisplayName";
import { fetchFriends, fetchIncomingFriendRequests } from "@/api/social";
import { fetchSavedTripPlans } from "@/api/trips";
import { friendPrimaryName, peerSecondaryLine } from "@/utils/socialDisplay";

const RightSidebar = () => {
  const { t } = useTranslation();
  const { isAuthenticated, user } = useAuth();

  const [loadingFriends, setLoadingFriends] = useState(false);
  const [loadingRequests, setLoadingRequests] = useState(false);
  const [loadingPlans, setLoadingPlans] = useState(false);
  const [friends, setFriends] = useState([]);
  const [requests, setRequests] = useState([]);
  const [savedPlans, setSavedPlans] = useState([]);

  const showPlans = user?.role === "USER";

  useEffect(() => {
    if (!isAuthenticated) {
      setFriends([]);
      return;
    }

    let active = true;
    void (async () => {
      try {
        setLoadingFriends(true);
        const payload = await fetchFriends();
        if (active) {
          setFriends(Array.isArray(payload) ? payload : []);
        }
      } catch (error) {
        if (active) {
          toast.error(
            getApiErrorMessage(
              error,
              t("sidebar.friendsLoadFailed", {
                defaultValue: "Could not load your friends list.",
              }),
            ),
          );
          setFriends([]);
        }
      } finally {
        if (active) {
          setLoadingFriends(false);
        }
      }
    })();

    return () => {
      active = false;
    };
  }, [isAuthenticated, user?.id, t]);

  useEffect(() => {
    if (!isAuthenticated) {
      setRequests([]);
      return;
    }

    let active = true;
    void (async () => {
      try {
        setLoadingRequests(true);
        const payload = await fetchIncomingFriendRequests();
        if (active) {
          setRequests((Array.isArray(payload) ? payload : []).slice(0, 4));
        }
      } catch (error) {
        if (active) {
          toast.error(
            getApiErrorMessage(
              error,
              t("sidebar.requestsLoadFailed", {
                defaultValue: "Could not load connection requests.",
              }),
            ),
          );
          setRequests([]);
        }
      } finally {
        if (active) {
          setLoadingRequests(false);
        }
      }
    })();

    return () => {
      active = false;
    };
  }, [isAuthenticated, user?.id, t]);

  useEffect(() => {
    if (!showPlans) {
      setSavedPlans([]);
      return;
    }

    let active = true;
    void (async () => {
      try {
        setLoadingPlans(true);
        const payload = await fetchSavedTripPlans();
        const normalized = extractTripPlans(payload)
          .sort(
            (left, right) =>
              new Date(right.createdAt).getTime() -
              new Date(left.createdAt).getTime(),
          )
          .slice(0, 3)
          .map((plan) => ({
            id: plan.id,
            title: formatTripPlanDisplayName(plan, t),
            createdAt: plan.createdAt,
            days: plan.days,
            shareSlug: plan.shareSlug ?? null,
          }));

        if (active) {
          setSavedPlans(normalized);
        }
      } catch (error) {
        if (active) {
          toast.error(
            getApiErrorMessage(
              error,
              t("social.feed.savedPlansLoadFailed", {
                defaultValue: "Failed to load saved plans",
              }),
            ),
          );
          setSavedPlans([]);
        }
      } finally {
        if (active) {
          setLoadingPlans(false);
        }
      }
    })();

    return () => {
      active = false;
    };
  }, [showPlans, t]);

  if (!isAuthenticated) {
    return null;
  }

  return (
    <div className="fb3-railList">
      <section className="fb3-card">
        <h3 className="fb3-cardTitle">
          {t("sidebar.friendsTitle", { defaultValue: "Your friends" })}
        </h3>
        {loadingFriends ? (
          <p className="fb3-cardText">
            {t("common.loading", { defaultValue: "Loading…" })}
          </p>
        ) : friends.length === 0 ? (
          <p className="fb3-cardText">
            {t("sidebar.friendsEmpty", {
              defaultValue:
                "Accepted traveler connections will appear here for faster messaging.",
            })}
          </p>
        ) : (
          <ul className="fb3-dataList">
            {friends.map((friend) => (
              <li key={friend.userId} className="fb3-dataRow">
                <div className="fb3-dataRowText">
                  <strong>
                    {friendPrimaryName(
                      friend,
                      t("sidebar.travelerLabel", { defaultValue: "Traveler" }),
                    )}
                  </strong>
                  {(() => {
                    const sub = peerSecondaryLine(friend);
                    return sub ? <span>{sub}</span> : null;
                  })()}
                </div>
                <Link
                  to={`/social?compose=${encodeURIComponent(friend.userId)}`}
                  className="fb3-inlineLink">
                  {t("sidebar.messageFriend", { defaultValue: "Message" })}
                </Link>
              </li>
            ))}
          </ul>
        )}
      </section>

      {requests.length > 0 || loadingRequests ? (
        <section className="fb3-card">
          <h3 className="fb3-cardTitle">
            {t("sidebar.connectionRequests", {
              defaultValue: "Connection requests",
            })}
          </h3>
          {loadingRequests ? (
            <p className="fb3-cardText">
              {t("common.loading", { defaultValue: "Loading…" })}
            </p>
          ) : (
            <ul className="fb3-dataList">
              {requests.map((request) => (
                <li key={request.requesterId} className="fb3-dataRow">
                  <div className="fb3-dataRowText">
                    <strong>{request.username}</strong>
                    <span>
                      {request.firstName || request.lastName
                        ? `${request.firstName} ${request.lastName}`.trim()
                        : t("sidebar.travelerLabel", {
                            defaultValue: "Traveler",
                          })}
                    </span>
                  </div>
                  <Link
                    to={`/u/${encodeURIComponent(request.username)}`}
                    className="fb3-inlineLink">
                    {t("sidebar.review", { defaultValue: "Review" })}
                  </Link>
                </li>
              ))}
            </ul>
          )}
        </section>
      ) : null}

      {showPlans ? (
        <section className="fb3-card fb3-card--accent">
          <span className="fb3-miniTag">
            {t("sidebar.aiPlanner", { defaultValue: "AI planner" })}
          </span>
          <h3 className="fb3-cardTitle">
            {t("sidebar.savedPlansTitle", { defaultValue: "Quick planner" })}
          </h3>
          {loadingPlans ? (
            <p className="fb3-cardText">
              {t("common.loading", { defaultValue: "Loading…" })}
            </p>
          ) : savedPlans.length === 0 ? (
            <>
              <p className="fb3-cardText">
                {t("sidebar.savedPlansEmpty", {
                  defaultValue:
                    "Your saved trips will appear here after you generate one.",
                })}
              </p>
              <div className="fb3-railActions">
                <Link
                  to="/plan"
                  className="fb3-railLinkButton fb3-railLinkButton--accent">
                  {t("sidebar.aiPlannerCta", { defaultValue: "Start planner" })}
                </Link>
              </div>
            </>
          ) : (
            <ul className="fb3-dataList">
              {savedPlans.map((plan) => (
                <li key={plan.id} className="fb3-dataRow">
                  <div className="fb3-dataRowText">
                    <strong>{plan.title}</strong>
                    <span>
                      {t("sidebar.planDays", {
                        defaultValue: "{{count}} days",
                        count: plan.days,
                      })}
                    </span>
                  </div>
                  <Link
                    to={
                      plan.shareSlug
                        ? `/trip/${encodeURIComponent(plan.shareSlug)}`
                        : "/saved-plans"
                    }
                    className="fb3-inlineLink">
                    {plan.shareSlug
                      ? t("sidebar.viewSharedPlan", { defaultValue: "Open" })
                      : t("sidebar.managePlans", { defaultValue: "Manage" })}
                  </Link>
                </li>
              ))}
            </ul>
          )}
        </section>
      ) : null}
    </div>
  );
};

export default RightSidebar;

