import { createContext, useCallback, useContext, useEffect, useMemo, useState } from "react";
import { useAuth } from "@/context/AuthContext";
import { fetchUnreadNotificationCount } from "@/api/social";

const NotificationsContext = createContext(undefined);

export function NotificationsProvider({ children }) {
  const { user, isAuthenticated } = useAuth();
  const [unreadCount, setUnreadCount] = useState(0);

  const refreshUnreadCount = useCallback(async () => {
    if (!isAuthenticated || !user?.id) {
      setUnreadCount(0);
      return;
    }
    try {
      const res = await fetchUnreadNotificationCount();
      const n = typeof res?.count === "number" ? res.count : Number(res?.count);
      setUnreadCount(Number.isFinite(n) ? n : 0);
    } catch {
      setUnreadCount(0);
    }
  }, [isAuthenticated, user?.id]);

  useEffect(() => {
    void refreshUnreadCount();
  }, [refreshUnreadCount]);

  useEffect(() => {
    if (!isAuthenticated) {
      return undefined;
    }
    const id = window.setInterval(() => {
      void refreshUnreadCount();
    }, 45_000);
    const onFocus = () => {
      void refreshUnreadCount();
    };
    window.addEventListener("focus", onFocus);
    return () => {
      window.clearInterval(id);
      window.removeEventListener("focus", onFocus);
    };
  }, [isAuthenticated, refreshUnreadCount]);

  const value = useMemo(
    () => ({ unreadCount, refreshUnreadCount }),
    [unreadCount, refreshUnreadCount],
  );

  return (
    <NotificationsContext.Provider value={value}>{children}</NotificationsContext.Provider>
  );
}

export function useNotifications() {
  const ctx = useContext(NotificationsContext);
  if (!ctx) {
    throw new Error("useNotifications must be used inside NotificationsProvider");
  }
  return ctx;
}

import { createContext, useContext, useEffect, useState } from "react";
import { fetchProviderProfile } from "@/api/provider";

const ProviderWorkspaceContext = createContext({
  slug: null,
  displayName: null,
  logoUrl: null,
  coverPhotoUrl: null,
  loading: true,
});

export const useProviderWorkspace = () => useContext(ProviderWorkspaceContext);

export const ProviderWorkspaceProvider = ({ children }) => {
  const [value, setValue] = useState({
    slug: null,
    displayName: null,
    logoUrl: null,
    coverPhotoUrl: null,
    loading: true,
  });

  useEffect(() => {
    let active = true;
    void fetchProviderProfile()
      .then((payload) => {
        if (!active) {
          return;
        }
        const slug =
          payload &&
          typeof payload === "object" &&
          typeof payload.slug === "string" &&
          payload.slug.trim()
            ? payload.slug.trim()
            : null;
        const displayName =
          payload &&
          typeof payload === "object" &&
          typeof payload.displayName === "string" &&
          payload.displayName.trim()
            ? payload.displayName.trim()
            : null;
        const logoUrl =
          payload &&
          typeof payload === "object" &&
          typeof payload.logoUrl === "string" &&
          payload.logoUrl.trim()
            ? payload.logoUrl.trim()
            : null;
        const coverPhotoUrl =
          payload &&
          typeof payload === "object" &&
          typeof payload.coverPhotoUrl === "string" &&
          payload.coverPhotoUrl.trim()
            ? payload.coverPhotoUrl.trim()
            : null;
        setValue({ slug, displayName, logoUrl, coverPhotoUrl, loading: false });
      })
      .catch(() => {
        if (active) {
          setValue((prev) => ({ ...prev, loading: false }));
        }
      });
    return () => {
      active = false;
    };
  }, []);

  return (
    <ProviderWorkspaceContext.Provider value={value}>{children}</ProviderWorkspaceContext.Provider>
  );
};

import { message } from "antd";
import { useCallback, useMemo, useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { getApiErrorMessage } from "@/utils/errors";

export const useCrudPage = ({ service, mapListResponse, query, messages }) => {
  const qc = useQueryClient();
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isDeleteOpen, setIsDeleteOpen] = useState(false);
  const [selectedRecord, setSelectedRecord] = useState(null);
  const [submitting, setSubmitting] = useState(false);
  const serializedQuery = useMemo(() => JSON.stringify(query ?? {}), [query]);
  const queryKey = useMemo(
    () => ["admin", "crud", service.cacheKey ?? "unknown", serializedQuery],
    [serializedQuery, service.cacheKey],
  );

  const listQuery = useQuery({
    queryKey,
    queryFn: async () => {
      try {
        const response = await service.list(query);
        const collection = mapListResponse(response);
        return {
          items: collection.items,
          total: collection.total ?? collection.items.length,
        };
      } catch (error) {
        message.error(messages.loadError);
        throw error;
      }
    },
    staleTime: 2 * 60 * 1000,
    gcTime: 10 * 60 * 1000,
    refetchOnWindowFocus: false,
    retry: 0,
  });

  const refresh = useCallback(async () => {
    await qc.invalidateQueries({ queryKey });
  }, [qc, queryKey]);

  const openCreate = useCallback(() => {
    setSelectedRecord(null);
    setIsFormOpen(true);
  }, []);

  const openEdit = useCallback((record) => {
    setSelectedRecord(record);
    setIsFormOpen(true);
  }, []);

  const openDelete = useCallback((record) => {
    setSelectedRecord(record);
    setIsDeleteOpen(true);
  }, []);

  const closeForm = useCallback(() => {
    setIsFormOpen(false);
    setSelectedRecord(null);
  }, []);

  const closeDelete = useCallback(() => {
    setIsDeleteOpen(false);
    setSelectedRecord(null);
  }, []);

  const submit = useCallback(
    async (values) => {
      setSubmitting(true);
      try {
        if (selectedRecord) {
          await service.update(selectedRecord.id, values);
          message.success(messages.updatedSuccess);
        } else if (service.create) {
          await service.create(values);
          message.success(messages.createdSuccess);
        } else {
          throw new Error("Create operation is not available for this page.");
        }

        closeForm();
        await refresh();
      } catch (error) {
        message.error(getApiErrorMessage(error, messages.saveError));
      } finally {
        setSubmitting(false);
      }
    },
    [closeForm, messages.createdSuccess, messages.saveError, messages.updatedSuccess, refresh, selectedRecord, service],
  );

  const confirmDelete = useCallback(async () => {
    if (!selectedRecord) {
      return;
    }

    setSubmitting(true);
    try {
      await service.remove(selectedRecord.id);
      message.success(messages.deletedSuccess);
      closeDelete();
      await refresh();
    } catch (error) {
      message.error(getApiErrorMessage(error, messages.deleteError));
    } finally {
      setSubmitting(false);
    }
  }, [closeDelete, messages.deleteError, messages.deletedSuccess, refresh, selectedRecord, service]);

  return useMemo(
    () => ({
      closeDelete,
      closeForm,
      confirmDelete,
      isDeleteOpen,
      isFormOpen,
      loading: listQuery.isLoading,
      openCreate,
      openDelete,
      openEdit,
      records: listQuery.data?.items ?? [],
      refresh,
      selectedRecord,
      submit,
      submitting,
      total: listQuery.data?.total ?? 0,
    }),
    [
      closeDelete,
      closeForm,
      confirmDelete,
      isDeleteOpen,
      isFormOpen,
      listQuery.data,
      listQuery.isFetching,
      listQuery.isLoading,
      openCreate,
      openDelete,
      openEdit,
      refresh,
      selectedRecord,
      submit,
    ],
  );
};

/**
 * useSavedPlans Hook
 * Handles saved trip plans CRUD operations
 */

import { useState, useCallback, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';

import { extractTripPlans } from '@/utils/trips/dataNormalizers';
import { getApiErrorStatus } from '@/utils/errors';
import { fetchSavedTripPlans, deleteTripPlan } from '@/api/trips';
import { useAuth } from '@/context/AuthContext';











export const useSavedPlans = () => {
  const navigate = useNavigate();
  const { isAuthenticated } = useAuth();
  const [savedPlans, setSavedPlans] = useState([]);
  const [loadingPlans, setLoadingPlans] = useState(false);
  const [planToDelete, setPlanToDelete] = useState(null);

  // Load saved plans when authenticated
  useEffect(() => {
    if (isAuthenticated) {
      void loadSavedPlans();
    } else {
      setSavedPlans([]);
    }
  }, [isAuthenticated]);

  const loadSavedPlans = useCallback(async () => {
    try {
      setLoadingPlans(true);
      const payload = await fetchSavedTripPlans();
      const plans = extractTripPlans(payload);
      setSavedPlans(plans);
    } catch (error) {
      if (getApiErrorStatus(error) !== 401) {
        toast.error('Failed to load saved plans');
      }
    } finally {
      setLoadingPlans(false);
    }
  }, []);

  const removePlan = useCallback((planId) => {
    setPlanToDelete(planId);
  }, []);

  const confirmDeletePlan = useCallback(async () => {
    if (!planToDelete) return;

    try {
      setLoadingPlans(true);
      await deleteTripPlan(planToDelete);
      setSavedPlans((current) => current.filter((plan) => plan.id !== planToDelete));
      toast.success('Plan deleted');
    } catch (error) {
      if (getApiErrorStatus(error) === 401) {
        navigate('/login');
      } else {
        toast.error('Failed to delete plan');
      }
    } finally {
      setLoadingPlans(false);
      setPlanToDelete(null);
    }
  }, [planToDelete, navigate]);

  const cancelDeletePlan = useCallback(() => {
    setPlanToDelete(null);
  }, []);

  return {
    savedPlans,
    loadingPlans,
    planToDelete,
    loadSavedPlans,
    removePlan,
    confirmDeletePlan,
    cancelDeletePlan
  };
};

/**
 * useTripForm Hook
 * Handles form state, validation, and persistence
 */

import { useState, useCallback, useEffect } from 'react';
import { useAuth } from '@/context/AuthContext';

import { toast } from 'react-toastify';

import { validateTripForm, sanitizeTripData, isBudgetTooLow } from '@/utils/trips/validation/tripValidation';
import { saveTripForm, loadTripForm } from '@/utils/trips/storage';
import { setFormDraft, getFormDraft, clearFormDraft } from '@/utils/trips/inMemoryDraft';

const DEFAULT_FORM_DATA = {
  budget: 1000,
  cityId: '',
  days: 3,
  interests: [],
  persons: 2
};
















export const useTripForm = () => {
  const { isAuthenticated } = useAuth();
  const [formData, setFormDataState] = useState(DEFAULT_FORM_DATA);

  // Load saved form data on mount (localStorage for authenticated users,
  // in-memory draft for guests)
  useEffect(() => {
    const savedForm = isAuthenticated ? loadTripForm() : getFormDraft();
    if (savedForm) {
      setFormDataState((current) => ({
        ...current,
        ...savedForm,
        interests: savedForm.interests ?? current.interests ?? []
      }));
      if (!isAuthenticated) {
        clearFormDraft();
      }
    }
  }, [isAuthenticated]);

  // Persist form data on change: authenticated => localStorage, guest => in-memory
  useEffect(() => {
    if (isAuthenticated) {
      saveTripForm(formData);
    } else {
      setFormDraft(formData);
    }
  }, [formData, isAuthenticated]);

  // Validation
  const { errors, isValid } = validateTripForm(formData);
  const minimumBudget = formData.persons * formData.days * 100;
  const budgetTooLow = isBudgetTooLow(formData.budget, formData.persons, formData.days);

  // Handlers
  const updateCity = useCallback((value) => {
    setFormDataState((current) => ({ ...current, cityId: value }));
  }, []);

  const updateDays = useCallback((event) => {
    const value = Math.max(1, Math.min(14, Number(event.target.value || 1)));
    setFormDataState((current) => ({ ...current, days: value }));
  }, []);

  const updateBudget = useCallback((event) => {
    const value = Math.max(0, Number(event.target.value || 0));
    setFormDataState((current) => ({ ...current, budget: value }));
  }, []);

  const updatePersons = useCallback((event) => {
    const value = Math.max(1, Math.min(20, Number(event.target.value || 1)));
    setFormDataState((current) => ({ ...current, persons: value }));
  }, []);

  const toggleInterest = useCallback((tagName) => {
    setFormDataState((current) => {
      const interests = current.interests ?? [];
      return {
        ...current,
        interests: interests.includes(tagName) ?
        interests.filter((i) => i !== tagName) :
        [...interests, tagName]
      };
    });
  }, []);

  const resetForm = useCallback(() => {
    setFormDataState(DEFAULT_FORM_DATA);
    toast.info('Form reset');
  }, []);

  const setFormData = useCallback((data) => {
    setFormDataState((current) => ({
      ...current,
      ...sanitizeTripData(data)
    }));
  }, []);

  return {
    formData,
    errors,
    isValid,
    budgetTooLow,
    minimumBudget,
    updateCity,
    updateDays,
    updateBudget,
    updatePersons,
    toggleInterest,
    resetForm,
    setFormData
  };
};

/**
 * useTripPlanner - Main composable hook
 * Orchestrates all trip planner functionality
 */

import { useState, useCallback, useEffect, useMemo, useRef } from 'react';

import { useSearchParams } from 'react-router-dom';
import { toast } from 'react-toastify';


import { useAuth } from '@/context/AuthContext';
import { useTripForm } from './useTripForm';
import { useTripResults } from './useTripResults';
import { useTripSharing } from './useTripSharing';
import { useSavedPlans } from './useSavedPlans';
import {
  fetchAllCities,
  fetchAllCountries,
  fetchCitiesByCountry,
  fetchCityById,
  fetchTags } from
'@/api/catalog';
import { extractCities, extractCountries, extractTags } from '@/utils/trips/dataNormalizers';
import { getRemixDraft, clearRemixDraft } from '@/utils/trips/inMemoryDraft';
import { formatDate } from '@/utils/trips/formatters';






























































export const useTripPlanner = () => {
  const { isAuthenticated } = useAuth();
  const [searchParams] = useSearchParams();
  const appliedCityFromUrlRef = useRef(null);

  // Initialize individual hooks
  const {
    formData,
    errors,
    isValid,
    budgetTooLow,
    minimumBudget,
    updateCity,
    updateDays,
    updateBudget,
    updatePersons,
    toggleInterest,
    setFormData
  } = useTripForm();
  const resultsHook = useTripResults();
  const sharingHook = useTripSharing(resultsHook.tripPlan, resultsHook.setTripPlan, formData);
  const savedPlansHook = useSavedPlans();

  // Location data state
  const [countries, setCountries] = useState([]);
  const [cities, setCities] = useState([]);
  const [tags, setTags] = useState([]);
  const [selectedCountryId, setSelectedCountryId] = useState(null);
  const [loadingCountries, setLoadingCountries] = useState(false);
  const [loadingCities, setLoadingCities] = useState(false);

  // City lookup for label formatting
  const cityLookup = useMemo(() => {
    const map = new Map();
    cities.forEach((city) => map.set(city.id, city));
    return map;
  }, [cities]);

  // Load initial data
  useEffect(() => {
    void loadInitialData();

    // Check for remix draft (in-memory for guest flows)
    const remixDraft = getRemixDraft();
    if (remixDraft) {
      setFormData(remixDraft);
      clearRemixDraft();
      toast.info('Shared trip loaded into the planner');
    }
  }, [setFormData]);

  const loadInitialData = async () => {
    await Promise.all([loadCountries(), loadCities(), loadTags()]);
  };

  const loadCountries = async () => {
    try {
      setLoadingCountries(true);
      const data = await fetchAllCountries();
      setCountries(extractCountries(data));
    } catch {
      toast.error('Failed to load countries');
    } finally {
      setLoadingCountries(false);
    }
  };

  const loadCities = async () => {
    try {
      setLoadingCities(true);
      const data = await fetchAllCities();
      setCities(extractCities(data));
    } catch {
      toast.error('Failed to load cities');
    } finally {
      setLoadingCities(false);
    }
  };

  const loadTags = async () => {
    try {
      const data = await fetchTags();
      setTags(extractTags(data));
    } catch {
      toast.error('Failed to load interests');
    }
  };

  const onCountryChange = useCallback(async (countryId) => {
    setSelectedCountryId(countryId);
    updateCity(''); // Reset city selection
    setCities([]);

    if (countryId) {
      try {
        setLoadingCities(true);
        const data = await fetchCitiesByCountry(countryId);
        setCities(extractCities(data));
      } catch {
        toast.error('Failed to load cities');
      } finally {
        setLoadingCities(false);
      }
    }
  }, [updateCity]);

  useEffect(() => {
    const cityParam = searchParams.get('cityId')?.trim() ?? '';
    if (!cityParam) {
      appliedCityFromUrlRef.current = null;
      return;
    }
    if (countries.length === 0) {
      return;
    }
    if (appliedCityFromUrlRef.current === cityParam) {
      return;
    }

    let cancelled = false;
    void (async () => {
      try {
        const city = await fetchCityById(cityParam);
        if (cancelled || !city) {
          return;
        }
        const countryId = city.countryId ?? city.country?.id;
        if (!countryId) {
          return;
        }
        setSelectedCountryId(countryId);
        setLoadingCities(true);
        try {
          const data = await fetchCitiesByCountry(countryId);
          if (cancelled) {
            return;
          }
          setCities(extractCities(data));
        } catch {
          if (!cancelled) {
            toast.error('Failed to load cities');
          }
        } finally {
          if (!cancelled) {
            setLoadingCities(false);
          }
        }
        if (cancelled) {
          return;
        }
        updateCity(cityParam);
        appliedCityFromUrlRef.current = cityParam;
      } catch {

        // ignore invalid city id
      }})();

    return () => {
      cancelled = true;
    };
  }, [searchParams, countries.length, updateCity]);

  const formatCityLabel = useCallback((cityId) => {
    const city = cityLookup.get(cityId);
    if (!city) return cityId;
    return city.stateName ? `${city.name} (${city.stateName})` : city.name;
  }, [cityLookup]);

  const onSubmit = useCallback((event) => {
    event.preventDefault();
    void resultsHook.submitTrip(formData);
  }, [formData, resultsHook]);

  // Combine all return values
  return {
    // Form state
    formData,
    errors,
    isValid,
    budgetTooLow,
    minimumBudget,

    // Location data
    countries,
    cities,
    tags,
    selectedCountryId,
    loadingCountries,
    loadingCities,

    // Results state
    tripPlan: resultsHook.tripPlan,
    generating: resultsHook.generating,
    resultsRef: resultsHook.resultsRef,

    // Sharing state
    publishing: sharingHook.publishing,
    hasShareLink: sharingHook.hasShareLink,
    publicShareUrl: sharingHook.publicShareUrl,

    // Saved plans state
    savedPlans: savedPlansHook.savedPlans,
    loadingPlans: savedPlansHook.loadingPlans,
    planToDelete: savedPlansHook.planToDelete,

    // Auth state
    isAuthenticated,

    // Formatters
    formatCityLabel,
    formatDate,

    // Form handlers
    updateCity,
    updateDays,
    updateBudget,
    updatePersons,
    toggleInterest,
    onCountryChange,
    onSubmit,

    // Results handlers
    clearPlan: resultsHook.clearPlan,
    publishPlan: sharingHook.publishPlan,
    copyShareLink: sharingHook.copyShareLink,
    addToWishlist: resultsHook.addToWishlist,
    viewPlace: resultsHook.viewPlace,

    // Saved plans handlers
    loadPlan: resultsHook.loadSavedPlan,
    removePlan: savedPlansHook.removePlan,
    confirmDeletePlan: savedPlansHook.confirmDeletePlan,
    cancelDeletePlan: savedPlansHook.cancelDeletePlan
  };
};

/**
 * useTripSharing Hook
 * Handles trip plan sharing functionality
 */

import { useState, useCallback, useMemo } from 'react';
import { toast } from 'react-toastify';

import { getApiErrorMessage } from '@/utils/errors';
import { copyTextToClipboard } from '@/utils/clipboard';
import { publishTripPlan } from '@/api/trips';










const toLocalTripUrl = (rawUrl, shareSlug) => {
  if (typeof window === 'undefined') {
    return null;
  }
  if (shareSlug) {
    return `${window.location.origin}/trip/${shareSlug}`;
  }
  if (!rawUrl) {
    return null;
  }
  try {
    const parsed = new URL(rawUrl);
    return `${window.location.origin}${parsed.pathname}${parsed.search}${parsed.hash}`;
  } catch {
    return null;
  }
};

export const useTripSharing = (
tripPlan,
setTripPlan,
formData) =>
{
  const [publishing, setPublishing] = useState(false);

  const hasShareLink = useMemo(
    () => Boolean(tripPlan?.isPublic && (tripPlan.shareUrl || tripPlan.shareSlug)),
    [tripPlan?.isPublic, tripPlan?.shareUrl, tripPlan?.shareSlug]
  );

  const getShareUrl = useCallback((shareSlug) => {
    if (!shareSlug || typeof window === 'undefined') {
      return null;
    }
    return `${window.location.origin}/trip/${shareSlug}`;
  }, []);

  const publicShareUrl = useMemo(
    () =>
    hasShareLink ?
    toLocalTripUrl(tripPlan?.shareUrl, tripPlan?.shareSlug) ?? '' :
    '',
    [hasShareLink, tripPlan?.shareUrl, tripPlan?.shareSlug]
  );

  const publishPlan = useCallback(async () => {
    if (!tripPlan) {
      toast.error('Generate a trip first');
      return;
    }

    try {
      setPublishing(true);

      // Generate title and description
      const cityLabel = formData.cityId || 'Trip Destination';
      const title = tripPlan.title ?? `${cityLabel} in ${formData.days} days`;
      const description =
      tripPlan.description ??
      `A ${formData.days}-day itinerary for ${formData.persons} traveler(s)${formData.interests?.length ? ` focused on ${formData.interests.join(', ')}` : ''}.`;

      // Call API to publish
      const response = await publishTripPlan(tripPlan.tripPlanId, {
        description,
        isPublic: true,
        title
      });

      // Get share URL
      const shareUrl = toLocalTripUrl(response.shareUrl, response.shareSlug);
      if (!shareUrl) {
        throw new Error('Share link missing');
      }

      // Update trip plan with sharing info
      const nextTripPlan = {
        ...tripPlan,
        description,
        isPublic: response.isPublic,
        shareSlug: response.shareSlug,
        shareUrl,
        title
      };

      setTripPlan(nextTripPlan);
      await copyTextToClipboard(shareUrl);
      toast.success('Public link copied to clipboard!');
    } catch (error) {
      toast.error(getApiErrorMessage(error, 'Failed to publish trip'));
    } finally {
      setPublishing(false);
    }
  }, [tripPlan, formData, setTripPlan, getShareUrl]);

  const copyShareLink = useCallback(async () => {
    const shareUrl = tripPlan?.isPublic ?
    toLocalTripUrl(tripPlan.shareUrl, tripPlan.shareSlug) :
    null;

    if (!shareUrl) {
      // No share link yet, trigger publish
      await publishPlan();
      return;
    }

    try {
      await copyTextToClipboard(shareUrl);
      toast.success('Link copied to clipboard!');
    } catch {
      toast.error('Failed to copy link');
    }
  }, [tripPlan, getShareUrl, publishPlan]);

  return {
    publishing,
    hasShareLink,
    publicShareUrl,
    publishPlan,
    copyShareLink,
    getShareUrl
  };
};

