    title: t("admin.places.name"),
    dataIndex: "name",
    key: "name"
  },
  {
    title: "State",
    dataIndex: "stateName",
    key: "stateName"
  },
  {
    title: "Population",
    dataIndex: "population",
    key: "population"
  },
  {
    title: t("admin.places.latitude"),
