import { useEffect, useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { useAuth } from "@/context/AuthContext";
import { fetchProviderProfile, getCachedProviderProfile } from "@/api/provider";
import { getDefaultDashboardPath, resolvePersonalPathFromRedirect } from "@/utils/routing";
import { setProviderModeChosen } from "@/utils/providerModeStorage";
import { setActiveWorkspace } from "@/utils/activeWorkspaceStorage";
import { getResolvedAvatarUrl, handleAvatarImageError } from "@/utils/avatar";
import { resolveMediaUrl } from "@/utils/mediaUrl";
import "@/pages/auth/login/Login.css";
import "./ChooseAccountMode.css";

const ChooseAccountMode = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const location = useLocation();
  const { user } = useAuth();
  const redirectTo = location.state?.redirectTo;
  const personalPath = resolvePersonalPathFromRedirect(redirectTo);

  const [providerVisual, setProviderVisual] = useState(
    /** @type {{ logoUrl: string | null; coverPhotoUrl: string | null; displayName: string } | null} */ (
      () => getCachedProviderProfile()
    ),
  );
  const [providerImageFailed, setProviderImageFailed] = useState(false);

  useEffect(() => {
    let active = true;
    void fetchProviderProfile()
      .then((payload) => {
        if (!active || !payload || typeof payload !== "object") {
          return;
        }
        setProviderVisual(payload);
      })
      .catch(() => {
        if (active) {
          setProviderVisual({ logoUrl: null, coverPhotoUrl: null, displayName: "" });
        }
      });
    return () => {
      active = false;
    };
  }, []);

  const firstName = user?.firstName?.trim();
  const username = user?.username?.trim();
  const personalLabel = firstName || username || "";
  const providerImageSource = providerVisual?.logoUrl || providerVisual?.coverPhotoUrl;
  const providerImageSrc = providerImageSource ? resolveMediaUrl(providerImageSource) : null;
  const personalAvatarSrc = getResolvedAvatarUrl(user);
  const personalLetter = (firstName?.[0] || username?.[0] || "?").toUpperCase();

  useEffect(() => {
    setProviderImageFailed(false);
  }, [providerImageSrc]);

  const commitChoiceAndNavigate = (path, workspace) => {
    if (user?.id) {
      setProviderModeChosen(user.id);
      setActiveWorkspace(user.id, workspace);
    }
    navigate(path);
  };

  return (
    <div className="choose-account-page container-center">
      <div className="choose-account-card login-card">
        <div className="login-header">
          <h1>{t("login.chooseAccountTitle")}</h1>
          <p>{t("login.chooseAccountSubtitle")}</p>
        </div>

        <div className="choose-account-actions">
          <button
            type="button"
            className="choose-account-option choose-account-option--personal"
            onClick={() => commitChoiceAndNavigate(personalPath, "personal")}>
            <div className="choose-account-option__row">
              <div className="choose-account-option__media">
                {personalAvatarSrc ? (
                  <img
                    src={personalAvatarSrc}
                    alt={personalLabel || t("login.choosePersonal")}
                    className="choose-account-option__avatar choose-account-option__avatar--circle"
                    onError={handleAvatarImageError}
                  />
                ) : (
                  <span
                    className="choose-account-option__avatar choose-account-option__avatar--circle choose-account-option__avatar--fallback choose-account-option__avatar--personal"
                    aria-hidden>
                    {personalLetter}
                  </span>
                )}
              </div>
              <div className="choose-account-option__body">
                <span className="choose-account-option__title">{t("login.choosePersonal")}</span>
                {personalLabel ? (
                  <span className="choose-account-option__name">{personalLabel}</span>
                ) : null}
                <span className="choose-account-option__hint">{t("login.choosePersonalHint")}</span>
              </div>
            </div>
          </button>

          <button
            type="button"
            className="choose-account-option choose-account-option--provider"
            onClick={() =>
              commitChoiceAndNavigate(getDefaultDashboardPath("PROVIDER"), "provider")
            }>
            <div className="choose-account-option__row">
              <div className="choose-account-option__media">
                {providerImageSrc && !providerImageFailed ? (
                  <img
                    src={providerImageSrc}
                    alt={providerVisual?.displayName || t("login.chooseProvider")}
                    onError={() => setProviderImageFailed(true)}
                    className={
                      providerVisual?.logoUrl
                        ? "choose-account-option__avatar choose-account-option__avatar--brand"
                        : "choose-account-option__avatar choose-account-option__avatar--brand choose-account-option__avatar--cover"
                    }
                  />
                ) : providerVisual === null ? (
                  <span
                    className="choose-account-option__avatar choose-account-option__avatar--brand choose-account-option__avatar--skeleton"
                    aria-hidden
                  />
                ) : (
                  <img
                    src="/images/waynest icon.svg"
                    alt=""
                    className="choose-account-option__avatar choose-account-option__avatar--brand choose-account-option__avatar--fallbackImage"
                  />
                )}
              </div>
              <div className="choose-account-option__body">
                <span className="choose-account-option__title">{t("login.chooseProvider")}</span>
                {providerVisual?.displayName ? (
                  <span className="choose-account-option__name">{providerVisual.displayName}</span>
                ) : null}
                <span className="choose-account-option__hint">{t("login.chooseProviderHint")}</span>
              </div>
            </div>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ChooseAccountMode;

import { Link, useNavigate } from "react-router-dom";
import { useInviteActivation } from "@/hooks/public/useInviteActivation";
import "./InvitePage.css";

const InvitePage = () => {
  const navigate = useNavigate();
  const { message, status } = useInviteActivation();

  return (
    <div className="invite-page container-center">
      <div className="invite-card">
        {status === "loading" &&
        <>
            <div className="invite-spinner" />
            <p className="invite-message">Activating your device...</p>
          </>
        }

        {status === "success" &&
        <>
            <div className="invite-icon invite-icon--success">✓</div>
            <h1 className="invite-title">Device Activated</h1>
            <p className="invite-message">{message}</p>
            <button className="invite-btn" onClick={() => navigate("/login")}>
              Go to Login
            </button>
          </>
        }

        {status === "error" &&
        <>
            <div className="invite-icon invite-icon--error">✕</div>
            <h1 className="invite-title">Link Invalid</h1>
            <p className="invite-message">{message}</p>
            <Link to="/" className="invite-btn invite-btn--secondary">
              Go to Home
            </Link>
          </>
        }
      </div>
    </div>);

};

export default InvitePage;

import { AiOutlineEye, AiOutlineEyeInvisible } from "react-icons/ai";
import { Link } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { useLoginForm } from "@/hooks/public/useLoginForm";
import "./Login.css";

const Login = () => {
  const { t } = useTranslation();
  const {
    errorMessage,
    formData,
    loading,
    setShowPassword,
    showPassword,
    submit,
    updateField
  } = useLoginForm();

  return (
    <div className="login-page container-center">
      <div className="login-card">
        <div className="login-header">
          <h1>{t("login.welcomeBack")}</h1>
          <p>{t("login.signIn")}</p>
        </div>

        <form
          className="login-form"
          onSubmit={(event) => {
            event.preventDefault();
            void submit();
          }}>
          <div className="input-group">
            <label>{t("login.emailOrUsername")}</label>
            <input
              type="text"
              placeholder={t("login.enterEmailOrUsername")}
              value={formData.identifier}
              onChange={(event) => updateField("identifier", event.target.value)}
              required />
            
          </div>

          <div className="input-group">
            <label>{t("login.password")}</label>
            <div className="password-input-wrapper">
              <input
                type={showPassword ? "text" : "password"}
                placeholder={t("login.enterPassword")}
                value={formData.password}
                onChange={(event) => updateField("password", event.target.value)}
                required />
              
              <button
                type="button"
                className="password-toggle"
                onClick={(event) => {
                  event.preventDefault();
                  event.stopPropagation();
                  setShowPassword(!showPassword);
                }}
                onMouseDown={(event) => {
                  event.preventDefault();
                }}
                aria-label={
                showPassword ? t("login.hidePassword") : t("login.showPassword")
                }
                tabIndex={-1}>
                {showPassword ? <AiOutlineEyeInvisible /> : <AiOutlineEye />}
              </button>
            </div>
          </div>

          {errorMessage && <div className="login-error">{errorMessage}</div>}

          <div className="login-forgot">
            <Link to="/forgot-password">{t("login.forgotPassword", "Forgot password?")}</Link>
          </div>

          <button type="submit" className="login-button" disabled={loading}>
            {loading ? t("login.loggingIn") : t("login.loginButton")}
          </button>

          <p className="login-register-link">
            {t("login.noAccount", "Don't have an account?")}{" "}
            <Link to="/register">{t("login.registerLink", "Sign up")}</Link>
          </p>
        </form>
      </div>
    </div>);

};

export default Login;

import { Link, useLocation } from "react-router-dom";
import { AiOutlineEye, AiOutlineEyeInvisible } from "react-icons/ai";
import { useTranslation } from "react-i18next";
import { useRegisterForm } from "@/hooks/public/useRegisterForm";
import "./Register.css";

const Register = () => {
  const location = useLocation();
  const { t } = useTranslation();
  const {
    errorMessage,
    formData,
    loading,
    setShowConfirmPassword,
    setShowPassword,
    showConfirmPassword,
    showPassword,
    submit,
    updateField
  } = useRegisterForm();

  return (
    <div className="register-page container-center">
      <div className="register-card">
        <div className="register-header">
          <h1>{t("register.title")}</h1>
          <p>{t("register.subtitle")}</p>
        </div>

        <form
          className="register-form"
          onSubmit={(event) => {
            event.preventDefault();
            void submit();
          }}>
          <div className="input-group">
            <label>{t("register.firstName")}</label>
            <input
              type="text"
              name="firstName"
              placeholder={t("register.firstNamePlaceholder")}
              value={formData.firstName}
              onChange={(event) => updateField("firstName", event.target.value)}
              required />
            
          </div>

          <div className="input-group">
            <label>{t("register.lastName")}</label>
            <input
              type="text"
              name="lastName"
              placeholder={t("register.lastNamePlaceholder")}
              value={formData.lastName}
              onChange={(event) => updateField("lastName", event.target.value)}
              required />
            
          </div>

          <div className="input-group">
            <label>{t("register.email")}</label>
            <input
              type="email"
              name="email"
              placeholder={t("register.emailPlaceholder")}
              value={formData.email}
              onChange={(event) => updateField("email", event.target.value)}
              required />
            
          </div>

          <div className="input-group">
            <label>{t("register.username")}</label>
            <input
              type="text"
              name="username"
              placeholder={t("register.usernamePlaceholder")}
              value={formData.username}
              onChange={(event) => updateField("username", event.target.value)}
              required />
            
          </div>

          <div className="input-group">
            <label>{t("register.password")}</label>
            <div className="password-input-wrapper">
              <input
                type={showPassword ? "text" : "password"}
                name="password"
                placeholder={t("register.passwordPlaceholder")}
                value={formData.password}
                onChange={(event) => updateField("password", event.target.value)}
                required
                minLength={8} />
              
              <button
                type="button"
                className="password-toggle"
                onClick={(event) => {
                  event.preventDefault();
                  event.stopPropagation();
                  setShowPassword(!showPassword);
                }}
                onMouseDown={(event) => {
                  event.preventDefault();
                }}
                aria-label={
                showPassword ?
                t("register.hidePassword") :
                t("register.showPassword")
                }
                tabIndex={-1}>
                {showPassword ? <AiOutlineEyeInvisible /> : <AiOutlineEye />}
              </button>
            </div>
          </div>

          <div className="input-group">
            <label>{t("register.confirmPassword")}</label>
            <div className="password-input-wrapper">
              <input
                type={showConfirmPassword ? "text" : "password"}
                name="confirmPassword"
                placeholder={t("register.confirmPasswordPlaceholder")}
                value={formData.confirmPassword}
                onChange={(event) =>
                updateField("confirmPassword", event.target.value)
                }
                required
                minLength={8} />
              
              <button
                type="button"
                className="password-toggle"
                onClick={(event) => {
                  event.preventDefault();
                  event.stopPropagation();
                  setShowConfirmPassword(!showConfirmPassword);
                }}
                onMouseDown={(event) => {
                  event.preventDefault();
                }}
                aria-label={
                showConfirmPassword ?
                t("register.hidePassword") :
                t("register.showPassword")
                }
                tabIndex={-1}>
                {showConfirmPassword ?
                <AiOutlineEyeInvisible /> :

                <AiOutlineEye />
                }
              </button>
            </div>
          </div>

          {formData.password && (() => {
            const p = formData.password;
            const score = [p.length >= 8, /[A-Z]/.test(p), /[0-9]/.test(p), /[^A-Za-z0-9]/.test(p)].filter(Boolean).length;
            const labels = ["", t("register.strengthWeak", "Weak"), t("register.strengthFair", "Fair"), t("register.strengthGood", "Good"), t("register.strengthStrong", "Strong")];
            const colors = [
              "",
              "var(--color-danger)",
              "var(--color-warning)",
              "var(--color-rating)",
              "var(--color-success)",
            ];
            return (
              <div className="register-strength">
                <div className="register-strength-bars">
                  {[1, 2, 3, 4].map((i) => (
                    <div
                      key={i}
                      className="register-strength-bar"
                      style={{ background: i <= score ? colors[score] : "var(--panel-border)" }}
                    />
                  ))}
                </div>
                <span className="register-strength-label" style={{ color: colors[score] }}>
                  {labels[score]}
                </span>
              </div>
            );
          })()}

          {errorMessage && <div className="register-error">{errorMessage}</div>}

          <button type="submit" className="register-button" disabled={loading}>
            {loading ? t("register.creatingAccount") : t("register.signUp")}
          </button>

          <div className="register-footer">
            <p>
              {t("register.alreadyHaveAccount")}{" "}
              <Link to="/login" state={location.state} className="register-link">
                {t("register.signIn")}
              </Link>
            </p>
          </div>
        </form>
      </div>
    </div>);

};

export default Register;

import { useState } from "react";
import { useTranslation } from "react-i18next";
import { FaTwitter, FaFacebook, FaInstagram, FaLinkedin } from "react-icons/fa";
import "./Contact.css";

const Contact = () => {
  const { t } = useTranslation();
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    subject: "",
    message: ""
  });
  const [loading, setLoading] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const handleChange = (
  e) =>
  {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    // Simulate form submission
    setTimeout(() => {
      setLoading(false);
      setSubmitted(true);
      setFormData({
        name: "",
        email: "",
        subject: "",
        message: ""
      });
    }, 1000);
  };

  return (
    <div className="contact-page">
      <section className="contact-hero">
        <h1>{t("contact.hero.title")}</h1>
        <p className="hero-subtitle">
          {t("contact.hero.subtitle")}
        </p>
      </section>

      <div className="contact-content">
        <div className="contact-info">
          <div className="info-section">
            <h2>{t("contact.contactInformation.title")}</h2>
            <div className="info-item">
              <h3>{t("contact.contactInformation.email")}</h3>
              <p>{t("contact.contactInformation.emailValue")}</p>
            </div>
            <div className="info-item">
              <h3>{t("contact.contactInformation.responseTime")}</h3>
              <p>{t("contact.contactInformation.responseTimeValue")}</p>
            </div>
            <div className="info-item">
              <h3>{t("contact.contactInformation.officeHours")}</h3>
              <p>{t("contact.contactInformation.officeHoursValue")}</p>
            </div>
          </div>

          <div className="info-section">
            <h2>{t("contact.followUs.title")}</h2>
            <div className="social-links">
              <a href="#" className="social-link">
                <FaTwitter className="social-icon" />
                <span>{t("contact.followUs.twitter")}</span>
              </a>
              <a href="#" className="social-link">
                <FaFacebook className="social-icon" />
                <span>{t("contact.followUs.facebook")}</span>
              </a>
              <a href="#" className="social-link">
                <FaInstagram className="social-icon" />
                <span>{t("contact.followUs.instagram")}</span>
              </a>
              <a href="#" className="social-link">
                <FaLinkedin className="social-icon" />
                <span>{t("contact.followUs.linkedin")}</span>
              </a>
            </div>
          </div>
        </div>

        <div className="contact-form-container">
          <h2>{t("contact.form.title")}</h2>
          {submitted ?
          <div className="success-message">
              <h3>{t("contact.success.title")}</h3>
              <p>{t("contact.success.message")}</p>
              <button
              className="btn-secondary"
              onClick={() => setSubmitted(false)}>
              
                {t("contact.success.sendAnother")}
              </button>
            </div> :

          <form className="contact-form" onSubmit={handleSubmit}>
              <div className="form-group">
                <label htmlFor="name">
                  {t("contact.form.name")} {t("contact.form.required")}
                </label>
                <input
                type="text"
                id="name"
                name="name"
                value={formData.name}
                onChange={handleChange}
                required
                placeholder={t("contact.form.namePlaceholder")} />
              
              </div>

              <div className="form-group">
                <label htmlFor="email">
                  {t("contact.form.email")} {t("contact.form.required")}
                </label>
                <input
                type="email"
                id="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                required
                placeholder={t("contact.form.emailPlaceholder")} />
              
              </div>

              <div className="form-group">
                <label htmlFor="subject">
                  {t("contact.form.subject")} {t("contact.form.required")}
                </label>
                <select
                id="subject"
                name="subject"
                value={formData.subject}
                onChange={handleChange}
                required>
                
                  <option value="">{t("contact.form.subjectPlaceholder")}</option>
                  <option value="general">{t("contact.form.subjectOptions.general")}</option>
                  <option value="support">{t("contact.form.subjectOptions.support")}</option>
                  <option value="feedback">{t("contact.form.subjectOptions.feedback")}</option>
                  <option value="partnership">{t("contact.form.subjectOptions.partnership")}</option>
                  <option value="other">{t("contact.form.subjectOptions.other")}</option>
                </select>
              </div>

              <div className="form-group">
                <label htmlFor="message">
                  {t("contact.form.message")} {t("contact.form.required")}
                </label>
                <textarea
                id="message"
                name="message"
                value={formData.message}
                onChange={handleChange}
                required
                rows={6}
                placeholder={t("contact.form.messagePlaceholder")} />
              
              </div>

              <button
              type="submit"
              className="btn-primary"
              disabled={loading}>
              
                {loading ? t("contact.form.sending") : t("contact.form.sendButton")}
              </button>
            </form>
          }
        </div>
      </div>
    </div>);

};

export default Contact;

import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { toast } from "react-toastify";
import { fetchEventById } from "@/api/catalog";
import FeedbackSection from "@/components/public/feedback/FeedbackSection";
import "./EventDetail.css";











const eventImageFallback =
"https://images.unsplash.com/photo-1511578314322-379afb476865?w=1400&q=75&auto=format&fit=crop";

const EventDetail = () => {
  const { id = "" } = useParams();
  const [event, setEvent] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      setLoading(true);
      try {
        const payload = await fetchEventById(id);
        setEvent(payload ?? null);
      } catch {
        toast.error("Failed to load event details");
      } finally {
        setLoading(false);
      }
    };
    if (id) {
      void load();
    }
  }, [id]);

  if (loading) {
    return (
      <div className="event-detail-page">
        <div className="event-detail-shell event-detail-shell--loading">Loading event details...</div>
      </div>);

  }

  if (!event) {
    return (
      <div className="event-detail-page">
        <div className="event-detail-shell event-detail-shell--empty">Event not found.</div>
      </div>);

  }

  return (
    <div className="event-detail-page">
      <article className="event-detail-shell">
        <section className="event-detail-hero">
          <img
            src={event.imageUrl || eventImageFallback}
            alt={event.title}
            className="event-detail-image"
            onError={({ currentTarget }) => {
              currentTarget.onerror = null;
              currentTarget.src = eventImageFallback;
            }} />
          
          <div className="event-detail-overlay">
            <h1>{event.title}</h1>
            <p>{event.description || "No description available yet for this event."}</p>
          </div>
        </section>

        <section className="event-detail-meta-grid">
          <div className="event-detail-meta-card">
            <span className="event-detail-meta-label">Venue</span>
            <strong>{event.venue?.name ?? "-"}</strong>
          </div>
          <div className="event-detail-meta-card">
            <span className="event-detail-meta-label">Start</span>
            <strong>{event.startDate ? new Date(event.startDate).toLocaleString() : "-"}</strong>
          </div>
          <div className="event-detail-meta-card">
            <span className="event-detail-meta-label">End</span>
            <strong>{event.endDate ? new Date(event.endDate).toLocaleString() : "-"}</strong>
          </div>
        </section>

        <FeedbackSection target="event" targetId={event.id} />
      </article>
    </div>);

};

export default EventDetail;

import { useCallback, useEffect, useMemo, useState } from "react";
import { FaCalendarAlt, FaMapMarkerAlt, FaStar } from "react-icons/fa";
import { useTranslation } from "react-i18next";
import { useNavigate, useSearchParams } from "react-router-dom";
import { toast } from "react-toastify";
import { globalSearch } from "@/api/public";
import { getApiErrorMessage } from "@/utils/errors";
import { useExplorePage } from "@/hooks/public/useExplorePage";
import "./Explore.css";

const getFallbackImage = (type) => {
  switch (type) {
    case "RESTAURANT":
      return "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=600&q=75&auto=format&fit=crop";
    case "CAFE":
      return "https://images.unsplash.com/photo-1509042239860-f550ce710b93?w=600&q=75&auto=format&fit=crop";
    case "MUSEUM":
      return "https://images.unsplash.com/photo-1566127992631-137a642a90f4?w=600&q=75&auto=format&fit=crop";
    case "PARK":
      return "https://images.unsplash.com/photo-1501785888041-af3ef285b470?w=600&q=75&auto=format&fit=crop";
    case "HISTORICAL":
      return "https://images.unsplash.com/photo-1600628422019-6c9b5b6f2a4b?w=600&q=75&auto=format&fit=crop";
    case "SHOP":
      return "https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=600&q=75&auto=format&fit=crop";
    default:
      return "https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?w=600&q=75&auto=format&fit=crop";
  }
};

const Explore = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const {
    activeCategory,
    events,
    filteredPlaces,
    loading,
    setActiveCategory
  } = useExplorePage();

  const [searchParams] = useSearchParams();
  const [globalQuery, setGlobalQuery] = useState(() => searchParams.get("q") ?? "");
  const [globalLoading, setGlobalLoading] = useState(false);
  const [globalResults, setGlobalResults] = useState([]);

  const tt = useCallback(
    (key, defaultValue) => t(key, { defaultValue }),
    [t],
  );

  const categories = useMemo(
    () => [
      { key: "all", label: tt("explore.categories.all", "All") },
      { key: "events", label: tt("explore.categories.events", "Events") },
      { key: "RESTAURANT", label: tt("explore.categories.restaurant", "Restaurant") },
      { key: "CAFE", label: tt("explore.categories.cafe", "Cafe") },
      { key: "ATTRACTION", label: tt("explore.categories.attraction", "Attraction") },
      { key: "MUSEUM", label: tt("explore.categories.museum", "Museum") },
      { key: "PARK", label: tt("explore.categories.park", "Park") },
      { key: "HISTORICAL", label: tt("explore.categories.historical", "Historical") },
    ],
    [tt],
  );

  const activeCategoryLabel = useMemo(
    () =>
    categories.find((category) => category.key === activeCategory)?.label ??
    tt("explore.categories.all", "All"),
    [activeCategory, categories, tt]
  );

  useEffect(() => {
    const query = globalQuery.trim();
    if (!query) {
      setGlobalResults([]);
      setGlobalLoading(false);
      return;
    }

    let active = true;
    setGlobalLoading(true);

    const handle = window.setTimeout(async () => {
      try {
        const response = await globalSearch(query, 10);
        if (!active) {
          return;
        }
        const nextItems = Array.isArray(response.items) ? response.items : [];
        setGlobalResults(nextItems.filter((item) => item.type !== "user"));
      } catch (error) {
        if (!active) {
          return;
        }
        toast.error(
          getApiErrorMessage(
            error,
            tt("explore.search.failed", "Search failed")
          )
        );
        setGlobalResults([]);
      } finally {
        if (active) {
          setGlobalLoading(false);
        }
      }
    }, 350);

    return () => {
      active = false;
      window.clearTimeout(handle);
    };
  }, [globalQuery, tt]);

  const providerHits = useMemo(
    () => globalResults.filter((hit) => hit.type === "provider"),
    [globalResults]
  );
  const placeHits = useMemo(
    () => globalResults.filter((hit) => hit.type === "place"),
    [globalResults]
  );
  const eventHits = useMemo(
    () => globalResults.filter((hit) => hit.type === "event"),
    [globalResults]
  );

  return (
    <div className="explore-page">
      <section className="hero-section">
        <div>
          <h1>{tt("explore.hero.title", "Explore places, events, and trusted providers")}</h1>
          <p>
            {tt(
              "explore.hero.description",
              "This page stays focused on discovery. Browse the catalog, search public providers, and open details without the social clutter."
            )}
          </p>
        </div>

        <div className="explore-people-search">
          <h2 className="explore-people-search__title">
            {tt("explore.search.title", "Search the public catalog")}
          </h2>
          <div className="explore-people-search__box">
            <input
              type="search"
              value={globalQuery}
              onChange={(event) => setGlobalQuery(event.target.value)}
              placeholder={tt(
                "explore.search.placeholder",
                "Search providers, places, and events..."
              )}
              className="explore-search-input" />
            
          </div>
        </div>
      </section>

      {globalQuery.trim() ?
      <section className="explore-people-search" aria-live="polite">
          {globalLoading ?
        <p className="explore-search-results__loading">
              {tt("explore.search.loading", "Searching...")}
            </p> :
        null}

          {!globalLoading &&
        providerHits.length === 0 &&
        placeHits.length === 0 &&
        eventHits.length === 0 ?
        <div className="explore-empty-state">
              {tt("explore.search.noResults", "No results")}
            </div> :
        null}

          {providerHits.length > 0 ?
        <div className="explore-search-results__section">
              <h3 className="explore-search-results__section-title">
                {tt("explore.search.providers", "Providers")}
              </h3>
              <div className="explore-people-results">
                {providerHits.map((hit) =>
            <div key={hit.href} className="explore-people-result-row">
                    <div className="explore-people-result-main">
                      <span className="explore-people-avatar explore-people-avatar--accent">
                        {hit.title.trim().charAt(0).toUpperCase()}
                      </span>
                      <div className="explore-people-result-text">
                        <strong className="explore-people-result-name">{hit.title}</strong>
                        {hit.subtitle ?
                  <small className="explore-people-result-sub">{hit.subtitle}</small> :
                  null}
                      </div>
                    </div>
                    <div className="explore-people-result-actions">
                      <button
                  type="button"
                  className="view-details-btn"
                  onClick={() => navigate(hit.href)}>
                        {tt("explore.actions.viewDetails", "View details")}
                      </button>
                    </div>
                  </div>
            )}
              </div>
            </div> :
        null}

          {eventHits.length > 0 ?
        <div className="explore-search-results__section">
              <h3 className="explore-search-results__section-title">
                {tt("explore.search.events", "Events")}
              </h3>
              <div className="grid">
                {eventHits.map((hit) =>
            <div key={hit.href} className="place-card">
                    <div className="place-image">
                      <img
                  src={hit.imageUrl || getFallbackImage("ATTRACTION")}
                  alt={hit.title}
                  onError={({ currentTarget }) => {
                    currentTarget.onerror = null;
                    currentTarget.src = getFallbackImage("ATTRACTION");
                  }} />
                
                    </div>
                    <div className="place-content">
                      <h3 className="place-title">{hit.title}</h3>
                      <p className="place-city">
                        <FaMapMarkerAlt className="place-icon" />
                        {hit.subtitle ?? "-"}
                      </p>
                      <p className="place-description">{hit.subtitle ?? "-"}</p>
                      <div className="place-meta">
                        <span className="place-rating">
                          <FaCalendarAlt className="place-star" />
                          {hit.date ? new Date(hit.date).toLocaleDateString() : tt("explore.labels.upcoming", "Upcoming")}
                        </span>
                        <span className="place-type">{tt("explore.labels.event", "Event")}</span>
                      </div>
                      <button
                  type="button"
                  className="view-details-btn"
                  onClick={() => navigate(hit.href)}>
                        {tt("explore.actions.viewDetails", "View details")}
                      </button>
                    </div>
                  </div>
            )}
              </div>
            </div> :
        null}

          {placeHits.length > 0 ?
        <div className="explore-search-results__section">
              <h3 className="explore-search-results__section-title">
                {tt("explore.search.places", "Places")}
              </h3>
              <div className="grid">
                {placeHits.map((hit) =>
            <div key={hit.href} className="place-card">
                    <div className="place-image">
                      <img
                  src={hit.imageUrl || getFallbackImage("ATTRACTION")}
                  alt={hit.title}
                  onError={({ currentTarget }) => {
                    currentTarget.onerror = null;
                    currentTarget.src = getFallbackImage("ATTRACTION");
                  }} />
                
                    </div>
                    <div className="place-content">
                      <h3 className="place-title">{hit.title}</h3>
                      <p className="place-city">
                        <FaMapMarkerAlt className="place-icon" />
                        {hit.subtitle ?? "-"}
                      </p>
                      <p className="place-description">{hit.subtitle ?? "-"}</p>
                      <div className="place-meta">
                        <span className="place-rating">
                          <FaStar className="place-star" />
                          {hit.rating != null ? Number(hit.rating).toFixed(1) : tt("explore.labels.noRating", "No rating")}
                        </span>
                        <span className="place-type">{tt("explore.labels.place", "Place")}</span>
                      </div>
                      <button
                  type="button"
                  className="view-details-btn"
                  onClick={() => navigate(hit.href)}>
                        {tt("explore.actions.viewDetails", "View details")}
                      </button>
                    </div>
                  </div>
            )}
              </div>
            </div> :
        null}
        </section> :

      <>
          <div className="filter-bar">
            {categories.map((category) =>
          <button
            type="button"
            key={category.key}
            className={activeCategory === category.key ? "active" : ""}
            onClick={() => setActiveCategory(category.key)}>
                {category.label}
              </button>
          )}
          </div>

          {loading ?
        <div className="explore-skeleton-grid" aria-hidden="true">
              {Array.from({ length: 6 }, (_, index) =>
          <div className="explore-skeleton-card" key={index}>
                  <div className="explore-skeleton-image" />
                  <div className="explore-skeleton-body">
                    <div className="explore-skeleton-line explore-skeleton-line--title" />
                    <div className="explore-skeleton-line explore-skeleton-line--city" />
                    <div className="explore-skeleton-line explore-skeleton-line--description" />
                    <div className="explore-skeleton-line explore-skeleton-line--description-short" />
                    <div className="explore-skeleton-meta">
                      <div className="explore-skeleton-pill" />
                      <div className="explore-skeleton-pill" />
                    </div>
                  </div>
                </div>
          )}
            </div> :
        filteredPlaces.length === 0 && events.length === 0 ?
        <div className="explore-empty-state">
              {tt(
            "explore.emptyStateCategory",
            `No results in ${activeCategoryLabel} category`
          )}
            </div> :

        <>
              {events.length > 0 ?
          <>
                  <h2 className="explore-section-title">
                    {tt("explore.sections.events", "Events")}
                  </h2>
                  <div className="grid">
                    {events.map((event) =>
              <div className="place-card" key={event.id}>
                        <div className="place-image">
                          <img
                    src={event.imageUrl || getFallbackImage("ATTRACTION")}
                    alt={event.title}
                    onError={({ currentTarget }) => {
                      currentTarget.onerror = null;
                      currentTarget.src = getFallbackImage("ATTRACTION");
                    }} />
                  
                        </div>

                        <div className="place-content">
                          <h3 className="place-title">{event.title}</h3>
                          <p className="place-city">
                            <FaMapMarkerAlt className="place-icon" />
                            {event.venue?.city?.name ?? event.venue?.name ?? "-"}
                          </p>
                          <p className="place-description">{event.description}</p>

                          <div className="place-meta">
                            <span className="place-rating">
                              <FaCalendarAlt className="place-star" />
                              {event.startDate ?
                      new Date(event.startDate).toLocaleDateString() :
                      "-"}
                            </span>
                            <span className="place-type">
                              {tt("explore.labels.event", "Event")}
                            </span>
                          </div>
                          <button
                    type="button"
                    className="view-details-btn"
                    onClick={() =>
                    navigate(`/events/${event.slug?.trim() ? event.slug : event.id}`)
                    }>
                            {tt("explore.actions.viewDetails", "View details")}
                          </button>
                        </div>
                      </div>
              )}
                  </div>
                </> :
          null}

              {filteredPlaces.length > 0 ?
          <>
                  <h2 className="explore-section-title">
                    {tt("explore.sections.places", "Places")}
                  </h2>
                  <div className="grid">
                    {filteredPlaces.map((place) =>
              <div className="place-card" key={place.id}>
                        <div className="place-image">
                          <img
                    src={place.imageUrl || getFallbackImage(place.type)}
                    alt={place.name}
                    onError={({ currentTarget }) => {
                      currentTarget.onerror = null;
                      currentTarget.src = getFallbackImage(place.type);
                    }} />
                  
                        </div>

                        <div className="place-content">
                          <h3 className="place-title">{place.name}</h3>

                          <p className="place-city">
                            <FaMapMarkerAlt className="place-icon" />
                            {place.city?.name}
                          </p>
                          <p className="place-description">{place.description}</p>

                          <div className="place-meta">
                            <span className="place-rating">
                              <FaStar className="place-star" />
                              {place.ratingAverage != null
                                ? `${Number(place.ratingAverage).toFixed(1)} (${place.ratingCount ?? 0})`
                                : tt("explore.labels.noRating", "No rating")}
                            </span>
                            <span className="place-type">{place.type}</span>
                          </div>
                          <button
                    type="button"
                    className="view-details-btn"
                    onClick={() =>
                    navigate(`/places/${place.slug?.trim() ? place.slug : place.id}`)
                    }>
                            {tt("explore.actions.viewDetails", "View details")}
                          </button>
                        </div>
                      </div>
              )}
                  </div>
                </> :
          null}
            </>
        }
        </>
      }
    </div>);

};

export default Explore;

import { useEffect, useState } from "react";
import { Link, useNavigate, useParams } from "react-router-dom";
import { toast } from "react-toastify";
import { FiArrowLeft, FiMapPin, FiStar, FiHeart, FiSend } from "react-icons/fi";
import { fetchPlaceById } from "@/api/catalog";
import { useAuth } from "@/context/AuthContext";
import { addWishlistItem } from "@/api/user";
import FeedbackSection from "@/components/public/feedback/FeedbackSection";
import "./PlaceDetail.css";

const placeImageFallback =
  "https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=1400&q=75&auto=format&fit=crop";

const TYPE_ICONS = {
  RESTAURANT: "🍽️",
  CAFE: "☕",
  MUSEUM: "🏛️",
  PARK: "🌿",
  HISTORICAL: "🏺",
  SHOP: "🛍️",
  ATTRACTION: "📍",
};

const PlaceDetailSkeleton = () => (
  <div className="place-detail-page">
    <div className="place-detail-shell">
      <div className="place-sk-hero" />
      <div className="place-sk-meta-grid">
        {[1, 2, 3, 4].map((i) => <div key={i} className="place-sk-meta-card" />)}
      </div>
      <div className="place-sk-line place-sk-line--wide" />
      <div className="place-sk-line" />
      <div className="place-sk-line place-sk-line--short" />
    </div>
  </div>
);

const PlaceDetail = () => {
  const { id = "" } = useParams();
  const navigate = useNavigate();
  const { isAuthenticated } = useAuth();
  const [place, setPlace] = useState(null);
  const [loading, setLoading] = useState(true);
  const [wishlisted, setWishlisted] = useState(false);
  const [wishlistBusy, setWishlistBusy] = useState(false);

  useEffect(() => {
    const load = async () => {
      setLoading(true);
      try {
        const payload = await fetchPlaceById(id);
        setPlace(payload ?? null);
      } catch {
        toast.error("Failed to load place details");
      } finally {
        setLoading(false);
      }
    };
    if (id) void load();
  }, [id]);

  const handleWishlist = async () => {
    if (!isAuthenticated) {
      toast.info("Sign in to save places to your wishlist");
      navigate("/login");
      return;
    }
    try {
      setWishlistBusy(true);
      await addWishlistItem(place.id);
      setWishlisted(true);
      toast.success("Added to wishlist ❤️");
    } catch {
      toast.error("Failed to update wishlist");
    } finally {
      setWishlistBusy(false);
    }
  };

  if (loading) return <PlaceDetailSkeleton />;

  if (!place) {
    return (
      <div className="place-detail-page">
        <div className="place-detail-shell place-detail-shell--empty">
          <p>Place not found.</p>
          <Link to="/explore" className="place-detail-back">← Back to Explore</Link>
        </div>
      </div>
    );
  }

  const typeIcon = TYPE_ICONS[place.type] ?? "📍";
  const rating = Number(place.ratingAverage ?? 0);

  return (
    <div className="place-detail-page">
      <article className="place-detail-shell">

        <div className="place-detail-breadcrumb">
          <Link to="/explore" className="place-detail-back">
            <FiArrowLeft size={15} /> Back to Explore
          </Link>
          {place.city?.name && (
            <Link
              to={`/explore?q=${encodeURIComponent(place.city.name)}`}
              className="place-detail-crumb-city"
            >
              <FiMapPin size={13} /> {place.city.name}
            </Link>
          )}
        </div>

        <section className="place-detail-hero">
          <img
            src={place.imageUrl || placeImageFallback}
            alt={place.name}
            className="place-detail-image"
            onError={({ currentTarget }) => {
              currentTarget.onerror = null;
              currentTarget.src = placeImageFallback;
            }}
          />
          <div className="place-detail-overlay">
            <div className="place-detail-overlay-top">
              <span className="place-detail-type-badge">{typeIcon} {place.type}</span>
              <div className="place-detail-overlay-actions">
                <button
                  type="button"
                  className={`place-detail-wishlist-btn${wishlisted ? " place-detail-wishlist-btn--active" : ""}`}
                  onClick={handleWishlist}
                  disabled={wishlistBusy || wishlisted}
                  title={wishlisted ? "In wishlist" : "Add to wishlist"}
                >
                  <FiHeart size={18} fill={wishlisted ? "currentColor" : "none"} />
                </button>
              </div>
            </div>
            <h1>{place.name}</h1>
            <p>{place.description || "No description available yet for this place."}</p>
          </div>
        </section>

        <section className="place-detail-meta-grid">
          <div className="place-detail-meta-card">
            <span className="place-detail-meta-label">Type</span>
            <strong>{typeIcon} {place.type ?? "—"}</strong>
          </div>
          <div className="place-detail-meta-card">
            <span className="place-detail-meta-label">City</span>
            <strong><FiMapPin size={13} /> {place.city?.name ?? "—"}</strong>
          </div>
          <div className="place-detail-meta-card">
            <span className="place-detail-meta-label">Rating</span>
            <strong className="place-detail-rating">
              <FiStar size={14} className="place-detail-star" />
              {rating > 0 ? `${rating.toFixed(1)} / 5` : "Not rated yet"}
            </strong>
          </div>
          <div className="place-detail-meta-card">
            <span className="place-detail-meta-label">Reviews</span>
            <strong>{place.ratingCount ?? 0} reviews</strong>
          </div>
        </section>

        {Array.isArray(place.tags) && place.tags.length > 0 && (
          <div className="place-detail-tags">
            {place.tags.map((tag) => (
              <span key={tag.id ?? tag} className="place-detail-tag">
                {tag.name ?? tag}
              </span>
            ))}
          </div>
        )}

        <div className="place-detail-cta-bar">
          <button
            type="button"
            className={`place-detail-wishlist-cta${wishlisted ? " active" : ""}`}
            onClick={handleWishlist}
            disabled={wishlistBusy || wishlisted}
          >
            <FiHeart size={16} fill={wishlisted ? "currentColor" : "none"} />
            {wishlisted ? "In wishlist" : "Add to wishlist"}
          </button>
          <Link
            to={`/plan?destination=${encodeURIComponent(place.city?.name ?? place.name)}`}
            className="place-detail-plan-cta"
          >
            <FiSend size={16} />
            Plan a trip here
          </Link>
        </div>

        <FeedbackSection target="place" targetId={place.id} />
      </article>
    </div>
  );
};

export default PlaceDetail;

import { useEffect, useState } from "react";
import { Link, useNavigate, useSearchParams } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { toast } from "react-toastify";
import { useAuth } from "@/context/AuthContext";
import { globalSearch } from "@/api/public";
import {
  fetchPublicTripBrowse } from

"@/api/trips";
import { getApiErrorMessage } from "@/utils/errors";
import { GlobalSearchBar } from "@/components/public/search/GlobalSearchBar";
import "./SearchPage.css";

const SearchPage = () => {
  const { t } = useTranslation();
  const { isAuthenticated } = useAuth();
  const [params] = useSearchParams();
  const navigate = useNavigate();
  const q = params.get("q")?.trim() ?? "";
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(false);
  const [publicTrips, setPublicTrips] = useState([]);
  const [publicTripsLoading, setPublicTripsLoading] = useState(true);

  useEffect(() => {
    let active = true;
    setPublicTripsLoading(true);
    void (async () => {
      try {
        const res = await fetchPublicTripBrowse(12);
        if (active) {
          setPublicTrips(res.items ?? []);
        }
      } catch (error) {
        if (active) {
          toast.error(
            getApiErrorMessage(
              error,
              t("search.publicTripsLoadFailed", {
                defaultValue: "Could not load public trips."
              })
            )
          );
          setPublicTrips([]);
        }
      } finally {
        if (active) {
          setPublicTripsLoading(false);
        }
      }
    })();
    return () => {
      active = false;
    };
  }, [t]);

  useEffect(() => {
    if (!q) {
      setItems([]);
      return;
    }
    let active = true;
    setLoading(true);
    void (async () => {
      try {
        const res = await globalSearch(q, 16);
        if (active) {
          setItems(res.items ?? []);
        }
      } catch (error) {
        if (active) {
          toast.error(getApiErrorMessage(error, t("search.failed", { defaultValue: "Search failed" })));
        }
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    })();
    return () => {
      active = false;
    };
  }, [q, t]);

  const planFromHere = (hit) => {
    if (hit.type === "place" && hit.cityId) {
      navigate(`/plan?cityId=${encodeURIComponent(hit.cityId)}`);
      return;
    }
    toast.info(t("search.planNeedsCity", { defaultValue: "Pick a place with a city to plan from here." }));
  };

  const visibleItems = isAuthenticated ?
  items :
  items.filter((hit) => hit.type !== "user");

  return (
    <div className="search-page">
      <h1 className="search-page__title">
        {t("search.emptyTitle", { defaultValue: "Search" })}
      </h1>
      <div className="search-page__toolbar">
        <GlobalSearchBar />
      </div>

      <section className="search-page__public-trips" aria-labelledby="search-public-trips-heading">
        <h2 id="search-public-trips-heading" className="search-page__section-title">
          {t("search.publicTripsTitle", { defaultValue: "Public trips from travelers" })}
        </h2>
        {publicTripsLoading ?
        <p className="search-page__hint">{t("common.loading", { defaultValue: "Loading…" })}</p> :
        publicTrips.length === 0 ?
        <p className="search-page__hint">
            {t("search.publicTripsEmpty", { defaultValue: "No public trips yet. Share a plan to see it here." })}
          </p> :

        <ul className="search-page__trip-cards">
            {publicTrips.map((trip) =>
          <li key={trip.shareSlug} className="search-page__trip-card">
                <Link className="search-page__trip-link" to={`/trip/${encodeURIComponent(trip.shareSlug)}`}>
                  {trip.title?.trim() ?
              trip.title :
              t("tripPlanner.savedPlans", { defaultValue: "Saved plan" })}
                </Link>
                <span className="search-page__trip-by">
                  {t("search.publicTripsBy", {
                username: trip.username,
                defaultValue: `By @${trip.username}`
              })}
                </span>
              </li>
          )}
          </ul>
        }
      </section>

      {q ?
      <section className="search-page__results" aria-labelledby="search-results-heading">
          <h2 id="search-results-heading" className="search-page__section-title">
            {t("search.resultsFor", { defaultValue: 'Results for "{{q}}"', q })}
          </h2>
          {loading ?
        <p>{t("common.loading", { defaultValue: "Loading…" })}</p> :
        visibleItems.length === 0 ?
        <p>{t("search.noResults", { defaultValue: "No matches yet." })}</p> :

        <ul className="search-page__list">
              {visibleItems.map((hit, index) =>
          <li key={`${hit.type}-${hit.href}-${index}`} className="search-page__item">
                  <div className="search-page__item-main">
                    <span className="search-page__badge">{hit.type}</span>
                    <Link className="search-page__link" to={hit.href}>
                      {hit.title}
                    </Link>
                    {hit.subtitle ?
              <span className="search-page__sub">{hit.subtitle}</span> :
              null}
                  </div>
                  {hit.type === "place" ?
            <button type="button" className="search-page__plan-btn" onClick={() => planFromHere(hit)}>
                      {t("search.planFromHere", { defaultValue: "Plan from here" })}
                    </button> :
            null}
                </li>
          )}
            </ul>
        }
        </section> :

      <p className="search-page__hint search-page__hint--below">
          {t("search.typeToSearch", {
          defaultValue: "Type above to search people, providers, places, and events."
        })}
        </p>
      }
    </div>);

};

export default SearchPage;

import { Outlet, useParams } from "react-router-dom";
import { ProviderProfileProvider } from "@/context/ProviderContext";
import { useProviderWorkspace } from "@/context/ProviderWorkspaceContext";

const ProviderBusinessLayout = () => {
  const { slug = "", param = "" } = useParams();
  const { slug: workspaceSlug } = useProviderWorkspace();
  const raw = slug || param;
  const decoded = raw ? decodeURIComponent(raw) : (workspaceSlug?.trim() ?? "");

  return (
    <ProviderProfileProvider slug={decoded}>
      <Outlet />
    </ProviderProfileProvider>
  );
};

export default ProviderBusinessLayout;

