}));

const extractRows = (payload) => {
  const list = Array.isArray(payload)
    ? payload
    : payload && typeof payload === "object" && Array.isArray(payload.data)
      ? payload.data
      : [];
  return list.filter(Boolean);
};

const extractCities = (payload) => {
