import { useEffect, useState } from "react";
import { Navigate, useParams } from "react-router-dom";
import { fetchPublicUserCard } from "@/api/public";
import { RouteLoadingState } from "@/components/shared/RouteLoadingState";

/**
 * Old URLs used /social/users/:id. Resolve to canonical /u/:username.
 */
const LegacyUserProfileRedirect = () => {
  const { legacy = "" } = useParams();
  const [target, setTarget] = useState(null);
  const [failed, setFailed] = useState(false);

  useEffect(() => {
    if (!legacy) {
      setFailed(true);
      return;
    }
    let active = true;
    void (async () => {
      try {
        const card = await fetchPublicUserCard(legacy);
        if (active) {
          setTarget(card.username);
        }
      } catch {
        if (active) {
          setFailed(true);
        }
      }
    })();
    return () => {
      active = false;
    };
  }, [legacy]);

  if (failed) {
    return <Navigate to="/social" replace />;
  }
  if (!target) {
    return <RouteLoadingState />;
  }
  return <Navigate to={`/u/${encodeURIComponent(target)}`} replace />;
};

export default LegacyUserProfileRedirect;

import { useEffect, useRef, useState, useCallback } from "react";
import { useSearchParams } from "react-router-dom";
import { io } from "socket.io-client";
import { toast } from "react-toastify";
import {
  FiPlus,
  FiSearch,
  FiSend,
  FiUsers,
  FiX,
  FiCheck,
  FiMessageSquare,
  FiBookmark,
  FiChevronLeft,
  FiChevronRight,
  FiArrowLeft,
} from "react-icons/fi";
import { useAuth } from "@/context/AuthContext";
import { API_BASE_URL } from "@/api/client";
import { STORAGE_KEYS } from "@/utils/storageKeys";
import { getResolvedAvatarUrl, handleAvatarImageError } from "@/utils/avatar";
import {
  createConversation,
  fetchFriends,
  fetchInbox,
  fetchConversationMessages,
  sendMessage,
  markConversationRead,
  normalizeMessageItem,
} from "@/api/social";
import "./MessengerHub.css";

const getConvDisplayName = (conv, currentUserId) => {
  if (!conv) return "Chat";
  if (conv.isGroup) return conv.title || "Group";
  if (conv.members?.length) {
    const other = conv.members.find((m) => m.userId !== currentUserId);
    if (other) {
      const name = `${other.firstName || ""} ${other.lastName || ""}`.trim();
      if (name) return name;
      if (other.username) return other.username;
    }
    if (conv.members.length === 1) {
      const self = conv.members[0];
      const name = `${self.firstName || ""} ${self.lastName || ""}`.trim();
      return name || "Saved Messages";
    }
  }
  return conv.title || "Private Chat";
};

const getConvAvatarInfo = (conv, currentUserId) => {
  if (!conv) return { type: "initial", value: "?" };
  if (conv.isGroup) return { type: "icon" };
  if (conv.members?.length) {
    const other = conv.members.find((m) => m.userId !== currentUserId);
    const target = other ?? conv.members[0];
    const avatarSrc = getResolvedAvatarUrl(target);
    if (avatarSrc) return { type: "img", src: avatarSrc };
    const name = getConvDisplayName(conv, currentUserId);
    return { type: "initial", value: (name[0] || "?").toUpperCase() };
  }
  const name = getConvDisplayName(conv, currentUserId);
  return { type: "initial", value: (name[0] || "?").toUpperCase() };
};

const MessengerHub = () => {
  const { user } = useAuth();
  const [searchParams, setSearchParams] = useSearchParams();
  const currentUserId = user?.id ?? user?.userId;
  const isRTL = document.documentElement.dir === "rtl";

  const [conversations, setConversations] = useState([]);
  const [friends, setFriends] = useState([]);
  const [messages, setMessages] = useState([]);
  const [messageDraft, setMessageDraft] = useState("");
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isGroupMode, setIsGroupMode] = useState(false);
  const [selectedFriends, setSelectedFriends] = useState([]);
  const [groupTitle, setGroupTitle] = useState("");
  const [friendSearch, setFriendSearch] = useState("");
  const [firstMessage, setFirstMessage] = useState("");
  const [isCreating, setIsCreating] = useState(false);
  const [sidebarSearch, setSidebarSearch] = useState("");
  const [typingUsers, setTypingUsers] = useState({});
  const [mobileShowChat, setMobileShowChat] = useState(false);

  const socketRef = useRef(null);
  const messagesEndRef = useRef(null);
  const inputRef = useRef(null);
  const typingTimeouts = useRef({});
  const typingEmitTimeout = useRef(null);
  const joinedConversationRef = useRef(null);
  const selectedConversationIdRef = useRef(null);

  const selectedConversationId = searchParams.get("conversation");
  const selectedConversation = conversations.find(
    (c) => c.id === selectedConversationId,
  );

  useEffect(() => {
    selectedConversationIdRef.current = selectedConversationId;
  }, [selectedConversationId]);

  const scrollToBottom = useCallback((smooth = true) => {
    messagesEndRef.current?.scrollIntoView({
      behavior: smooth ? "smooth" : "auto",
    });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, scrollToBottom]);

  const loadInbox = useCallback(async () => {
    try {
      const data = await fetchInbox();
      setConversations(data);
    } catch {}
  }, []);

  const joinCurrentRoom = useCallback(() => {
    const convId = selectedConversationIdRef.current;
    if (!convId) return;
    const prev = joinedConversationRef.current;
    if (prev && prev !== convId) {
      socketRef.current?.emit("leave", { conversationId: prev });
      joinedConversationRef.current = null;
    }
    socketRef.current?.emit("join", { conversationId: convId }, (res) => {
      if (res?.ok) joinedConversationRef.current = convId;
    });
  }, []);

  useEffect(() => {
    if (!currentUserId) return;
    const token = localStorage.getItem(STORAGE_KEYS.authToken);
    const base = API_BASE_URL.replace(/\/$/, "");
    socketRef.current = io(`${base}/chat`, {
      auth: { token },
      query: { userId: currentUserId },
      transports: ["websocket"],
      withCredentials: true,
    });

    socketRef.current.on("connect", () => joinCurrentRoom());

    const onMessage = (payload) => {
      try {
        const normMsg =
          payload?.message && typeof normalizeMessageItem === "function"
            ? normalizeMessageItem(payload.message, payload.conversationId)
            : payload?.message;

        if (payload?.conversationId === selectedConversationIdRef.current) {
          setMessages((prev) => {
            if (!normMsg?.id) return prev;
            if (prev.some((m) => m.id === normMsg.id)) return prev;
            const merged = [...prev, normMsg];
            merged.sort(
              (a, b) =>
                new Date(a.createdAt).getTime() -
                new Date(b.createdAt).getTime(),
            );
            return merged;
          });
        }

        setConversations((prev) =>
          prev.map((c) =>
            c.id === payload?.conversationId
              ? {
                  ...c,
                  lastMessage: normMsg?.content ?? c.lastMessage,
                  lastMessageAt: normMsg?.createdAt ?? c.lastMessageAt,
                }
              : c,
          ),
        );

        window.dispatchEvent(
          new CustomEvent("chat:message", { detail: payload }),
        );
      } catch {}
    };

    const onConversationUpsert = (payload) => {
      if (!payload?.id) return;
      setConversations((prev) => {
        const exists = prev.find((c) => c.id === payload.id);
        if (exists)
          return prev.map((c) =>
            c.id === payload.id ? { ...c, ...payload } : c,
          );
        return [payload, ...prev];
      });
    };

    const onTyping = ({ conversationId, userId }) => {
      if (
        conversationId === selectedConversationIdRef.current &&
        userId !== currentUserId
      ) {
        setTypingUsers((prev) => ({ ...prev, [userId]: true }));
        clearTimeout(typingTimeouts.current[userId]);
        typingTimeouts.current[userId] = setTimeout(() => {
          setTypingUsers((prev) => {
            const n = { ...prev };
            delete n[userId];
            return n;
          });
        }, 3500);
      }
    };

    const onStopTyping = ({ userId }) => {
      clearTimeout(typingTimeouts.current[userId]);
      setTypingUsers((prev) => {
        const n = { ...prev };
        delete n[userId];
        return n;
      });
    };

    socketRef.current.on("message:new", onMessage);
    socketRef.current.on("conversation:upsert", onConversationUpsert);
    socketRef.current.on("typing", onTyping);
    socketRef.current.on("stop_typing", onStopTyping);

    return () => {
      socketRef.current?.off("message:new", onMessage);
      socketRef.current?.off("conversation:upsert", onConversationUpsert);
      socketRef.current?.off("typing", onTyping);
      socketRef.current?.off("stop_typing", onStopTyping);
      socketRef.current?.disconnect();
      Object.values(typingTimeouts.current).forEach(clearTimeout);
    };
  }, [currentUserId, loadInbox, joinCurrentRoom]);

  useEffect(() => {
    loadInbox();
    fetchFriends()
      .then(setFriends)
      .catch(() => {});
  }, [loadInbox]);

  useEffect(() => {
    if (!selectedConversationId) return;
    setMessages([]);

    fetchConversationMessages(selectedConversationId)
      .then((msgs) => {
        setMessages(msgs);
        setTimeout(() => scrollToBottom(false), 60);
      })
      .catch(() => {});

    markConversationRead(selectedConversationId)
      .then(() => {
        setConversations((prev) =>
          prev.map((c) =>
            c.id === selectedConversationId ? { ...c, unreadCount: 0 } : c,
          ),
        );
      })
      .catch(() => {});

    inputRef.current?.focus();

    const joinRoom = () => {
      const prev = joinedConversationRef.current;
      if (prev && prev !== selectedConversationId) {
        socketRef.current?.emit("leave", { conversationId: prev });
        joinedConversationRef.current = null;
      }
      socketRef.current?.emit(
        "join",
        { conversationId: selectedConversationId },
        (res) => {
          if (res?.ok) joinedConversationRef.current = selectedConversationId;
        },
      );
    };

    if (socketRef.current?.connected) joinRoom();
    else socketRef.current?.once("connect", joinRoom);

    return () => {
      if (joinedConversationRef.current) {
        socketRef.current?.emit("leave", {
          conversationId: joinedConversationRef.current,
        });
        joinedConversationRef.current = null;
      }
    };
  }, [selectedConversationId, scrollToBottom]);

  const handleInputChange = (e) => {
    setMessageDraft(e.target.value);
    if (socketRef.current && selectedConversationId) {
      socketRef.current.emit("typing", {
        conversationId: selectedConversationId,
        isTyping: true,
      });
      clearTimeout(typingEmitTimeout.current);
      typingEmitTimeout.current = setTimeout(() => {
        socketRef.current?.emit("typing", {
          conversationId: selectedConversationId,
          isTyping: false,
        });
      }, 3500);
    }
  };

  const handleCreateChat = async () => {
    if (!firstMessage.trim()) {
      toast.error(
        isRTL ? "اكتب رسالتك الأولى أولاً" : "Write your first message",
      );
      return;
    }
    if (selectedFriends.length === 0) {
      toast.error(
        isRTL ? "اختر شخصاً على الأقل" : "Select at least one person",
      );
      return;
    }
    setIsCreating(true);
    try {
      const res = await createConversation({
        participantIds: selectedFriends,
        title: isGroupMode && groupTitle.trim() ? groupTitle.trim() : undefined,
        firstMessage: firstMessage.trim(),
      });
      setSearchParams({ conversation: res.conversation.id });
      setMobileShowChat(true);
      setIsModalOpen(false);
      resetModal();
      loadInbox();
    } catch {
      toast.error(
        isRTL ? "فشل إنشاء المحادثة" : "Failed to create conversation",
      );
    } finally {
      setIsCreating(false);
    }
  };

  const resetModal = () => {
    setIsGroupMode(false);
    setSelectedFriends([]);
    setGroupTitle("");
    setFriendSearch("");
    setFirstMessage("");
  };

  const toggleFriendSelection = (id) => {
    if (isGroupMode) {
      setSelectedFriends((prev) =>
        prev.includes(id) ? prev.filter((fid) => fid !== id) : [...prev, id],
      );
    } else {
      setSelectedFriends([id]);
    }
  };

  const handleSend = async () => {
    const content = messageDraft.trim();
    if (!content || !selectedConversationId) return;
    setMessageDraft("");
    clearTimeout(typingEmitTimeout.current);
    socketRef.current?.emit("typing", {
      conversationId: selectedConversationId,
      isTyping: false,
    });
    try {
      await sendMessage(selectedConversationId, content);
    } catch {
      toast.error(isRTL ? "خطأ في الإرسال" : "Send error");
    }
  };

  const openConversation = (id) => {
    setSearchParams({ conversation: id });
    setMobileShowChat(true);
  };

  const formatTime = (dateStr) => {
    if (!dateStr) return "";
    return new Date(dateStr).toLocaleTimeString(isRTL ? "ar-EG" : "en-US", {
      hour: "2-digit",
      minute: "2-digit",
    });
  };

  const formatConvTime = (dateStr) => {
    if (!dateStr) return "";
    const d = new Date(dateStr);
    const now = new Date();
    if (d.toDateString() === now.toDateString())
      return d.toLocaleTimeString(isRTL ? "ar-EG" : "en-US", {
        hour: "2-digit",
        minute: "2-digit",
      });
    return d.toLocaleDateString(isRTL ? "ar-EG" : "en-US", {
      day: "numeric",
      month: "short",
    });
  };

  const filteredConversations = conversations.filter((c) => {
    if (!sidebarSearch) return true;
    return getConvDisplayName(c, currentUserId)
      .toLowerCase()
      .includes(sidebarSearch.toLowerCase());
  });

  const filteredFriends = friends.filter((f) => {
    if (!friendSearch) return true;
    return `${f.firstName} ${f.lastName} ${f.username || ""}`
      .toLowerCase()
      .includes(friendSearch.toLowerCase());
  });

  const typingCount = Object.keys(typingUsers).length;
  const convDisplayName = selectedConversation
    ? getConvDisplayName(selectedConversation, currentUserId)
    : "";
  const ChevronIcon = isRTL ? FiChevronLeft : FiChevronRight;

  const [isMobileWidth, setIsMobileWidth] = useState(() =>
    typeof window !== "undefined"
      ? window.matchMedia("(max-width: 640px)").matches
      : false,
  );

  useEffect(() => {
    if (typeof window === "undefined") return;
    const mq = window.matchMedia("(max-width: 640px)");
    const handler = (e) => setIsMobileWidth(e.matches);
    // set initial
    setIsMobileWidth(mq.matches);
    if (mq.addEventListener) mq.addEventListener("change", handler);
    else mq.addListener(handler);
    return () => {
      if (mq.removeEventListener) mq.removeEventListener("change", handler);
      else mq.removeListener(handler);
    };
  }, []);

  const showMobileBackBtn = isMobileWidth && mobileShowChat;

  const renderAvatarContent = (avatarInfo, fallbackName, isGroup = false) => {
    if (isGroup) return <FiUsers size={17} />;
    if (avatarInfo?.type === "img")
      return (
        <img
          src={avatarInfo.src}
          alt={fallbackName}
          onError={handleAvatarImageError}
        />
      );
    return avatarInfo?.value || "?";
  };

  return (
    <div className="mh-root">
      <aside
        className={`mh-sidebar${mobileShowChat ? " mh-sidebar--slide-out" : ""}`}>
        <header className="mh-sidebar-header">
          <h1 className="mh-sidebar-title">{isRTL ? "الرسائل" : "Messages"}</h1>
          <button
            className="mh-new-btn"
            onClick={() => setIsModalOpen(true)}
            aria-label="New">
            <FiPlus size={18} />
          </button>
        </header>

        <div className="mh-sidebar-search">
          <FiSearch size={14} />
          <input
            placeholder={
              isRTL ? "بحث في المحادثات..." : "Search conversations..."
            }
            value={sidebarSearch}
            onChange={(e) => setSidebarSearch(e.target.value)}
          />
        </div>

        <nav className="mh-conv-list">
          {filteredConversations.length === 0 && (
            <div className="mh-empty-list">
              <FiMessageSquare size={30} />
              <p>{isRTL ? "لا توجد محادثات بعد" : "No conversations yet"}</p>
              <button
                className="mh-empty-new-btn"
                onClick={() => setIsModalOpen(true)}>
                <FiPlus size={12} />
                {isRTL ? "ابدأ محادثة" : "Start a chat"}
              </button>
            </div>
          )}

          {filteredConversations.map((conv) => {
            const isActive = selectedConversationId === conv.id;
            const hasUnread = conv.unreadCount > 0;
            const displayName = getConvDisplayName(conv, currentUserId);
            const avatarInfo = getConvAvatarInfo(conv, currentUserId);

            return (
              <div
                key={conv.id}
                className={`mh-conv-item${isActive ? " active" : ""}${hasUnread ? " unread" : ""}`}
                onClick={() => openConversation(conv.id)}>
                <div
                  className={`mh-conv-avatar${conv?.isGroup ? " group" : ""}`}>
                  {renderAvatarContent(
                    avatarInfo,
                    displayName,
                    conv?.isGroup ?? false,
                  )}
                </div>
                <div className="mh-conv-body">
                  <div className="mh-conv-top">
                    <span className="mh-conv-name">{displayName}</span>
                    <span className="mh-conv-time">
                      {formatConvTime(conv.lastMessageAt)}
                    </span>
                  </div>
                  <div className="mh-conv-bottom">
                    <span className="mh-conv-preview">
                      {conv.lastMessage ||
                        (isRTL ? "ابدأ المحادثة" : "Start chatting")}
                    </span>
                    {hasUnread && (
                      <span className="mh-unread-badge">
                        {conv.unreadCount > 99 ? "99+" : conv.unreadCount}
                      </span>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </nav>
      </aside>

      <main className={`mh-chat${mobileShowChat ? " mh-chat--slide-in" : ""}`}>
        {selectedConversationId ? (
          <>
            <header className="mh-chat-header">
              {showMobileBackBtn && (
                <button
                  className="mh-back-btn"
                  onClick={() => setMobileShowChat(false)}
                  aria-label={isRTL ? "رجوع" : "Back"}>
                  {isRTL ? (
                    <FiChevronRight size={20} />
                  ) : (
                    <FiArrowLeft size={20} />
                  )}
                </button>
              )}
              <div
                className={`mh-chat-header-avatar${selectedConversation?.isGroup ? " group" : ""}`}>
                {renderAvatarContent(
                  getConvAvatarInfo(selectedConversation, currentUserId),
                  convDisplayName,
                  selectedConversation?.isGroup ?? false,
                )}
              </div>
              <div className="mh-chat-header-info">
                <h2>{convDisplayName}</h2>
                {typingCount > 0 ? (
                  <p className="mh-typing-text">
                    {typingCount > 1
                      ? isRTL
                        ? `${typingCount} أشخاص يكتبون`
                        : `${typingCount} people typing`
                      : isRTL
                        ? "يكتب..."
                        : "typing..."}
                    <span className="mh-typing-dots">
                      <span />
                      <span />
                      <span />
                    </span>
                  </p>
                ) : (selectedConversation?.isGroup ?? false) ? (
                  <p className="mh-chat-header-sub">
                    {isRTL ? "مجموعة" : "Group"}
                  </p>
                ) : null}
              </div>
            </header>

            <div className="mh-messages">
              {messages.length === 0 && (
                <div className="mh-messages-empty">
                  <FiMessageSquare size={34} />
                  <p>
                    {isRTL ? "ابدأ المحادثة الآن!" : "Start the conversation!"}
                  </p>
                </div>
              )}

              {messages.map((m, idx) => {
                const isOwn = m.senderId === currentUserId;
                const grouped =
                  idx > 0 && messages[idx - 1]?.senderId === m.senderId;
                const showName =
                  !isOwn &&
                  (selectedConversation?.isGroup ?? false) &&
                  !grouped;
                const senderAvatarSrc = getResolvedAvatarUrl(m.sender);

                return (
                  <div
                    key={m.id}
                    className={`mh-msg-row${isOwn ? " own" : ""}${grouped ? " grouped" : ""}`}>
                    {!isOwn && (
                      <div
                        className={`mh-msg-avatar${grouped ? " hidden" : ""}`}>
                        {!grouped &&
                          (senderAvatarSrc ? (
                            <img
                              src={senderAvatarSrc}
                              alt=""
                              onError={handleAvatarImageError}
                            />
                          ) : (
                            (m.sender?.firstName?.[0] || "?").toUpperCase()
                          ))}
                      </div>
                    )}
                    <div className="mh-msg-content-group">
                      {showName && (
                        <span className="mh-msg-sender-name">
                          {m.sender?.firstName} {m.sender?.lastName}
                        </span>
                      )}
                      <div className={`mh-msg-bubble${isOwn ? " own" : ""}`}>
                        {m.replyToMessage && (
                          <div className="mh-reply-preview">
                            <span className="mh-reply-bar" />
                            <span className="mh-reply-text">
                              {m.replyToMessage.content}
                            </span>
                          </div>
                        )}
                        <span className="mh-msg-text">{m.content}</span>
                        <div className="mh-msg-meta">
                          <span className="mh-msg-time">
                            {formatTime(m.createdAt)}
                          </span>
                          {m.editedAt && (
                            <span className="mh-edited-tag">
                              {isRTL ? "معدّل" : "edited"}
                            </span>
                          )}
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}
              <div ref={messagesEndRef} />
            </div>

            <div className="mh-input-area">
              <input
                ref={inputRef}
                className="mh-input"
                value={messageDraft}
                onChange={handleInputChange}
                placeholder={isRTL ? "اكتب رسالة..." : "Write a message..."}
                onKeyDown={(e) => {
                  if (e.key === "Enter" && !e.shiftKey) {
                    e.preventDefault();
                    handleSend();
                  }
                }}
              />
              <button
                className={`mh-send-btn${messageDraft.trim() ? " active" : ""}`}
                onClick={handleSend}
                disabled={!messageDraft.trim()}>
                <FiSend size={16} />
              </button>
            </div>
          </>
        ) : (
          <div className="mh-no-chat">
            <div className="mh-no-chat-icon">
              <FiMessageSquare size={46} />
            </div>
            <h3>{isRTL ? "مرحباً بك في الرسائل" : "Welcome to Messages"}</h3>
            <p>
              {isRTL
                ? "اختر محادثة موجودة أو ابدأ محادثة جديدة"
                : "Select a conversation or start a new one"}
            </p>
            <button
              className="mh-no-chat-btn"
              onClick={() => setIsModalOpen(true)}>
              <FiPlus size={14} />
              {isRTL ? "محادثة جديدة" : "New conversation"}
            </button>
          </div>
        )}
      </main>

      {isModalOpen && (
        <div
          className="mh-overlay"
          onClick={(e) => {
            if (e.target === e.currentTarget) {
              setIsModalOpen(false);
              resetModal();
            }
          }}>
          <div className="mh-modal">
            <div className="mh-modal-header">
              <h2>
                {isGroupMode
                  ? isRTL
                    ? "إنشاء مجموعة"
                    : "Create Group"
                  : isRTL
                    ? "محادثة جديدة"
                    : "New Conversation"}
              </h2>
              <button
                className="mh-modal-close"
                onClick={() => {
                  setIsModalOpen(false);
                  resetModal();
                }}>
                <FiX size={17} />
              </button>
            </div>

            <div className="mh-type-toggle">
              <button
                className={`mh-type-btn${!isGroupMode ? " active" : ""}`}
                onClick={() => {
                  setIsGroupMode(false);
                  setSelectedFriends([]);
                }}>
                <FiMessageSquare size={14} />
                {isRTL ? "فردية" : "Direct"}
              </button>
              <button
                className={`mh-type-btn${isGroupMode ? " active" : ""}`}
                onClick={() => {
                  setIsGroupMode(true);
                  setSelectedFriends([]);
                }}>
                <FiUsers size={14} />
                {isRTL ? "مجموعة" : "Group"}
              </button>
            </div>

            {isGroupMode && (
              <div className="mh-modal-field">
                <label className="mh-modal-label">
                  {isRTL ? "اسم المجموعة" : "Group name"}
                </label>
                <input
                  className="mh-modal-input"
                  placeholder={
                    isRTL ? "مثال: فريق العمل..." : "e.g. Work team..."
                  }
                  value={groupTitle}
                  onChange={(e) => setGroupTitle(e.target.value)}
                  maxLength={200}
                />
              </div>
            )}

            <div className="mh-modal-search">
              <FiSearch size={14} />
              <input
                placeholder={isRTL ? "ابحث عن أصدقاء..." : "Search friends..."}
                value={friendSearch}
                onChange={(e) => setFriendSearch(e.target.value)}
              />
            </div>

            <div className="mh-friends-list">
              {!isGroupMode && (
                <div
                  className={`mh-friend-item self${selectedFriends[0] === currentUserId ? " selected" : ""}`}
                  onClick={() => setSelectedFriends([currentUserId])}>
                  <div className="mh-friend-avatar self">
                    <FiBookmark size={14} />
                  </div>
                  <div className="mh-friend-info">
                    <span className="mh-friend-name">
                      {isRTL ? "رسائل محفوظة" : "Saved Messages"}
                    </span>
                    <span className="mh-friend-sub">
                      {isRTL
                        ? "احفظ ملاحظاتك ووصلاتك"
                        : "Save your notes and links"}
                    </span>
                  </div>
                  {selectedFriends[0] === currentUserId && (
                    <span className="mh-friend-check">
                      <FiCheck size={13} />
                    </span>
                  )}
                </div>
              )}

              {filteredFriends.map((f) => {
                const isSelected = selectedFriends.includes(f.userId);
                const friendAvatarSrc = getResolvedAvatarUrl(f);
                return (
                  <div
                    key={f.userId}
                    className={`mh-friend-item${isSelected ? " selected" : ""}`}
                    onClick={() => toggleFriendSelection(f.userId)}>
                    <div className="mh-friend-avatar">
                      {friendAvatarSrc ? (
                        <img
                          src={friendAvatarSrc}
                          alt={f.firstName}
                          onError={handleAvatarImageError}
                        />
                      ) : (
                        f.firstName[0].toUpperCase()
                      )}
                    </div>
                    <div className="mh-friend-info">
                      <span className="mh-friend-name">
                        {f.firstName} {f.lastName}
                      </span>
                      {f.username && (
                        <span className="mh-friend-sub">@{f.username}</span>
                      )}
                    </div>
                    {isSelected && (
                      <span className="mh-friend-check">
                        <FiCheck size={13} />
                      </span>
                    )}
                  </div>
                );
              })}

              {filteredFriends.length === 0 && (
                <div className="mh-friends-empty">
                  {isRTL ? "لا يوجد أصدقاء مطابقون" : "No matching friends"}
                </div>
              )}
            </div>

            {isGroupMode && selectedFriends.length > 0 && (
              <div className="mh-selected-chips">
                {selectedFriends.map((fid) => {
                  const fr = friends.find((f) => f.userId === fid);
                  if (!fr) return null;
                  return (
                    <span key={fid} className="mh-chip">
                      {fr.firstName}
                      <button onClick={() => toggleFriendSelection(fid)}>
                        <FiX size={10} />
                      </button>
                    </span>
                  );
                })}
              </div>
            )}

            <div className="mh-modal-field">
              <label className="mh-modal-label">
                {isRTL ? "الرسالة الأولى" : "First message"}
              </label>
              <input
                className="mh-modal-input"
                placeholder={
                  isRTL
                    ? "اكتب رسالتك الأولى..."
                    : "Write your first message..."
                }
                value={firstMessage}
                onChange={(e) => setFirstMessage(e.target.value)}
                onKeyDown={(e) =>
                  e.key === "Enter" && !isCreating && handleCreateChat()
                }
              />
            </div>

            <button
              className="mh-confirm-btn"
              disabled={
                selectedFriends.length === 0 ||
                !firstMessage.trim() ||
                isCreating
              }
              onClick={handleCreateChat}>
              {isCreating ? (
                <span className="mh-spinner" />
              ) : (
                <>
                  {isGroupMode
                    ? isRTL
                      ? "إنشاء المجموعة"
                      : "Create Group"
                    : isRTL
                      ? "بدء المحادثة"
                      : "Start Chat"}
                  <ChevronIcon size={15} />
                </>
              )}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default MessengerHub;

import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { toast } from "react-toastify";
import { getApiErrorMessage } from "@/utils/errors";
import {
  fetchNotifications,
  getNotificationHref,
  markAllNotificationsRead,
  markNotificationRead,
} from "@/api/social";
import { useNotifications } from "@/context/NotificationsContext";
import "./SocialFeed.css";

const NOTIF_ICONS = {
  LIKE: "❤️",
  COMMENT: "💬",
  REPLY: "↩️",
  FOLLOW: "👤",
  MESSAGE: "✉️",
  PLAN_COPIED: "📋",
  FRIEND_REQUEST: "🤝",
  FRIEND_ACCEPTED: "✅",
  BOOKING_NEW: "📅",
  BOOKING_STATUS: "🔔",
  REVIEW_NEW: "⭐",
};

const NotificationsPage = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { refreshUnreadCount } = useNotifications();
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);

  const load = async () => {
    try {
      setLoading(true);
      const payload = await fetchNotifications();
      setItems(Array.isArray(payload) ? payload : []);
    } catch (error) {
      toast.error(
        getApiErrorMessage(
          error,
          t("social.notifications.loadFailed", { defaultValue: "Failed to load notifications" }),
        ),
      );
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    void load();
  }, []);

  return (
    <section className="social-feed-page">
      <div className="social-feed-header">
        <h1>{t("social.notifications.title", { defaultValue: "Notifications" })}</h1>
        <button
          type="button"
          onClick={async () => {
            try {
              await markAllNotificationsRead();
              await load();
              await refreshUnreadCount();
            } catch (error) {
              toast.error(
                getApiErrorMessage(
                  error,
                  t("social.notifications.markFailed", {
                    defaultValue: "Failed to mark notifications",
                  }),
                ),
              );
            }
          }}
        >
          {t("social.notifications.markAllRead", { defaultValue: "Mark all as read" })}
        </button>
      </div>
      <div className="social-post-list">
        {loading ? (
          <div className="social-feed-skeletons">
            {Array.from({ length: 4 }).map((_, i) => (
              <div key={i} className="social-post-skeleton">
                <div className="social-skeleton-header">
                  <div className="social-skeleton-avatar" />
                  <div className="social-skeleton-meta">
                    <div className="social-skeleton-line social-skeleton-line--body" />
                    <div className="social-skeleton-line social-skeleton-line--date" />
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : items.length === 0 ? (
          <p className="social-empty">
            {t("social.notifications.empty", { defaultValue: "No notifications yet." })}
          </p>
        ) : (
          items.map((item) => {
            const icon = NOTIF_ICONS[item.type] ?? "🔔";
            const href = getNotificationHref(item);
            return (
              <article
                key={item.id}
                className={`social-post-card notif-card${item.isRead ? " notif-card--read" : ""}`}
                role={href ? "button" : undefined}
                tabIndex={href ? 0 : undefined}
                onClick={async () => {
                  try {
                    await markNotificationRead(item.id);
                    await refreshUnreadCount();
                    if (href) {
                      navigate(href);
                    }
                  } catch (error) {
                    toast.error(
                      getApiErrorMessage(
                        error,
                        t("social.notifications.markFailed", {
                          defaultValue: "Failed to update notification",
                        }),
                      ),
                    );
                  }
                }}
                onKeyDown={(e) => e.key === "Enter" && e.currentTarget.click()}
              >
                <div className="notif-card-body">
                  <span className="notif-icon">{icon}</span>
                  <div className="notif-content">
                    <p>{item.message}</p>
                    <small>{new Date(item.createdAt).toLocaleString()}</small>
                  </div>
                  {!item.isRead && <span className="notif-unread-dot" />}
                </div>
              </article>
            );
          })
        )}
      </div>
    </section>
  );
};

export default NotificationsPage;

import { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { toast } from "react-toastify";
import { getApiErrorMessage } from "@/utils/errors";
import { useAuth } from "@/context/AuthContext";
import {
  createStory,
  deleteSocialPost,
  deleteStory,
  fetchSocialFeed,
  fetchStoryFeed,
  groupStoriesByAuthor,
  saveSocialPost,
  unsaveSocialPost,
  toggleSocialLike,
  updateSocialPost,
  uploadImage,
  viewStory,
} from "@/services/social/social.service";
import { PostCard, Stories } from "@/components/social";
import "./SocialFeed.css";

const SocialFeed = () => {
  const { t } = useTranslation();
  const { isAuthenticated, user } = useAuth();

  const [filter, setFilter] = useState("for-you");
  const [posts, setPosts] = useState([]);
  const [storiesLoading, setStoriesLoading] = useState(false);
  const [loading, setLoading] = useState(true);
  const [creatingStory, setCreatingStory] = useState(false);

  const [storyModalOpen, setStoryModalOpen] = useState(false);
  const [storyFile, setStoryFile] = useState(null);
  const [storyPreviewUrl, setStoryPreviewUrl] = useState(null);
  const [storyCaption, setStoryCaption] = useState("");

  const [storyUploadProgress, setStoryUploadProgress] = useState(0);

  const [stories, setStories] = useState(() => groupStoriesByAuthor([]));

  const loadFeed = async () => {
    try {
      setLoading(true);
      const payload = await fetchSocialFeed(filter);
      setPosts(Array.isArray(payload) ? payload : []);
    } catch (error) {
      toast.error(getApiErrorMessage(error, "Failed to load social feed"));
      setPosts([]);
    } finally {
      setLoading(false);
    }
  };

  const loadStories = async () => {
    if (!isAuthenticated) {
      setStories([]);
      return;
    }

    try {
      setStoriesLoading(true);
      const payload = await fetchStoryFeed();
      setStories(groupStoriesByAuthor(Array.isArray(payload) ? payload : []));
    } catch (error) {
      toast.error(getApiErrorMessage(error, "Failed to load stories"));
      setStories([]);
    } finally {
      setStoriesLoading(false);
    }
  };

  useEffect(() => {
    loadFeed();
  }, [filter]);

  useEffect(() => {
    loadStories();
  }, [isAuthenticated]);

  const closeStoryModal = () => {
    if (storyPreviewUrl) URL.revokeObjectURL(storyPreviewUrl);
    setStoryFile(null);
    setStoryPreviewUrl(null);
    setStoryCaption("");
    setStoryModalOpen(false);
  };

  const submitStory = async () => {
    if (!storyFile) return;

    try {
      setCreatingStory(true);

      const { path } = await uploadImage(storyFile, setStoryUploadProgress);

      await createStory({
        imageUrl: path,
        caption: storyCaption.trim() || undefined,
      });

      closeStoryModal();
      toast.success("Story published");
      await loadStories();
    } catch (error) {
      toast.error(getApiErrorMessage(error, "Story failed"));
    } finally {
      setCreatingStory(false);
      setStoryUploadProgress(0);
    }
  };

  const handleDeletePost = async (postId) => {
    try {
      await deleteSocialPost(postId);
      toast.success("Post deleted");
      await loadFeed();
    } catch (error) {
      toast.error(getApiErrorMessage(error, "Delete failed"));
    }
  };

  const handleUpdatePost = async (postId, payload) => {
    try {
      await updateSocialPost(postId, payload);
      toast.success("Post updated");
      await loadFeed();
    } catch (error) {
      toast.error(getApiErrorMessage(error, "Update failed"));
    }
  };

  const handleDeleteStory = async (storyId) => {
    try {
      await deleteStory(storyId);
      toast.success("Story deleted");
      await loadStories();
    } catch (error) {
      toast.error(getApiErrorMessage(error, "Delete story failed"));
    }
  };

  const handleViewStory = async (id) => {
    try {
      await viewStory(id);
    } catch {}
  };

  return (
    <section className="social-feed-page">
      <div className="social-feed-filters">
        {["for-you", "following"].map((tab) => (
          <button
            key={tab}
            type="button"
            className={`social-feed-tab${filter === tab ? " social-feed-tab--active" : ""}`}
            onClick={() => setFilter(tab)}
          >
            {tab === "for-you" ? t("social.feed.forYou", "For You") : t("social.feed.following", "Following")}
          </button>
        ))}
      </div>

      <Stories
        stories={stories}
        loading={storiesLoading}
        onCreateStory={() => setStoryModalOpen(true)}
        onViewStory={handleViewStory}
        onDeleteStory={handleDeleteStory}
        actorId={user?.id}
      />

      {loading ? (
        <div className="social-feed-skeletons">
          {Array.from({ length: 3 }).map((_, i) => (
            <div key={i} className="social-post-skeleton">
              <div className="social-skeleton-header">
                <div className="social-skeleton-avatar" />
                <div className="social-skeleton-meta">
                  <div className="social-skeleton-line social-skeleton-line--name" />
                  <div className="social-skeleton-line social-skeleton-line--date" />
                </div>
              </div>
              <div className="social-skeleton-line social-skeleton-line--title" />
              <div className="social-skeleton-line social-skeleton-line--body" />
              <div className="social-skeleton-line social-skeleton-line--body-short" />
            </div>
          ))}
        </div>
      ) : (
        posts.map((post) => (
          <PostCard
            key={post.id}
            post={post}
            isAuthenticated={isAuthenticated}
            toggleSocialLike={toggleSocialLike}
            saveSocialPost={saveSocialPost}
            unsaveSocialPost={unsaveSocialPost}
            actorId={user?.id}
            onDeletePost={handleDeletePost}
            onUpdatePost={handleUpdatePost}
          />
        ))
      )}

      {storyModalOpen && (
        <div className="social-modalBackdrop" onClick={closeStoryModal}>
          <div
            className="social-modalCard"
            onClick={(e) => e.stopPropagation()}>
            <input
              type="file"
              accept="image/*"
              onChange={(e) => {
                const file = e.target.files?.[0];
                if (!file) return;
                if (!file.type.startsWith("image/")) {
                  toast.error("Only image files are allowed");
                  return;
                }
                if (file.size > 5 * 1024 * 1024) {
                  toast.error("Image size must be less than 5MB");
                  return;
                }

                if (storyPreviewUrl) URL.revokeObjectURL(storyPreviewUrl);

                setStoryFile(file);
                setStoryPreviewUrl(URL.createObjectURL(file));
              }}
            />

            {storyPreviewUrl && <img src={storyPreviewUrl} alt="preview" />}
            {storyUploadProgress > 0 && storyUploadProgress < 100 ? (
              <small>Uploading... {storyUploadProgress}%</small>
            ) : null}

            <textarea
              value={storyCaption}
              onChange={(e) => setStoryCaption(e.target.value)}
            />

            <button
              onClick={submitStory}
              disabled={!storyFile || creatingStory}>
              Publish
            </button>
          </div>
        </div>
      )}
    </section>
  );
};

export default SocialFeed;

import { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { useParams } from "react-router-dom";
import { toast } from "react-toastify";
import { getApiErrorMessage } from "@/utils/errors";
import { createPostComment, fetchPostComments, fetchSocialPost } from "@/api/social";
import { useAuth } from "@/context/AuthContext";
import "./SocialFeed.css";

const SocialPostDetail = () => {
  const { t } = useTranslation();
  const { id = "" } = useParams();
  const { isAuthenticated } = useAuth();
  const [post, setPost] = useState(null);
  const [comments, setComments] = useState([]);
  const [commentText, setCommentText] = useState("");

  const load = async () => {
    try {
      const [nextPost, nextComments] = await Promise.all([
      fetchSocialPost(id),
      fetchPostComments(id)]
      );
      setPost(nextPost);
      setComments(Array.isArray(nextComments) ? nextComments : []);
    } catch (error) {
      toast.error(
        getApiErrorMessage(
          error,
          t("social.postDetail.loadFailed", { defaultValue: "Failed to load post details" })
        )
      );
    }
  };

  useEffect(() => {
    void load();
  }, [id]);

  return (
    <section className="social-feed-page">
      {!post ?
      <p className="social-loading">
          {t("social.postDetail.loading", { defaultValue: "Loading post..." })}
        </p> :

      <article className="social-post-card">
          <h2>{post.title || t("social.postDetail.titleFallback", { defaultValue: "Post details" })}</h2>
          {post.body ? <p>{post.body}</p> : null}
        </article>
      }

      <article className="social-composer">
        <h3>{t("social.postDetail.commentsTitle", { defaultValue: "Comments" })}</h3>
        {comments.length === 0 ?
        <p className="social-empty">
            {t("social.postDetail.commentsEmpty", { defaultValue: "No comments yet." })}
          </p> :
        null}
        {comments.map((comment) =>
        <div key={comment.id} className="social-post-card">
            <p>{comment.content}</p>
            <small>{new Date(comment.createdAt).toLocaleString()}</small>
          </div>
        )}
        {isAuthenticated ?
        <>
            <textarea
            value={commentText}
            onChange={(event) => setCommentText(event.target.value)}
            placeholder={t("social.postDetail.commentPlaceholder", {
              defaultValue: "Add a comment..."
            })} />
          
            <button
            type="button"
            onClick={async () => {
              try {
                const saved = await createPostComment(id, { content: commentText });
                setCommentText("");
                setComments((current) => [...current, saved]);
              } catch (error) {
                toast.error(
                  getApiErrorMessage(
                    error,
                    t("social.postDetail.addCommentFailed", {
                      defaultValue: "Failed to add comment"
                    })
                  )
                );
              }
            }}>
              {t("social.postDetail.addComment", { defaultValue: "Add Comment" })}
            </button>
          </> :
        null}
      </article>
    </section>);

};

export default SocialPostDetail;

import { useEffect, useMemo, useState } from "react";
import { useTranslation } from "react-i18next";
import { Link, useParams } from "react-router-dom";
import { toast } from "react-toastify";
import { getApiErrorMessage } from "@/utils/errors";
import {
  acceptFriendship,
  declineFriendship,
  fetchUserPostsByUsername,
  followUser,
  getFriendshipStateByUsername,
  getSocialGraphState,
  requestFriendship,
  saveSocialPost,
  unsaveSocialPost,
  toggleSocialLike,
  unfollowUser,
} from "@/api/social";
import {
  deleteSocialPost,
  updateSocialPost,
} from "@/services/social/social.service";
import { fetchPublicUserCard } from "@/api/public";
import { useAuth } from "@/context/AuthContext";
import { PostCard, ProfilePostComposer } from "@/components/social";
import { getResolvedAvatarUrl, handleAvatarImageError } from "@/utils/avatar";
import "./SocialFeed.css";
import "./UserSocialProfile.css";

const UserSocialProfile = () => {
  const { t } = useTranslation();
  const { username = "" } = useParams();
  const { isAuthenticated, user } = useAuth();
  const [posts, setPosts] = useState([]);
  const [card, setCard] = useState(null);
  const [graph, setGraph] = useState(null);
  const [friend, setFriend] = useState(null);
  const [friendActionLoading, setFriendActionLoading] = useState(false);
  const [followActionLoading, setFollowActionLoading] = useState(false);

  const decodedUsername = useMemo(
    () => decodeURIComponent(username),
    [username],
  );

  const isOwnProfile = useMemo(() => {
    if (!isAuthenticated || !user?.username || !decodedUsername.trim())
      return false;
    return user.username.toLowerCase() === decodedUsername.trim().toLowerCase();
  }, [isAuthenticated, user?.username, decodedUsername]);

  const load = async () => {
    if (!decodedUsername.trim()) {
      return;
    }
    try {
      const [publicCard, userPosts] = await Promise.all([
        fetchPublicUserCard(decodedUsername),
        fetchUserPostsByUsername(decodedUsername),
      ]);
      setCard(publicCard);
      setPosts(Array.isArray(userPosts) ? userPosts : []);

      if (isAuthenticated && user?.id) {
        const targetUserId =
          typeof publicCard?.id === "string" ? publicCard.id : null;
        const [fs, state] = await Promise.all([
          getFriendshipStateByUsername(decodedUsername),
          targetUserId && targetUserId !== user.id
            ? getSocialGraphState(targetUserId)
            : Promise.resolve(null),
        ]);
        setFriend(fs);

        if (state) {
          setGraph({
            followersCount: state.followersCount,
            following: state.following,
            followingCount: state.followingCount,
          });
        } else {
          setGraph(null);
        }
      } else {
        setGraph(null);
        setFriend(null);
      }
    } catch (error) {
      toast.error(
        getApiErrorMessage(
          error,
          t("social.userProfile.loadFailed", {
            defaultValue: "Failed to load profile",
          }),
        ),
      );
    }
  };

  useEffect(() => {
    void load();
  }, [decodedUsername, isAuthenticated, user?.id]);

  const targetUserId = friend?.targetUserId;

  const displayName = card
    ? `${card.firstName} ${card.lastName}`.trim() || card.username
    : decodedUsername ||
      t("social.userProfile.title", { defaultValue: "User Profile" });

  const profileUsername = card?.username ?? decodedUsername;

  const initial =
    (card?.username || decodedUsername || "?").trim().charAt(0).toUpperCase() ||
    "?";
  const cardAvatarSrc = getResolvedAvatarUrl(card);

  const followersCount = graph?.followersCount ?? card?.followersCount ?? 0;
  const followingCount = graph?.followingCount ?? card?.followingCount ?? 0;
  const isProviderProfile = (card?.role || "").toUpperCase() === "PROVIDER";
  // Show provider view (followers) only when viewing someone else's profile.
  const showProviderView = isProviderProfile && !isOwnProfile;

  const followersTo = profileUsername
    ? isOwnProfile
      ? "/profile/followers"
      : `/u/${encodeURIComponent(profileUsername)}/followers`
    : null;

  const followingTo = profileUsername
    ? isOwnProfile
      ? "/profile/following"
      : `/u/${encodeURIComponent(profileUsername)}/following`
    : null;

  const friendsTo = profileUsername
    ? isOwnProfile
      ? "/profile/friends"
      : `/u/${encodeURIComponent(profileUsername)}/friends`
    : null;

  const handleDeletePost = async (postId) => {
    const previousPosts = posts;
    setPosts((current) => current.filter((post) => post.id !== postId));
    try {
      await deleteSocialPost(postId);
      toast.success(
        t("social.profile.postDeleted", { defaultValue: "Post deleted" }),
      );
    } catch (error) {
      setPosts(previousPosts);
      toast.error(getApiErrorMessage(error, "Delete failed"));
    }
  };

  const handleUpdatePost = async (postId, payload) => {
    const previousPosts = posts;
    setPosts((current) =>
      current.map((post) =>
        post.id === postId
          ? {
              ...post,
              title:
                typeof payload.title === "string" ? payload.title : post.title,
              body: typeof payload.body === "string" ? payload.body : post.body,
            }
          : post,
      ),
    );
    try {
      await updateSocialPost(postId, payload);
      toast.success(
        t("social.profile.postUpdated", { defaultValue: "Post updated" }),
      );
    } catch (error) {
      setPosts(previousPosts);
      toast.error(getApiErrorMessage(error, "Update failed"));
    }
  };

  const optimisticFriendUpdate = (
    nextState,
    nextRequesterId = friend?.requesterId ?? null,
  ) => {
    setFriend((prev) => {
      if (!prev) return prev;
      return {
        ...prev,
        state: nextState,
        requesterId: nextRequesterId,
      };
    });
  };

  const handleAcceptFriend = async () => {
    const requesterId = friend?.requesterId ?? "";
    if (!requesterId || friendActionLoading) return;

    setFriendActionLoading(true);
    optimisticFriendUpdate("ACCEPTED", requesterId);
    try {
      await acceptFriendship(requesterId);
    } catch (error) {
      toast.error(getApiErrorMessage(error, "Accept failed"));
      await load();
    } finally {
      setFriendActionLoading(false);
    }
  };

  const handleDeclineFriend = async () => {
    const requesterId = friend?.requesterId ?? "";
    if (!requesterId || friendActionLoading) return;

    setFriendActionLoading(true);
    optimisticFriendUpdate("DECLINED", requesterId);
    try {
      await declineFriendship(requesterId);
    } catch (error) {
      toast.error(getApiErrorMessage(error, "Decline failed"));
      await load();
    } finally {
      setFriendActionLoading(false);
    }
  };

  const handleRequestFriend = async () => {
    if (!decodedUsername || friendActionLoading) return;

    setFriendActionLoading(true);
    optimisticFriendUpdate(
      "PENDING_OUTGOING",
      user?.id ?? friend?.requesterId ?? null,
    );
    try {
      await requestFriendship(decodedUsername);
    } catch (error) {
      toast.error(getApiErrorMessage(error, "Request failed"));
      await load();
    } finally {
      setFriendActionLoading(false);
    }
  };

  const handleFollowToggle = async () => {
    if (!targetUserId || followActionLoading || !graph) return;

    const currentlyFollowing = Boolean(graph.following);
    setFollowActionLoading(true);
    setGraph((prev) => {
      if (!prev) return prev;
      const delta = currentlyFollowing ? -1 : 1;
      return {
        ...prev,
        following: !currentlyFollowing,
        followersCount: Math.max(0, (prev.followersCount ?? 0) + delta),
      };
    });

    try {
      if (currentlyFollowing) {
        await unfollowUser(targetUserId);
      } else {
        await followUser(targetUserId);
      }
    } catch (error) {
      toast.error(
        getApiErrorMessage(
          error,
          t("social.userProfile.followUpdateFailed", {
            defaultValue: "Failed to update follow state",
          }),
        ),
      );
      await load();
    } finally {
      setFollowActionLoading(false);
    }
  };

  return (
    <section className="social-feed-page user-public-profile">
      <div className="user-public__shell">
        <div className="user-public__cover" aria-hidden />
        <div className="user-public__sheet">
          <div className="user-public__identity">
            <div className="user-public__avatarCol">
              <div className="user-public__avatarShell">
                <div className="user-public__avatar" aria-hidden="true">
                  {cardAvatarSrc ? (
                    <img
                      src={cardAvatarSrc}
                      alt=""
                      className="user-public__avatarImg"
                      onError={handleAvatarImageError}
                    />
                  ) : (
                    <span className="user-public__avatarInitial">
                      {initial}
                    </span>
                  )}
                </div>
              </div>
            </div>

            <div className="user-public__main">
              <p className="user-public__eyebrow">
                {t("social.userProfile.eyebrow", {
                  defaultValue: "Traveler profile",
                })}
              </p>
              <h1 className="user-public__name">{displayName}</h1>
              {profileUsername ? (
                <p className="user-public__handle">@{profileUsername}</p>
              ) : null}

              <div className="user-public__stats" role="list">
                {/* Show friends count for regular users (as a link), followers for providers */}
                {showProviderView ? (
                  followersTo ? (
                    <Link
                      to={followersTo}
                      className="user-public__statLink"
                      role="listitem">
                      <strong>{followersCount}</strong>
                      <span>
                        {t("social.userProfile.followersLabel", {
                          defaultValue: "followers",
                        })}
                      </span>
                    </Link>
                  ) : (
                    <span className="user-public__statPlain" role="listitem">
                      <strong>{followersCount}</strong>
                      <span>
                        {t("social.userProfile.followersLabel", {
                          defaultValue: "followers",
                        })}
                      </span>
                    </span>
                  )
                ) : friendsTo ? (
                  <Link
                    to={friendsTo}
                    className="user-public__statLink"
                    role="listitem">
                    <strong>{card?.friendsCount ?? 0}</strong>
                    <span>
                      {t("social.userProfile.friendsLabel", {
                        defaultValue: "friends",
                      })}
                    </span>
                  </Link>
                ) : (
                  <span className="user-public__statPlain" role="listitem">
                    <strong>{card?.friendsCount ?? 0}</strong>
                    <span>
                      {t("social.userProfile.friendsLabel", {
                        defaultValue: "friends",
                      })}
                    </span>
                  </span>
                )}
              </div>
            </div>

            <div className="user-public__actions">
              {isOwnProfile ? (
                <Link
                  to="/profile"
                  className="user-public__btn user-public__btn--secondary">
                  {t("social.userProfile.accountSettings", {
                    defaultValue: "Account settings",
                  })}
                </Link>
              ) : null}
              {isAuthenticated &&
              user?.id &&
              targetUserId &&
              user.id !== targetUserId ? (
                <div className="user-public__actionChips">
                  {/* Friend actions only for regular user profiles */}
                  {!isProviderProfile ? (
                    <>
                      {friend?.state === "ACCEPTED" ? (
                        <span className="user-public__badge">
                          {t("friends.connected", { defaultValue: "Friends" })}
                        </span>
                      ) : null}
                      {friend?.state === "PENDING_OUTGOING" ? (
                        <span className="user-public__badge user-public__badge--muted">
                          {t("friends.requestSent", {
                            defaultValue: "Request sent",
                          })}
                        </span>
                      ) : null}
                      {friend?.state === "PENDING_INCOMING" ? (
                        <>
                          <button
                            type="button"
                            className="user-public__btn"
                            disabled={friendActionLoading}
                            onClick={handleAcceptFriend}>
                            {t("friends.accept", { defaultValue: "Accept" })}
                          </button>
                          <button
                            type="button"
                            className="user-public__btn user-public__btn--ghost"
                            disabled={friendActionLoading}
                            onClick={handleDeclineFriend}>
                            {t("friends.decline", { defaultValue: "Decline" })}
                          </button>
                        </>
                      ) : null}
                      {friend?.state === "NONE" ||
                      friend?.state === "DECLINED" ? (
                        <button
                          type="button"
                          className="user-public__btn"
                          disabled={friendActionLoading}
                          onClick={handleRequestFriend}>
                          {t("friends.add", { defaultValue: "Add friend" })}
                        </button>
                      ) : null}
                    </>
                  ) : null}

                  {/* Follow actions only for provider profiles when viewing others */}
                  {showProviderView && graph ? (
                    <button
                      type="button"
                      className="user-public__btn user-public__btn--ghost"
                      disabled={followActionLoading}
                      onClick={handleFollowToggle}>
                      {graph.following
                        ? t("social.unfollow", { defaultValue: "Unfollow" })
                        : t("social.follow", { defaultValue: "Follow" })}
                    </button>
                  ) : null}
                </div>
              ) : null}
            </div>
          </div>
        </div>
      </div>

      {isOwnProfile && isAuthenticated ? (
        <div className="user-public__composer">
          <h2 className="user-public__composerTitle">
            {t("social.userProfile.publishSection", {
              defaultValue: "Share a trip to your feed",
            })}
          </h2>
          <ProfilePostComposer onPublished={() => void load()} />
        </div>
      ) : null}

      <div className="user-public__postsBlock">
        <h2 className="user-public__postsHeading">
          {t("social.userProfile.postsHeading", { defaultValue: "Posts" })}
        </h2>
        <div className="user-public__postList social-feed-list">
          {posts.length === 0 ? (
            <div className="user-public__empty">
              <p className="user-public__emptyTitle">
                {t("social.userProfile.noPosts", {
                  defaultValue: "No posts yet",
                })}
              </p>
              <p className="user-public__emptyHint">
                {t("social.userProfile.noPostsHint", {
                  defaultValue:
                    "When this traveler shares a trip, it will show up here.",
                })}
              </p>
            </div>
          ) : (
            posts.map((post) => (
              <PostCard
                key={post.id}
                post={post}
                isAuthenticated={isAuthenticated}
                toggleSocialLike={toggleSocialLike}
                saveSocialPost={saveSocialPost}
                unsaveSocialPost={unsaveSocialPost}
                actorId={user?.id}
                onDeletePost={handleDeletePost}
                onUpdatePost={handleUpdatePost}
              />
            ))
          )}
        </div>
      </div>
    </section>
  );
};

