import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { Link, NavLink } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { toast } from "react-toastify";
import {
  FiBell,
  FiBookmark,
  FiCalendar,
  FiHeart,
  FiHome,
  FiMail,
  FiMap,
  FiMessageCircle,
  FiPhone,
  FiUser,
} from "react-icons/fi";
import { useAuth } from "@/context/AuthContext";
import { updateUserProfile } from "@/api/user";
import {
  fetchUserPostsByUsername,
  saveSocialPost,
  toggleSocialLike,
  unsaveSocialPost,
} from "@/api/social";
import { deleteSocialPost, updateSocialPost, uploadImage } from "@/services/social/social.service";
import { useUserProfilePage } from "@/hooks/user/useUserProfilePage";
import { PostCard, ProfilePostComposer } from "@/components/social";
import { getResolvedAvatarUrl, handleAvatarImageError } from "@/utils/avatar";
import { getApiErrorMessage } from "@/utils/errors";
import "@/pages/social/SocialFeed.css";
import "@/pages/social/UserSocialProfile.css";
import "./Profile.css";

const Profile = () => {
  const { t } = useTranslation();
  const { refreshUser, user } = useAuth();
  const { error, loading, profile, refresh } = useUserProfilePage();
  const [activeTab, setActiveTab] = useState("posts");
  const [editing, setEditing] = useState(false);
  const [saving, setSaving] = useState(false);
  const [draft, setDraft] = useState({ fullName: "", phone: "" });
  const [posts, setPosts] = useState([]);
  const [postsLoading, setPostsLoading] = useState(false);
  const [avatarUploading, setAvatarUploading] = useState(false);
  const avatarInputRef = useRef(null);

  const displayAvatarSrc = getResolvedAvatarUrl(profile);
  const avatarInitial = (profile.fullName || user?.username || "U").trim().charAt(0).toUpperCase();

  const displayName = editing ? draft.fullName : profile.fullName;
  const headlineName = (displayName || "").trim() || profile.username || "—";

  const publicProfileTo = profile.username
    ? `/u/${encodeURIComponent(profile.username)}`
    : null;

  const loadPosts = useCallback(async () => {
    const uname = user?.username?.trim();
    if (!uname) {
      setPosts([]);
      return;
    }
    try {
      setPostsLoading(true);
      const userPosts = await fetchUserPostsByUsername(uname);
      const list = Array.isArray(userPosts) ? userPosts : [];
      list.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
      setPosts(list);
    } catch (err) {
      toast.error(
        getApiErrorMessage(
          err,
          t("social.userProfile.postsLoadFailed", { defaultValue: "Failed to load posts" }),
        ),
      );
      setPosts([]);
    } finally {
      setPostsLoading(false);
    }
  }, [t, user?.username]);

  useEffect(() => {
    void loadPosts();
  }, [loadPosts]);

  useEffect(() => {
    if (!editing) {
      setDraft({ fullName: profile.fullName, phone: profile.phone });
    }
  }, [profile.fullName, profile.phone, editing]);

  useEffect(() => {
    if (activeTab !== "about" && editing) {
      setDraft({ fullName: profile.fullName, phone: profile.phone });
      setEditing(false);
    }
  }, [activeTab, editing, profile.fullName, profile.phone]);

  const startEdit = () => {
    setDraft({ fullName: profile.fullName, phone: profile.phone });
    setEditing(true);
  };

  const openAboutAndEdit = () => {
    setActiveTab("about");
    startEdit();
  };

  const cancelEdit = () => {
    setDraft({ fullName: profile.fullName, phone: profile.phone });
    setEditing(false);
  };

  const saveEdit = async () => {
    if (!user?.id) return;
    try {
      setSaving(true);
      const [firstName, ...rest] = draft.fullName.trim().split(" ");
      await updateUserProfile(user.id, {
        firstName: firstName || "",
        lastName: rest.join(" ") || undefined,
        phone: draft.phone || undefined,
      });
      await refreshUser();
      await refresh();
      toast.success(t("profile.saveSuccess", { defaultValue: "Profile updated" }));
      setEditing(false);
    } catch {
      toast.error(t("profile.saveError", { defaultValue: "Failed to update profile" }));
    } finally {
      setSaving(false);
    }
  };

  const handleAvatarChange = async (e) => {
    const file = e.target.files?.[0];
    e.target.value = "";
    if (!file || !editing || !user?.id) return;
    try {
      setAvatarUploading(true);
      const { path } = await uploadImage(file);
      await updateUserProfile(user.id, { avatarUrl: path });
      await refreshUser();
      await refresh();
      toast.success(t("profile.avatarUpdated", { defaultValue: "Profile photo updated" }));
    } catch (err) {
      toast.error(getApiErrorMessage(err, t("profile.avatarError", { defaultValue: "Upload failed" })));
    } finally {
      setAvatarUploading(false);
    }
  };

  const handleDeletePost = async (postId) => {
    try {
      await deleteSocialPost(postId);
      toast.success(t("social.profile.postDeleted", { defaultValue: "Post deleted" }));
      await loadPosts();
    } catch (err) {
      toast.error(getApiErrorMessage(err, "Delete failed"));
    }
  };

  const handleUpdatePost = async (postId, payload) => {
    try {
      await updateSocialPost(postId, payload);
      toast.success(t("social.profile.postUpdated", { defaultValue: "Post updated" }));
      await loadPosts();
    } catch (err) {
      toast.error(getApiErrorMessage(err, "Update failed"));
    }
  };

  const navItems = useMemo(
    () => [
      { to: "/", label: t("navbar.home", { defaultValue: "Home" }), icon: <FiHome /> },
      {
        to: "/wishlist",
        label: t("sidebar.wishlist", { defaultValue: "Wishlist" }),
        icon: <FiHeart />,
      },
      {
        to: "/saved-plans",
        label: t("sidebar.saved", { defaultValue: "Saved plans" }),
        icon: <FiBookmark />,
      },
      {
        to: "/notifications",
        label: t("navbar.notifications", { defaultValue: "Notifications" }),
        icon: <FiBell />,
      },
      {
        to: "/social",
        label: t("sidebar.messengerTitle", { defaultValue: "Messenger" }),
        icon: <FiMessageCircle />,
      },
      {
        to: "/trip-planner",
        label: t("navbar.planner", { defaultValue: "Trip planner" }),
        icon: <FiMap />,
      },
      {
        to: "/bookings",
        label: t("navbar.bookings", { defaultValue: "Bookings" }),
        icon: <FiCalendar />,
      },
      {
        to: "/geo",
        label: t("profile.navGeo", { defaultValue: "Geo tables" }),
        icon: <FiMap />,
      },
      ...(publicProfileTo
        ? [
            {
              to: publicProfileTo,
              label: t("profile.publicProfile", { defaultValue: "Public profile" }),
              icon: <FiUser />,
              end: false,
            },
          ]
        : []),
    ],
    [publicProfileTo, t],
  );

  const tabPostsLabel = t("profile.tabPosts", { defaultValue: "Posts" });
  const tabAboutLabel = t("profile.tabAbout", { defaultValue: "About" });

  return (
    <section className="profile profile-page profile-page--fb profile-page--fullbleed">
      <div className="profile-page__grid profile-page__grid--fb">
        <div className="profile-page__main">
          {loading ? (
            <div className="profile-page__skeleton" aria-busy="true" aria-live="polite">
              <div className="profile-skeleton profile-skeleton--cover" />
              <div className="profile-skeleton profile-skeleton--panel" />
            </div>
          ) : null}

          {!loading && error ? (
            <p className="profile-page__status profile-page__status--error">
              {t("profile.loadError", { defaultValue: "We couldn't load your profile." })}
            </p>
          ) : null}

          {!loading && !error ? (
            <>
              <div className="profile-fb">
                <div className="profile-fb__cover" aria-hidden />
                <div className="profile-fb__body">
                  <div className="profile-fb__identity">
                    <div className="profile-fb__avatarCol">
                      <div className="profile-fb__avatarShell">
                        <div className="profile-fb__avatar">
                          {displayAvatarSrc ? (
                            <img
                              src={displayAvatarSrc}
                              alt=""
                              className="profile-fb__avatarImg"
                              onError={handleAvatarImageError}
                            />
                          ) : (
                            <span className="profile-fb__avatarInitial">{avatarInitial}</span>
                          )}
                        </div>
                      </div>
                      {activeTab === "about" && editing ? (
                        <>
                          <input
                            ref={avatarInputRef}
                            type="file"
                            accept="image/*"
                            className="profile-fb__avatarInput"
                            onChange={handleAvatarChange}
                            tabIndex={-1}
                            aria-hidden
                          />
                          <button
                            type="button"
                            className="profile-fb__avatarBtn"
                            disabled={avatarUploading}
                            onClick={() => avatarInputRef.current?.click()}
                          >
                            {avatarUploading
                              ? t("profile.uploading", { defaultValue: "Uploading…" })
                              : t("profile.changePhoto", { defaultValue: "Update photo" })}
                          </button>
                        </>
                      ) : null}
                    </div>

                    <div className="profile-fb__meta">
                      <h1 className="profile-fb__name">{headlineName}</h1>
                      {profile.username ? (
                        <p className="profile-fb__handle">@{profile.username}</p>
                      ) : null}
                      <div className="profile-fb__stats">
                        <Link to="/profile/friends" className="profile-fb__statLink">
                          <strong>{profile.friendsCount ?? 0}</strong>
                          <span>{t("profile.statFriendsShort", { defaultValue: "friends" })}</span>
                        </Link>
                        <span className="profile-fb__statDot" aria-hidden>
                          ·
                        </span>
                        <Link to="/profile/followers" className="profile-fb__statLink">
                          <strong>{profile.followersCount ?? 0}</strong>
                          <span>{t("profile.statFollowersShort", { defaultValue: "followers" })}</span>
                        </Link>
                        <span className="profile-fb__statDot" aria-hidden>
                          ·
                        </span>
                        <Link to="/profile/following" className="profile-fb__statLink">
                          <strong>{profile.followingCount ?? 0}</strong>
                          <span>{t("profile.statFollowingShort", { defaultValue: "following" })}</span>
                        </Link>
                        <span className="profile-fb__statDot" aria-hidden>
                          ·
                        </span>
                        <Link to="/wishlist" className="profile-fb__statLink">
                          <strong>{profile.wishlistCount}</strong>
                          <span>{t("profile.statWishlist", { defaultValue: "wishlist" })}</span>
                        </Link>
                        <span className="profile-fb__statDot" aria-hidden>
                          ·
                        </span>
                        <Link to="/saved-plans" className="profile-fb__statLink">
                          <strong>{profile.savedPlansCount}</strong>
                          <span>{t("profile.statPlansShort", { defaultValue: "saved plans" })}</span>
                        </Link>
                      </div>
                    </div>

                    <div className="profile-fb__actions">
                      {publicProfileTo ? (
                        <Link to={publicProfileTo} className="profile-fb__btn profile-fb__btn--secondary">
                          {t("profile.publicProfile", { defaultValue: "View as visitor" })}
                        </Link>
                      ) : null}
                      {activeTab === "about" && editing ? null : (
                        <button
                          type="button"
                          className="profile-fb__btn profile-fb__btn--primary"
                          onClick={openAboutAndEdit}
                        >
                          {t("profile.edit", { defaultValue: "Edit profile" })}
                        </button>
                      )}
                    </div>
                  </div>

                  <div className="profile-fb__tabBar" role="tablist" aria-label={t("profile.tabsLabel", { defaultValue: "Profile sections" })}>
                    <button
                      type="button"
                      role="tab"
                      id="profile-tab-posts"
                      aria-controls="profile-panel-posts"
                      aria-selected={activeTab === "posts"}
                      className={`profile-fb__tab${activeTab === "posts" ? " profile-fb__tab--active" : ""}`}
                      onClick={() => setActiveTab("posts")}
                    >
                      {tabPostsLabel}
                    </button>
                    <button
                      type="button"
                      role="tab"
                      id="profile-tab-about"
                      aria-controls="profile-panel-about"
                      aria-selected={activeTab === "about"}
                      className={`profile-fb__tab${activeTab === "about" ? " profile-fb__tab--active" : ""}`}
                      onClick={() => setActiveTab("about")}
                    >
                      {tabAboutLabel}
                    </button>
                  </div>
                </div>
              </div>

              {activeTab === "posts" ? (
                <div
                  className="profile-fbContent"
                  id="profile-panel-posts"
                  role="tabpanel"
                  aria-labelledby="profile-tab-posts"
                >
                  <section className="profile-panel profile-panel--composer" aria-labelledby="profile-composer-heading">
                    <h2 id="profile-composer-heading" className="profile-panel__title profile-panel__title--inline">
                      {t("social.userProfile.publishSection", { defaultValue: "Create post" })}
                    </h2>
                    <div className="profile-panel__composer">
                      <ProfilePostComposer onPublished={() => void loadPosts()} />
                    </div>
                  </section>

                  <section className="profile-panel profile-panel--posts" aria-labelledby="profile-posts-heading">
                    <div className="profile-panel__head profile-panel__head--row profile-panel__head--flush">
                      <h2 id="profile-posts-heading" className="profile-panel__title">
                        {t("social.userProfile.postsHeading", { defaultValue: "Posts" })}
                      </h2>
                      {postsLoading ? (
                        <span className="profile-panel__meta">{t("profile.postsLoading", { defaultValue: "Loading…" })}</span>
                      ) : (
                        <span className="profile-panel__meta">
                          {t("profile.postCount", {
                            count: posts.length,
                            defaultValue: "{{count}} posts",
                          })}
                        </span>
                      )}
                    </div>
                    <div className="social-feed-list user-profile-posts profile-page__posts">
                      {!postsLoading && posts.length === 0 ? (
                        <div className="profile-empty">
                          <p className="profile-empty__title">
                            {t("social.userProfile.noPosts", { defaultValue: "No posts yet" })}
                          </p>
                          <p className="profile-empty__text">
                            {t("profile.emptyPostsLead", {
                              defaultValue: "Start a post above — it will show here and on your public profile.",
                            })}
                          </p>
                        </div>
                      ) : null}
                      {posts.map((post) => (
                        <PostCard
                          key={post.id}
                          post={post}
                          isAuthenticated
                          toggleSocialLike={toggleSocialLike}
                          saveSocialPost={saveSocialPost}
                          unsaveSocialPost={unsaveSocialPost}
                          actorId={user?.id}
                          onDeletePost={handleDeletePost}
                          onUpdatePost={handleUpdatePost}
                        />
                      ))}
                    </div>
                  </section>
                </div>
              ) : null}

              {activeTab === "about" ? (
                <div
                  className="profile-fbContent"
                  id="profile-panel-about"
                  role="tabpanel"
                  aria-labelledby="profile-tab-about"
                >
                  <section
                    className="profile-panel profile-panel--account"
                    aria-labelledby="profile-account-heading"
                  >
                    <div className="profile-panel__head">
                      <h2 id="profile-account-heading" className="profile-panel__title">
                        {t("profile.accountDetailsTitle", { defaultValue: "Contact and basic info" })}
                      </h2>
                      <p className="profile-panel__subtitle">
                        {t("profile.accountDetailsLead", {
                          defaultValue: "Update how you appear on Waynest. Email is read-only.",
                        })}
                      </p>
                    </div>

                    <div className="profile-panel__grid">
                      <label className="profile-field">
                        <span>{t("profile.name", { defaultValue: "Name" })}</span>
                        <input
                          type="text"
                          name="profile-fullName"
                          autoComplete="name"
                          value={editing ? draft.fullName : profile.fullName}
                          onChange={(e) => setDraft((d) => ({ ...d, fullName: e.target.value }))}
                          readOnly={!editing}
                          aria-readOnly={!editing}
                          className={!editing ? "profile-field__input--locked" : undefined}
                        />
                      </label>
                      <label className="profile-field profile-field--span2">
                        <span>{t("profile.email", { defaultValue: "Email" })}</span>
                        <input
                          type="email"
                          name="profile-email"
                          autoComplete="email"
                          value={profile.email}
                          readOnly
                          tabIndex={-1}
                          className="profile-field__input--locked"
                        />
                      </label>
                      <label className="profile-field">
                        <span>{t("profile.phone", { defaultValue: "Phone" })}</span>
                        <input
                          type="tel"
                          name="profile-phone"
                          autoComplete="tel"
                          value={editing ? draft.phone : profile.phone}
                          onChange={(e) => setDraft((d) => ({ ...d, phone: e.target.value }))}
                          readOnly={!editing}
                          aria-readOnly={!editing}
                          className={!editing ? "profile-field__input--locked" : undefined}
                        />
                      </label>
                    </div>

                    {editing ? (
                      <div className="profile-panel__toolbar">
                        <button
                          type="button"
                          className="profile-btn-save"
                          disabled={saving}
                          onClick={() => void saveEdit()}
                        >
                          {saving
                            ? t("profile.saving", { defaultValue: "Saving…" })
                            : t("profile.save", { defaultValue: "Save changes" })}
                        </button>
                        <button type="button" className="profile-btn-cancel" onClick={cancelEdit}>
                          {t("profile.cancel", { defaultValue: "Cancel" })}
                        </button>
                      </div>
                    ) : (
                      <div className="profile-panel__toolbar profile-panel__toolbar--solo">
                        <button type="button" className="profile-btn-edit" onClick={startEdit}>
                          {t("profile.editDetails", { defaultValue: "Edit details" })}
                        </button>
                      </div>
                    )}
                  </section>
                </div>
              ) : null}
            </>
          ) : null}
        </div>

        <aside className="profile-page__aside" aria-label={t("profile.asideLabel", { defaultValue: "Profile sidebar" })}>
          {!loading && !error ? (
            <div className="profile-intro">
              <h2 className="profile-intro__title">
                {t("profile.introTitle", { defaultValue: "Intro" })}
              </h2>
              <ul className="profile-intro__list">
                {profile.email ? (
                  <li className="profile-intro__row">
                    <span className="profile-intro__icon" aria-hidden>
                      <FiMail />
                    </span>
                    <span className="profile-intro__text">{profile.email}</span>
                  </li>
                ) : null}
                {profile.phone ? (
                  <li className="profile-intro__row">
                    <span className="profile-intro__icon" aria-hidden>
                      <FiPhone />
                    </span>
                    <span className="profile-intro__text">{profile.phone}</span>
                  </li>
                ) : (
                  <li className="profile-intro__row profile-intro__row--muted">
                    <span className="profile-intro__icon" aria-hidden>
                      <FiPhone />
                    </span>
                    <span className="profile-intro__text">
                      {t("profile.introNoPhone", { defaultValue: "No phone added" })}
                    </span>
                  </li>
                )}
              </ul>
              <div className="profile-intro__links">
                <Link to="/wishlist" className="profile-intro__link">
                  {t("profile.statWishlist", { defaultValue: "Wishlist" })}
                  <span className="profile-intro__badge">{profile.wishlistCount}</span>
                </Link>
                <Link to="/saved-plans" className="profile-intro__link">
                  {t("profile.statPlans", { defaultValue: "Saved plans" })}
                  <span className="profile-intro__badge">{profile.savedPlansCount}</span>
                </Link>
              </div>
            </div>
          ) : null}

          <nav className="profile-aside-nav">
            <h2 className="profile-aside-nav__title">
              {t("profile.asideTitle", { defaultValue: "Shortcuts" })}
            </h2>
            <ul className="profile-aside-nav__list">
              {navItems.map((item) => (
                <li key={item.to}>
                  <NavLink
                    to={item.to}
                    end={item.end ?? item.to === "/"}
                    className={({ isActive }) =>
                      `profile-aside-nav__link${isActive ? " profile-aside-nav__link--active" : ""}`
                    }
                  >
                    <span className="profile-aside-nav__icon" aria-hidden>
                      {item.icon}
                    </span>
                    <span>{item.label}</span>
                  </NavLink>
                </li>
              ))}
            </ul>
          </nav>
        </aside>
      </div>
    </section>
  );
};

export default Profile;

import { useCallback, useEffect, useMemo, useState } from "react";
import { Link, useParams, useNavigate } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { FiArrowLeft, FiArrowRight, FiSearch } from "react-icons/fi";
import { fetchFriends, fetchMyFollowers, fetchMyFollowing } from "@/api/social";
import {
  fetchPublicUserFollowers,
  fetchPublicUserFollowing,
} from "@/api/public";
import { getResolvedAvatarUrl, handleAvatarImageError } from "@/utils/avatar";
import { getApiErrorMessage } from "@/utils/errors";
import "./ProfileConnections.css";

const LISTS = /** @type {const} */ (["friends", "followers", "following"]);

/**
 * @param {{
 *   list: "friends" | "followers" | "following";
 *   subjectUsername?: string;
 * }} props
 */
const ProfileConnections = ({ list, subjectUsername }) => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const [search, setSearch] = useState("");
  const [debouncedSearch, setDebouncedSearch] = useState("");
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const id = window.setTimeout(() => setDebouncedSearch(search.trim()), 320);
    return () => window.clearTimeout(id);
  }, [search]);

  const title = useMemo(() => {
    if (list === "friends") {
      return t("profile.connectionsFriends", { defaultValue: "Friends" });
    }
    if (list === "followers") {
      return t("profile.connectionsFollowers", { defaultValue: "Followers" });
    }
    return t("profile.connectionsFollowing", { defaultValue: "Following" });
  }, [list, t]);

  const backHref = subjectUsername
    ? `/u/${encodeURIComponent(subjectUsername)}`
    : "/profile";

  const isRTL =
    typeof document !== "undefined" && document.documentElement.dir === "rtl";
  const backText = subjectUsername
    ? t("profile.connectionsBackUser", { defaultValue: "Back" })
    : t("profile.connectionsBack", { defaultValue: "Back" });

  const load = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      let payload;
      if (subjectUsername) {
        if (list === "friends") {
          setError(
            t("profile.connectionsFriendsPublicUnavailable", {
              defaultValue:
                "Friends list is only available from your account settings.",
            }),
          );
          setRows([]);
          return;
        }
        if (list === "followers") {
          payload = await fetchPublicUserFollowers(
            subjectUsername,
            debouncedSearch,
          );
        } else {
          payload = await fetchPublicUserFollowing(
            subjectUsername,
            debouncedSearch,
          );
        }
      } else if (list === "friends") {
        payload = await fetchFriends(debouncedSearch);
      } else if (list === "followers") {
        payload = await fetchMyFollowers(debouncedSearch);
      } else {
        payload = await fetchMyFollowing(debouncedSearch);
      }
      setRows(Array.isArray(payload) ? payload : []);
    } catch (err) {
      setError(
        getApiErrorMessage(
          err,
          t("profile.connectionsLoadFailed", {
            defaultValue: "Could not load list.",
          }),
        ),
      );
      setRows([]);
    } finally {
      setLoading(false);
    }
  }, [debouncedSearch, list, subjectUsername, t]);

  useEffect(() => {
    void load();
  }, [load]);

  if (!LISTS.includes(list)) {
    return null;
  }

  return (
    <section className="profile-conn">
      <div className="profile-conn__bar">
        <button
          type="button"
          className="profile-conn__back"
          aria-label={backText}
          onClick={() => {
            try {
              if (
                typeof window !== "undefined" &&
                window.history &&
                window.history.length > 1
              ) {
                navigate(-1);
                return;
              }
            } catch {
              /* ignore and fallback to href */
            }
            navigate(backHref);
          }}>
          {!isRTL && <FiArrowLeft aria-hidden />}
          {backText}
          {isRTL && <FiArrowRight aria-hidden />}
        </button>
        <h1 className="profile-conn__title">
          {title}
          {subjectUsername ? (
            <span className="profile-conn__subject"> @{subjectUsername}</span>
          ) : null}
        </h1>
      </div>

      <div className="profile-conn__searchWrap">
        <FiSearch className="profile-conn__searchIcon" aria-hidden />
        <input
          type="search"
          className="profile-conn__search"
          placeholder={t("profile.connectionsSearchPlaceholder", {
            defaultValue: "Search by name or username…",
          })}
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          autoComplete="off"
          spellCheck={false}
        />
      </div>

      {error ? <p className="profile-conn__error">{error}</p> : null}

      {loading ? (
        <p className="profile-conn__status">
          {t("profile.connectionsLoading", { defaultValue: "Loading…" })}
        </p>
      ) : null}

      {!loading && !error && rows.length === 0 ? (
        <p className="profile-conn__empty">
          {debouncedSearch
            ? t("profile.connectionsEmptySearch", {
                defaultValue: "No people match your search.",
              })
            : t("profile.connectionsEmptyList", {
                defaultValue: "No one to show here yet.",
              })}
        </p>
      ) : null}

      <ul className="profile-conn__list">
        {rows.map((person) => {
          const name =
            `${person.firstName ?? ""} ${person.lastName ?? ""}`.trim() ||
            person.username;
          const avatar = getResolvedAvatarUrl(person);
          const initial = (person.username || name || "?")
            .trim()
            .charAt(0)
            .toUpperCase();
          const key = person.userId || person.id || person.username;
          return (
            <li key={key}>
              <Link
                to={`/u/${encodeURIComponent(person.username)}`}
                className="profile-conn__row">
                <div className="profile-conn__avatar">
                  {avatar ? (
                    <img
                      src={avatar}
                      alt=""
                      className="profile-conn__avatarImg"
                      onError={handleAvatarImageError}
                    />
                  ) : (
                    <span className="profile-conn__avatarInitial">
                      {initial}
                    </span>
                  )}
                </div>
                <div className="profile-conn__meta">
                  <span className="profile-conn__name">{name}</span>
                  <span className="profile-conn__handle">
                    @{person.username}
                  </span>
                </div>
              </Link>
            </li>
          );
        })}
      </ul>
    </section>
  );
};

export function UserPublicFollowersRoute() {
  const { username } = useParams();
  const decoded = decodeURIComponent(username ?? "");
  return <ProfileConnections list="followers" subjectUsername={decoded} />;
}

export function UserPublicFollowingRoute() {
  const { username } = useParams();
  const decoded = decodeURIComponent(username ?? "");
  return <ProfileConnections list="following" subjectUsername={decoded} />;
}

export default ProfileConnections;

import { lazy, Suspense } from "react";
import { Navigate, createBrowserRouter, useLocation } from "react-router-dom";
import { ProviderModeGate } from "@/components/routing/ProviderModeGate";
import { useAuth } from "@/context/AuthContext";
import { RouteLoadingState } from "@/components/shared/RouteLoadingState";
import { getDefaultDashboardPath } from "@/utils/routing";
import ProfileConnections, {
  UserPublicFollowersRoute,
  UserPublicFollowingRoute,
} from "@/pages/user/profile/ProfileConnections";

const GuestLayout = lazy(() => import("@/layouts/GuestLayout"));
const AuthLayout = lazy(() => import("@/layouts/AuthLayout"));
const SocialLayout = lazy(() => import("@/layouts/SocialLayout"));
const AdminLayout = lazy(() => import("@/layouts/AdminLayout"));
const ProviderLayout = lazy(() => import("@/layouts/ProviderLayout"));

const LandingPage = lazy(() => import("@/pages/guest/landing/LandingPage"));
const Explore = lazy(() => import("@/pages/guest/explore/Explore"));
const Destinations = lazy(() => import("@/pages/guest/destinations/Destinations"));
const About = lazy(() => import("@/pages/guest/about/About"));
const Contact = lazy(() => import("@/pages/guest/contact/Contact"));
const SearchPage = lazy(() => import("@/pages/guest/search/SearchPage"));
const PlaceDetail = lazy(() => import("@/pages/guest/placeDetail/PlaceDetail"));
const EventDetail = lazy(() => import("@/pages/guest/eventDetail/EventDetail"));
const PublicTripPage = lazy(() => import("@/pages/guest/tripShare/PublicTripPage"));
const Login = lazy(() => import("@/pages/auth/login/Login"));
const Register = lazy(() => import("@/pages/auth/register/Register"));
const VerifyEmail = lazy(() => import("@/pages/auth/verifyEmail/VerifyEmail"));
const ChooseAccountMode = lazy(() => import("@/pages/auth/chooseAccount/ChooseAccountMode"));
const InvitePage = lazy(() => import("@/pages/auth/invite/InvitePage"));
const SocialFeed = lazy(() => import("@/pages/social/SocialFeed"));
const MessengerHub = lazy(() => import("@/pages/social/MessengerHub"));
const SocialPostDetail = lazy(() => import("@/pages/social/SocialPostDetail"));
const UserSocialProfile = lazy(() => import("@/pages/social/UserSocialProfile"));
const InboxPage = lazy(() => import("@/pages/social/InboxPage"));
const ConversationPage = lazy(() => import("@/pages/social/ConversationPage"));
const NotificationsPage = lazy(() => import("@/pages/social/NotificationsPage"));
const CommunityTabPlaceholder = lazy(() => import("@/pages/social/community/CommunityTabPlaceholder"));
const Profile = lazy(() => import("@/pages/user/profile/Profile"));
const Bookings = lazy(() => import("@/pages/user/bookings/Bookings"));
const Wishlist = lazy(() => import("@/pages/user/wishlist/Wishlist"));
const GeoTables = lazy(() => import("@/pages/user/geo/GeoTables"));
const SavedPlans = lazy(() => import("@/pages/user/savedPlans/SavedPlans"));
const ProviderBusinessFeed = lazy(() => import("@/pages/provider/feed/ProviderBusinessFeed"));
const ProviderBusinessLayout = lazy(() => import("@/pages/provider/ProviderBusinessLayout"));
const ProviderCreatePostPage = lazy(() => import("@/pages/provider/create/ProviderCreatePostPage"));
const ProviderProfilePage = lazy(() => import("@/pages/provider/ProviderProfilePage"));
const ProviderReviewsPage = lazy(() => import("@/pages/provider/ProviderReviewsPage"));
const ProviderPanelProfile = lazy(() => import("@/pages/provider/profile/ProviderPanelProfile"));
const ProviderEvents = lazy(() => import("@/pages/provider/events/ProviderEvents"));
const ProviderPlaces = lazy(() => import("@/pages/provider/places/ProviderPlaces"));
const ProviderBookings = lazy(() => import("@/pages/provider/bookings/ProviderBookings"));
const ProviderApplyPage = lazy(() => import("@/pages/provider/apply/ProviderApplyPage"));
const AdminDashboard = lazy(() => import("@/pages/admin/dashboard/AdminDashboard"));
const DevicesPage = lazy(() => import("@/pages/admin/devices/DevicesPage"));
const UsersPage = lazy(() => import("@/pages/admin/users/UsersPage"));
const ProvidersPage = lazy(() => import("@/pages/admin/providers/ProvidersPage"));
const PlacesPage = lazy(() => import("@/pages/admin/places/PlacesPage"));
const CountriesPage = lazy(() => import("@/pages/admin/countries/CountriesPage"));
const CitiesPage = lazy(() => import("@/pages/admin/cities/CitiesPage"));
const CurrenciesPage = lazy(() => import("@/pages/admin/currencies/CurrenciesPage"));
const TagsPage = lazy(() => import("@/pages/admin/tags/TagsPage"));
const EventsPage = lazy(() => import("@/pages/admin/events/EventsPage"));
const ReviewsPage = lazy(() => import("@/pages/admin/reviews/ReviewsPage"));
const PlacePricingPage = lazy(() => import("@/pages/admin/placePricing/PlacePricingPage"));
const PlaceOpeningHoursPage = lazy(() => import("@/pages/admin/placeOpeningHours/PlaceOpeningHoursPage"));
const ProviderMembershipPage = lazy(() => import("@/pages/admin/providerMembership/ProviderMembershipPage"));
const ProviderApplicationsAdminPage = lazy(() =>
  import("@/pages/admin/providerApplications/ProviderApplicationsAdminPage"),
);
const TripPlanner = lazy(() => import("@/pages/shared/TripPlanner"));
const NotFound = lazy(() => import("@/pages/system/notfound/NotFound"));
const Unauthorized = lazy(() => import("@/pages/system/unauthorized/Unauthorized"));

const MEMBER_ROLES = ["USER", "PROVIDER"];

const getRoleFallbackPath = (role) => {
  if (role === "ADMIN" || role === "PROVIDER" || role === "USER") {
    return getDefaultDashboardPath(role);
  }

  return "/unauthorized";
};

/** Public business page: `/p/:slug` + optional `/places|events` (same component; tab follows URL). */
const providerBusinessChildRoutes = [
  { index: true, element: <ProviderProfilePage /> },
  { path: "places", element: <ProviderProfilePage /> },
  { path: "events", element: <ProviderProfilePage /> },
  { path: "reviews", element: <Navigate to=".." replace /> },
  { path: "services", element: <Navigate to="../places" replace /> },
];

const getSignedInHomePath = (role) => {
  if (role === "ADMIN") {
    return "/admin-panel";
  }
  return "/";
};

function RequireAuth({ allowedRoles, children }) {
  const { isAuthenticated, loading, user } = useAuth();
  const location = useLocation();

  if (loading) {
    return <RouteLoadingState />;
  }

  if (!isAuthenticated) {
    return <Navigate to="/login" replace state={{ from: location }} />;
  }

  if (allowedRoles?.length && !allowedRoles.includes(user?.role)) {
    return <Navigate to={getRoleFallbackPath(user?.role)} replace />;
  }

  return children;
}

function RequireGuest({ children }) {
  const { isAuthenticated, loading, user } = useAuth();

  if (loading) {
    return <RouteLoadingState />;
  }

  if (isAuthenticated) {
    return <Navigate to={getSignedInHomePath(user?.role)} replace />;
  }

  return children;
}

function HomeEntry() {
  const { isAuthenticated, loading, user } = useAuth();

  if (loading) {
    return <RouteLoadingState />;
  }

  if (!isAuthenticated) {
    return (
      <GuestLayout showRail={false}>
        <LandingPage />
      </GuestLayout>
    );
  }

  if (user?.role === "ADMIN") {
    return <Navigate to="/admin-panel" replace />;
  }

  if (user?.role === "USER" || user?.role === "PROVIDER") {
    return (
      <SocialLayout variant="signed-in-social">
        <SocialFeed />
      </SocialLayout>
    );
  }

  return <Navigate to="/unauthorized" replace />;
}

/** Traveler account pages: USER and PROVIDER; admins go to admin panel elsewhere. */
function TravelerOrRedirect({ children }) {
  const { loading, user } = useAuth();

  if (loading) {
    return <RouteLoadingState />;
  }

  if (user?.role === "ADMIN") {
    return <Navigate to="/admin-panel" replace />;
  }

  if (user?.role !== "USER" && user?.role !== "PROVIDER") {
    return <Navigate to="/unauthorized" replace />;
  }

  return children;
}

function RequireUserRole({ children }) {
  const { loading, user } = useAuth();

  if (loading) {
    return <RouteLoadingState />;
  }

  if (user?.role !== "USER") {
    return <Navigate to={getRoleFallbackPath(user?.role)} replace />;
  }

  return children;
}

function SocialRedirect({ section }) {
  const { isAuthenticated, loading } = useAuth();
  const location = useLocation();

  if (loading) {
    return <RouteLoadingState />;
  }

  if (!isAuthenticated) {
    return <Navigate to="/login" replace state={{ from: location }} />;
  }

  const targets = {
    inbox: "/social",
    notifications: "/notifications",
  };

  return <Navigate to={targets[section] || "/"} replace />;
}

const router = createBrowserRouter([
  {
    element: <ProviderModeGate />,
    children: [
  { path: "/", element: <HomeEntry /> },
  {
    path: "/dashboard/provider",
    element: <Navigate to="/account/provider" replace />,
  },
  {
    element: <GuestLayout showRail />,
    children: [
      { path: "/explore", element: <Explore /> },
      { path: "/destinations", element: <Destinations /> },
      { path: "/plan", element: <TripPlanner /> },
      { path: "/trip/:slug", element: <PublicTripPage /> },
      { path: "/places/:id", element: <PlaceDetail /> },
      { path: "/events/:id", element: <EventDetail /> },
      { path: "/about", element: <About /> },
      { path: "/contact", element: <Contact /> },
      { path: "/search", element: <SearchPage /> },
    ],
  },
  {
    element: (
      <RequireGuest>
        <AuthLayout />
      </RequireGuest>
    ),
    children: [
      { path: "/login", element: <Login /> },
      { path: "/register", element: <Register /> },
      { path: "/verify-email", element: <VerifyEmail /> },
    ],
  },
  {
    element: <AuthLayout />,
    children: [{ path: "/invite", element: <InvitePage /> }],
  },
  {
    path: "/choose-account",
    element: (
      <RequireAuth allowedRoles={["PROVIDER"]}>
        <AuthLayout />
      </RequireAuth>
    ),
    children: [{ index: true, element: <ChooseAccountMode /> }],
  },
  {
    element: <SocialLayout variant="signed-in-social" />,
    children: [
      { path: "/u/:username/followers", element: <UserPublicFollowersRoute /> },
      { path: "/u/:username/following", element: <UserPublicFollowingRoute /> },
      { path: "/u/:username", element: <UserSocialProfile /> },
      {
        path: "/p/:slug",
        element: <ProviderBusinessLayout />,
        children: providerBusinessChildRoutes,
      },
      {
        path: "/provider/:param",
        element: <ProviderBusinessLayout />,
        children: providerBusinessChildRoutes,
      },
      { path: "/social/post/:id", element: <SocialPostDetail /> },
    ],
  },
  {
    element: (
      <RequireAuth allowedRoles={MEMBER_ROLES}>
        <SocialLayout variant="messenger" />
      </RequireAuth>
    ),
    children: [
      { path: "/social", element: <MessengerHub /> },
      { path: "/inbox", element: <InboxPage /> },
      { path: "/inbox/:id", element: <ConversationPage /> },
      { path: "/community/:tab", element: <CommunityTabPlaceholder /> },
    ],
  },
  {
    element: (
      <RequireAuth allowedRoles={MEMBER_ROLES}>
        <SocialLayout variant="signed-in-social" />
      </RequireAuth>
    ),
    children: [
      { path: "/notifications", element: <NotificationsPage /> },
      { path: "/dashboard", element: <Navigate to="/" replace /> },
      {
        path: "/profile",
        element: (
          <TravelerOrRedirect>
            <Profile />
          </TravelerOrRedirect>
        ),
      },
      {
        path: "/profile/friends",
        element: (
          <TravelerOrRedirect>
            <ProfileConnections list="friends" />
          </TravelerOrRedirect>
        ),
      },
      {
        path: "/profile/followers",
        element: (
          <TravelerOrRedirect>
            <ProfileConnections list="followers" />
          </TravelerOrRedirect>
        ),
      },
      {
        path: "/profile/following",
        element: (
          <TravelerOrRedirect>
            <ProfileConnections list="following" />
          </TravelerOrRedirect>
        ),
      },
      {
        path: "/bookings",
        element: (
          <TravelerOrRedirect>
            <Bookings />
          </TravelerOrRedirect>
        ),
      },
      {
        path: "/wishlist",
        element: (
          <TravelerOrRedirect>
            <Wishlist />
          </TravelerOrRedirect>
        ),
      },
      {
        path: "/saved-plans",
        element: (
          <TravelerOrRedirect>
            <SavedPlans />
          </TravelerOrRedirect>
        ),
      },
      {
        path: "/trip-planner",
        element: (
          <TravelerOrRedirect>
            <TripPlanner />
          </TravelerOrRedirect>
        ),
      },
      {
        path: "/geo",
        element: (
          <TravelerOrRedirect>
            <GeoTables />
          </TravelerOrRedirect>
        ),
      },
    ],
  },
  {
    path: "/account/provider/apply",
    element: (
      <RequireUserRole>
        <GuestLayout showRail={false} showFooter={false} fullWidth>
          <ProviderApplyPage />
        </GuestLayout>
      </RequireUserRole>
    ),
  },
  {
    path: "/register/provider",
    element: (
      <RequireUserRole>
        <GuestLayout showRail={false} showFooter={false} fullWidth>
          <ProviderApplyPage />
        </GuestLayout>
      </RequireUserRole>
    ),
  },
  {
    path: "/account",
    element: (
      <RequireAuth allowedRoles={["PROVIDER"]}>
        <ProviderLayout />
      </RequireAuth>
    ),
    children: [
      { path: "provider", element: <ProviderBusinessFeed /> },
      { path: "provider/create-post", element: <ProviderCreatePostPage /> },
      {
        path: "provider/public",
        element: <ProviderBusinessLayout />,
        children: providerBusinessChildRoutes,
      },
      {
        path: "provider/reviews",
        element: <ProviderBusinessLayout />,
        children: [{ index: true, element: <ProviderReviewsPage /> }],
      },
      { path: "provider/places", element: <ProviderPlaces /> },
      {
        path: "provider/events",
        element: (
          <Suspense fallback={<RouteLoadingState />}>
            <ProviderEvents />
          </Suspense>
        ),
      },
      { path: "provider/bookings", element: <ProviderBookings /> },
      { path: "provider/settings", element: <ProviderPanelProfile /> },
    ],
  },
  { path: "/provider-panel", element: <Navigate to="/account/provider" replace /> },
  { path: "/provider-panel/profile", element: <Navigate to="/account/provider/settings" replace /> },
  { path: "/provider-panel/places", element: <Navigate to="/account/provider/places" replace /> },
  { path: "/provider-panel/events", element: <Navigate to="/account/provider/events" replace /> },
  { path: "/provider-panel/bookings", element: <Navigate to="/account/provider/bookings" replace /> },
  {
    path: "/admin-panel",
    element: (
      <RequireAuth allowedRoles={["ADMIN"]}>
        <AdminLayout />
      </RequireAuth>
    ),
    children: [
      { index: true, element: <AdminDashboard /> },
      { path: "devices", element: <DevicesPage /> },
      { path: "users", element: <UsersPage /> },
      { path: "providers", element: <ProvidersPage /> },
      { path: "places", element: <PlacesPage /> },
      { path: "countries", element: <CountriesPage /> },
      { path: "cities", element: <CitiesPage /> },
      { path: "currencies", element: <CurrenciesPage /> },
      { path: "tags", element: <TagsPage /> },
      { path: "events", element: <EventsPage /> },
      { path: "reviews", element: <ReviewsPage /> },
      { path: "place-pricing", element: <PlacePricingPage /> },
      { path: "place-opening-hours", element: <PlaceOpeningHoursPage /> },
      { path: "provider-membership", element: <ProviderMembershipPage /> },
      {
        path: "provider-applications",
        element: <ProviderApplicationsAdminPage />,
      },
    ],
  },
  { path: "/user-panel", element: <Navigate to="/" replace /> },
  { path: "/user-panel/profile", element: <Navigate to="/profile" replace /> },
  { path: "/user-panel/bookings", element: <Navigate to="/bookings" replace /> },
  { path: "/user-panel/wishlist", element: <Navigate to="/wishlist" replace /> },
  { path: "/user-panel/saved-plans", element: <Navigate to="/saved-plans" replace /> },
  { path: "/user-panel/trip-planner", element: <Navigate to="/trip-planner" replace /> },
  { path: "/user-panel/geo", element: <Navigate to="/geo" replace /> },
  { path: "/messenger", element: <SocialRedirect section="inbox" /> },
  { path: "/unauthorized", element: <Unauthorized /> },
  { path: "*", element: <NotFound /> },
    ],
  },
]);

export default router;
